    /**
     * Ticks of grace after combat starts before the fall-death check is armed.
     *
     * <p>The arena's blocks are placed over several ticks (and on a slow machine, chunk loading
     * makes that much worse). Until the floor exists the player is standing in mid-air and
     * gravity is pulling them down, so the "below the arena floor" check fires and reads a
     * still-loading arena as a fall into the void. That used to kill people outright; once
     * totems started covering void deaths it started eating their totem on arena entry instead.
     *
     * <p>Three seconds is generous on purpose - a false fall-death is a catastrophic,
     * unrecoverable outcome for the player, while a genuine void fall being caught a moment
     * late costs nothing.
     */
    /**
     * Turns of Marked applied by a spectral arrow.
     *
     * <p>The Marked countdown runs in {@code tickEnemyDeciding}, i.e. at the start of the
     * ENEMY phase, after the player has finished acting. One turn therefore means "for the
     * rest of the turn you shot it in" - long enough to set up a follow-up hit with the 2x
     * bonus, and gone before the enemy acts. (The spyglass uses 2 to also cover the player's
     * next turn; the arrow is deliberately the cheaper, shorter version.)
     */
    private static final int SPECTRAL_ARROW_MARK_TURNS = 1;

    private static final int FALL_DEATH_GRACE_TICKS = 60;

    /** Counts down from {@link #FALL_DEATH_GRACE_TICKS} at combat start. */
    private int fallDeathGraceTicks = 0;
    // In MP each party member needs their OWN status-effect state -bleed /
    // burn / poison applied to player 2 should not appear on player 1's HUD,
    // tick on player 1's turn, or modify player 1's speed. The field is kept
    // for backward compat with the 32+ existing call sites (combatEffects.X())
    // but is retargeted to the current this.player's entry in this map by
    // retargetEffectsToCurrentPlayer() at every this.player reassignment.
    private final java.util.Map<java.util.UUID, CombatEffects> playerCombatEffects = new java.util.HashMap<>();
    private CombatEffects combatEffects = new CombatEffects();

    /** Re-point the {@link #combatEffects} field at {@link #player}'s entry in
     *  {@link #playerCombatEffects}, creating a fresh entry if this is the
     *  first time we've seen them. Call after every {@code this.player = X}
     *  reassignment so the existing 32+ {@code combatEffects.X()} call sites
     *  automatically operate on the right player's state. No-op when
     *  {@code this.player == null}. */
    /**
     * Runs the player-side per-turn effects for whoever {@code this.player} currently is:
     * trim REGEN, status DoT/regen, magma/soul-sand/tidal tile hazards, campfire heal, and
     * poison-cloud breath. Callers swap {@code this.player} (and the arena grid pos) to each
     * party member before invoking this so every member's own effects, trim scan, and tile
     * are used. Returns {@code true} if a player death ended the whole combat (party wiped),
     * in which case the caller should abort the current tick.
     */
    private boolean tickPlayerPerTurnEffects() {
        if (player == null) return false;
        // The player this pass is processing. handlePlayerDeathOrGameOver swaps
        // this.player to the next-alive member on death, so we capture the member
        // up front and stop processing them the moment they die (returning false
        // unless the whole party wiped). Without this, post-death tile effects
        // would run against the swapped-in survivor and double-process them.
        ServerPlayerEntity member = this.player;

        // Trim REGEN bonus: +1 HP per piece every 2 turns
        int trimRegen = activeTrimScan != null ? activeTrimScan.get(TrimEffects.Bonus.REGEN) : 0;
        if (trimRegen > 0 && turnNumber % 2 == 0
                && member.getHealth() < member.getMaxHealth()) {
            member.setHealth(Math.min(member.getMaxHealth(), member.getHealth() + trimRegen));
            sendMessage("§a♥ Trim regen healed " + trimRegen + " HP");
        }

        int hpChange = combatEffects.applyPerTurnEffects(SpecialAffinity.points(member));
        if (hpChange != 0) {
            float newHp = Math.max(1, Math.min(member.getMaxHealth(), member.getHealth() + hpChange));
            member.setHealth(newHp);
            if (hpChange > 0) {
                sendMessage("§a♥ Regeneration healed " + hpChange + " HP");
            } else {
                StringBuilder dmgSources = new StringBuilder();
                if (combatEffects.hasEffect(CombatEffects.EffectType.POISON)) dmgSources.append("Poison ");
                if (combatEffects.hasEffect(CombatEffects.EffectType.WITHER)) dmgSources.append("Wither ");
                if (combatEffects.hasEffect(CombatEffects.EffectType.BURNING)) dmgSources.append("Fire ");
                sendMessage("§c☠ " + dmgSources.toString().trim() + " dealt " + (-hpChange) + " damage");
            }
            if (getPlayerHp() <= 0) { handlePlayerDeathOrGameOver(); return partyPlayers.size() <= 1 || !active; }
        }

        GridPos playerPos = arena.getPlayerGridPos();
        GridTile playerTile = arena.getTile(playerPos);
        if (playerTile != null) {
            net.minecraft.block.Block tileBlock = playerTile.getBlockType();
            if (tileBlock == Blocks.MAGMA_BLOCK && !combatEffects.hasFireResistance()) {
                int magmaDmg = damagePlayer(4);
                sendMessage("§cMagma burns you for " + magmaDmg + " damage!");
                if (getPlayerHp() <= 0) { handlePlayerDeathOrGameOver(); return partyPlayers.size() <= 1 || !active; }
            } else if (tileBlock == Blocks.SOUL_SAND || tileBlock == Blocks.SOUL_SOIL) {
                movePointsRemaining = Math.max(1, movePointsRemaining - 1);
                sendMessage("§7☁ Soul sand slows your movement (-1 Speed)");
            }
            // TIDAL set bonus: water tiles heal 1 HP/turn
            if (playerTile.isWater() && activeTrimScan != null
                    && activeTrimScan.setBonus() == TrimEffects.SetBonus.TIDAL
                    && member.getHealth() < member.getMaxHealth()) {
                member.setHealth(Math.min(member.getMaxHealth(), member.getHealth() + 1));
                sendMessage("§b§l✦ Tidal! §r§3Water heals you for 1 HP");
            }
        }

        // Prismarine armor: the shell discharges at whatever has crowded the wearer.
        if (ArmorSetEffects.hasPrismarineDischarge(PlayerCombatStats.getArmorSet(member))) {
            applyPrismarineDischarge(member);
        }


        // Campfire heal + poison-cloud breath are tile effects centered on the
        // player's own position, so they belong in this per-member pass.
        for (var entry : tileEffects.entrySet()) {
            GridPos tPos = entry.getKey();
            String effect = entry.getValue();
            if ("campfire".equals(effect)) {
                // 5x5 square around the campfire = Chebyshev distance <= 2.
                int dx = Math.abs(playerPos.x() - tPos.x());
                int dz = Math.abs(playerPos.z() - tPos.z());
                if (Math.max(dx, dz) <= 2) {
                    float healed = Math.min(member.getMaxHealth(), member.getHealth() + 2);
                    if (healed > member.getHealth()) {
                        member.setHealth(healed);
                        sendMessage("§6Campfire heals 2 HP.");
                    }
                }
            } else if ("poison_cloud".equals(effect)) {
                if (playerPos.manhattanDistance(tPos) <= 1) {
                    member.setHealth(Math.max(1, member.getHealth() - 1));
                    sendMessage("§5You breathe in the poison cloud! -1 HP");
                    if (getPlayerHp() <= 0) { handlePlayerDeathOrGameOver(); return partyPlayers.size() <= 1 || !active; }
                }
            }
        }
        return false;
    }

    private void retargetEffectsToCurrentPlayer() {
        if (this.player == null) return;
        java.util.UUID uuid = this.player.getUuid();
        // Each player MUST get their own fresh CombatEffects instance. An
        // earlier version seeded new map entries with the existing
        // `combatEffects` field reference, which meant player 2's first
        // retarget aliased their map entry to player 1's CombatEffects object
        // -bleed/burn/poison added to either then showed on both, DoT damage
        // hit the wrong player, and bleeding ticking on the new turn-holder
        // could kill a teammate immediately after a death handoff. The
        // computeIfAbsent / `new` lambda guarantees a unique instance per UUID.
        this.combatEffects = playerCombatEffects.computeIfAbsent(uuid, k -> new CombatEffects());
        // The defensive trim/set bonuses read by damagePlayer (AC, ETHEREAL
        // dodge, FORTRESS reduction, OCEAN_BLESSING heal) come from
        // activeTrimScan. When an enemy hit swaps this.player to a non-turn
        // victim, the scan must follow the victim or they get the turn-holder's
        // armor bonuses (e.g. a teammate full-healed by an Ocean's Blessing set
        // they aren't wearing). Re-scan here so every this.player reassignment
        // keeps activeTrimScan consistent with the player effects now apply to.
        this.activeTrimScan = TrimEffects.scan(this.player);
        this.activeCombatEffects = activeTrimScan.getCombatEffects();
        if (effectContext != null) effectContext.update(player, arena, combatEffects, activeTrimScan);
    }

    private CombatAchievementTracker achievementTracker = new CombatAchievementTracker();

    private EventManager eventManager;
    // Server handle retained across endCombat() so music can be routed to the run's
    // players during event interludes (when `player`/party tracking are cleared).
    private net.minecraft.server.MinecraftServer server;
    private java.util.UUID worldOwnerUuid;
    private java.util.UUID leaderUuid;

    // Pets persist across level transitions within a biome run
    private final List<HubPetCollector.PetData> savedPets = new ArrayList<>();
    private List<HubPetCollector.TamedPetSnapshot> hubPetSnapshots = new ArrayList<>();
    public void setHubPetSnapshots(List<HubPetCollector.TamedPetSnapshot> snapshots) { this.hubPetSnapshots = snapshots; }

    // True once a normal combat exit (boss win, biome complete, return-home,
    // next-level) has explicitly disposed of the surviving allied pets. When
    // false at endCombat() time, the exit is abnormal (disconnect, death, error)
    // and endCombat() must restore the survivors to the hub itself, otherwise
    // they are discarded and lost forever.
    private boolean petsRescued = false;

    private CombatEntity pendingAllyAttackTarget = null;
    /** Non-ally target chosen this turn when an enemy should focus a pet that damaged it. */
    private CombatEntity currentEnemyPetAggroTarget = null;
    /** When set, the current confused enemy redirects its RANGED action at this fellow
     *  enemy instead of the player (a confused skeleton shoots its ally). Reset each
     *  enemy turn so it never leaks to the next mob. */
    private CombatEntity confusedRangedVictim = null;

    public EventManager getEventManager() { return eventManager; }
    public void setEventManager(EventManager em) { this.eventManager = em; }

    public java.util.UUID getWorldOwnerUuid() { return worldOwnerUuid; }
    public void setWorldOwnerUuid(java.util.UUID uuid) { this.worldOwnerUuid = uuid; }

    // === Party co-op support ===

    /** All players participating in this combat (leader first, then party members). */
    private final List<ServerPlayerEntity> partyPlayers = new ArrayList<>();

    /** Maps non-leader party member UUID → leader UUID for action routing. */
    private static final java.util.Map<java.util.UUID, java.util.UUID> PARTY_COMBAT_LEADER =
        new java.util.concurrent.ConcurrentHashMap<>();

    /** Tracks party members who have died during this combat level (spectating). */
    private final java.util.Set<java.util.UUID> deadPartyMembers = new java.util.HashSet<>();

    public void addPartyMember(ServerPlayerEntity member) {
        if (partyPlayers.stream().noneMatch(p -> p.getUuid().equals(member.getUuid()))) {
            partyPlayers.add(member);
        }
        if (player != null && !member.getUuid().equals(player.getUuid())) {
            PARTY_COMBAT_LEADER.put(member.getUuid(), player.getUuid());
        }
        // A member joining an in-progress run needs the current track right away -
        // the shared refresh only broadcasts on change, which already happened.
        if (!lastSentMusicKey.isEmpty()) {
            sendMusicTo(member);
        }
    }

    /**
     * Called once after the full party roster has been registered (post member
     * loop in the start-combat handler) to build the turn queue and push an
     * authoritative party-wide sync. startCombat's own sendSync fires before any
     * non-leader is added, so without this every member sat on stale/default HP
     * and an empty party/turn HUD until the first action-driven sync. With the
     * roster populated, this sync carries partyHpData/turnOrderData to everyone.
     * No-op for solo play (the start sync already covered the lone player).
     */
    public void finishPartyJoin() {
        if (!active || partyPlayers.size() <= 1) return;
        rebuildTurnQueue();
        // Keep the leader as the current turn-holder; rebuildTurnQueue resets the
        // cursor to 0 and this.player is still the leader from startCombat.
        sendSync();
    }

    public void removePartyMember(java.util.UUID memberUuid) {
        // If the removed player currently holds the turn, `this.player` still
        // points at their (possibly disconnected) entity after the removal.
        // `handleAction` gates on `player.getUuid().equals(senderUuid)`, so
        // without reassigning, every remaining party member's action gets
        // rejected and combat deadlocks. Called directly from the server
        // disconnect handler, which bypasses `leavePartyCombat`'s own reassign.
        boolean wasCurrent = player != null && player.getUuid().equals(memberUuid);
        partyPlayers.removeIf(p -> p.getUuid().equals(memberUuid));
        PARTY_COMBAT_LEADER.remove(memberUuid);
        // turnQueue.remove(Object) removes by value and shifts every later index
        // down by one. If the leaver sat BEFORE the cursor, the cursor must shift
        // down too -otherwise it points one player too far forward and that
        // player silently loses their turn when the current player ends theirs.
        // (When the leaver WAS the current holder, removedIdx == currentTurnIndex
        // and we do NOT decrement: the cursor now correctly points at whoever
        // shifted into that slot, and the wasCurrent -> switchToTurnPlayer below
        // re-resolves this.player to it.)
        int removedIdx = turnQueue.indexOf(memberUuid);
        turnQueue.remove(memberUuid);
        if (removedIdx >= 0 && removedIdx < currentTurnIndex) {
            currentTurnIndex--;
        }
        if (currentTurnIndex >= turnQueue.size() && !turnQueue.isEmpty()) {
            currentTurnIndex = 0;
        }
        if (wasCurrent && !turnQueue.isEmpty()) {
            switchToTurnPlayer();
        }
        // If the leaver was the last one we were waiting on at the trader or
        // crafting station, finalize the event so the rest of the party isn't
        // stranded in a non-combat room with no way to advance.
        clearEventPendingForDisconnect(memberUuid);
    }

    /**
     * Remove a now-dead player's UUID from the positional turn queue and fix the
     * cursor, so turn rotation doesn't hand their (now-occupied) slot to a
     * survivor for a free extra action that round. Turn rotation in handleEndTurn
     * pre-increments currentTurnIndex then reads, so if the dead player sat at or
     * before the cursor, removing them shifts later slots down one and the cursor
     * must shift down too to still land on the correct successor. Mirrors the
     * queue maintenance in removePartyMember.
     */
    private void pruneDeadFromTurnQueue(java.util.UUID deadUuid) {
        int deadIdx = turnQueue.indexOf(deadUuid);
        if (deadIdx < 0) return;
        turnQueue.remove(deadIdx);
        if (deadIdx <= currentTurnIndex && currentTurnIndex > 0) {
            currentTurnIndex--;
        }
        if (currentTurnIndex >= turnQueue.size() && !turnQueue.isEmpty()) {
            currentTurnIndex = 0;
        }
    }

    /**
     * Treat a disconnecting player as if they finished any non-combat event
     * they were holding the party on (trader, crafting station). Without this,
     * a mid-event DC leaves the player's UUID in the pending set forever and
     * the transition never fires for the remaining online members.
     */
    private void clearEventPendingForDisconnect(java.util.UUID memberUuid) {
        // Drop the leaver from the cinematic so they never block the arrived/finished gates.
        if (activeCinematic != null) activeCinematic.removePlayer(memberUuid);
        if (traderPendingPlayers.remove(memberUuid)) {
            // Reclaim any emerald items still in the leaver's inventory into their bank.
            // offerTrader materialized their whole balance as items, so a mid-trade
            // disconnect would otherwise strand the currency as loose inventory items.
            if (server != null) {
                ServerPlayerEntity leaver = server.getPlayerManager().getPlayer(memberUuid);
                if (leaver != null) reclaimTraderEmeralds(leaver);
            }
            traderQueue.remove(memberUuid);
            // If the leaver was the active shopper, release the shared-merchant lock
            // and hand it to the next queued member so the party doesn't freeze on the
            // waiting overlay. Mirrors the handoff in handleTraderDone.
            if (memberUuid.equals(currentTrader)) {
                currentTrader = null;
                if (spawnedTrader != null) spawnedTrader.setCustomer(null);
                while (!traderQueue.isEmpty()) {
                    java.util.UUID nextUuid = traderQueue.poll();
                    ServerPlayerEntity next = server != null
                        ? server.getPlayerManager().getPlayer(nextUuid) : null;
                    if (next != null && traderPendingPlayers.contains(nextUuid)) {
                        openTraderFor(next);
                        break;
                    }
                }
            }
            if (traderPendingPlayers.isEmpty() && spawnedTrader != null) {
                ServerPlayerEntity ref = firstOnlinePartyMember();
                if (ref != null) finalizeTraderEvent(ref);
            }
        }
        if (lootPendingPlayers.remove(memberUuid) && lootPendingPlayers.isEmpty()) {
            continueVictoryAfterLoot();
        }
        // Intro narrator gate (trial chambers, ominous trials, addon events):
        // drop the leaver from the dismiss set. If they were the last one we
        // were waiting on, fire the leader's queued Accept/Decline prompt.
        if (introPendingPlayers.remove(memberUuid)
                && introPendingPlayers.isEmpty() && pendingIntroPrompt != null) {
            Runnable prompt = pendingIntroPrompt;
            pendingIntroPrompt = null;
            prompt.run();
        }
        // Dig Site minigame: drop the leaver from the pending set. If they were
        // the last player still digging, finalize the event so the rest of the
        // party can transition to the next level.
        if (digSitePending && digSitePendingPlayers.remove(memberUuid)) {
            digBrushCount.remove(memberUuid);
            if (digSitePendingPlayers.isEmpty()) {
                ServerPlayerEntity ref = firstOnlinePartyMember();
                if (ref != null) finalizeDigSiteEvent(ref);
            }
        }
        // Trial vote: count the leaver as a Pass (conservative -opt-out by
        // default). If they were the last voter, resolve; if they were on the
        // outcome-dismiss gate, finalize the transition.
        if (eventRoomPending && "trial".equals(eventRoomType)
                && eventPendingPlayers.remove(memberUuid)) {
            int expected = trialVoteMembers != null ? trialVoteMembers.size() : 0;
            boolean inVotingPhase = trialVotes.size() < expected;
            if (inVotingPhase) trialVotes.put(memberUuid, false);
            if (eventPendingPlayers.isEmpty()) {
                ServerPlayerEntity ref = firstOnlinePartyMember();
                if (ref != null) {
                    if (inVotingPhase) resolveTrialVote(ref);
                    else finalizeTrialEvent(ref);
                }
            }
        }
        // Shiny vote: count the leaver as a No so the vote can still resolve.
        // In the dismissal phase (all votes already in), just drop them.
        if (eventRoomPending && "shiny".equals(eventRoomType)
                && eventPendingPlayers.remove(memberUuid)) {
            int expected = pendingShinyMembers != null ? pendingShinyMembers.size() : 0;
            boolean inVotingPhase = shinyVotes.size() < expected;
            if (inVotingPhase) shinyVotes.put(memberUuid, false);
            if (eventPendingPlayers.isEmpty()) {
                ServerPlayerEntity ref = firstOnlinePartyMember();
                if (ref != null) {
                    if (inVotingPhase) resolveShinyVote(ref);
                    else finalizeShinyEvent(ref);
                }
            }
        }
        // Generic per-player event cleanup (shrine / traveler / enchanter / vault).
        // These use eventPendingPlayers + finalizeXxxEvent and need disconnect
        // handling the same way trial / shiny / dig do. Shiny + trial handle
        // their own removal above, so the .remove call here only fires for the
        // other event types.
        if (eventRoomPending && eventPendingPlayers.remove(memberUuid)
                && eventPendingPlayers.isEmpty()) {
            ServerPlayerEntity ref = firstOnlinePartyMember();
            if (ref != null) {
                switch (eventRoomType) {
                    case "shrine"        -> finalizeShrineEvent(ref);
                    case "traveler"      -> finalizeTravelerEvent(ref);
                    case "enchanter"     -> finalizeEnchanterEvent(ref);
                    case "vault"         -> finalizeVaultEvent(ref);
                    case "piglin_barter" -> finalizeBarterEvent(ref);
                    default              -> { /* shiny/trial finalize themselves above */ }
                }
            }
        }
    }

    /** First still-online party member, or {@code null} if everyone is gone. During a
     *  between-level gate endCombat has already run cleanupPartyTracking, so partyPlayers
     *  is EMPTY -every disconnect finalizer in clearEventPendingForDisconnect would get
     *  null here and silently strand the party. Fall back to the durable EventManager
     *  roster (how the event code itself reaches players), then to this CM's owner. */
    private ServerPlayerEntity firstOnlinePartyMember() {
        for (ServerPlayerEntity p : partyPlayers) {
            if (p != null && !p.isRemoved() && !p.isDisconnected()) return p;
        }
        if (eventManager != null && server != null) {
            for (ServerPlayerEntity p : eventManager.getOnlineParticipants(server.getOverworld())) {
                if (p != null && !p.isRemoved() && !p.isDisconnected()) return p;
            }
        }
        return resolveCmOwnerPlayer(null);
    }

    /** True if this combat manager is holding {@code uuid} in a between-level event gate
     *  (the per-player "pending" sets). The disconnect handler needs this: during an event
     *  interlude the manager is no longer {@link #active}, so without it a disconnect would
     *  skip {@link #removePartyMember} (which releases the gate via
     *  {@link #clearEventPendingForDisconnect}) and softlock the rest of the party. */
    public boolean holdsPendingPlayer(java.util.UUID uuid) {
        return eventPendingPlayers.contains(uuid)
            || introPendingPlayers.contains(uuid)
            || traderPendingPlayers.contains(uuid)
            || lootPendingPlayers.contains(uuid)
            || digSitePendingPlayers.contains(uuid);
    }

    /** True if this manager is still gating any between-level event on per-player input.
     *  Used so a LEADER disconnecting during the (inactive) event interlude still runs the
     *  "send the party home" teardown instead of stranding the remaining members. */
    public boolean hasPendingEvent() {
        return !eventPendingPlayers.isEmpty() || !introPendingPlayers.isEmpty()
            || !traderPendingPlayers.isEmpty() || !lootPendingPlayers.isEmpty()
            || !digSitePendingPlayers.isEmpty();
    }

    // Pulls one player out of party combat, transferring leader role if needed
    public void leavePartyCombat(ServerPlayerEntity leaver) {
        if (!active) return;
        java.util.UUID leaverUuid = leaver.getUuid();

        // Move item is persistent across combat -no per-combat cleanup needed.
        leaver.clearStatusEffects();
        leaver.changeGameMode(net.minecraft.world.GameMode.SURVIVAL);

        if (leaver.networkHandler != null) {
            ServerPlayNetworking.send(leaver, new com.crackedgames.craftics.network.ExitCombatPayload(false));
        }

        deadPartyMembers.remove(leaverUuid);
        removePartyMember(leaverUuid);
        sendMessage("§e" + leaver.getName().getString() + " left the battle.");

        if (player != null && player.getUuid().equals(leaverUuid)) {
            ServerPlayerEntity nextAlive = null;
            for (ServerPlayerEntity member : partyPlayers) {
                if (!deadPartyMembers.contains(member.getUuid())
                        && member != null && !member.isRemoved() && !member.isDisconnected()) {
                    nextAlive = member;
                    break;
                }
            }
            if (nextAlive != null) {
                sendMessage("§e" + nextAlive.getName().getString() + " takes over the fight!");
                nextAlive.requestTeleport(player.getX(), player.getY(), player.getZ());
                this.player = nextAlive;
                retargetEffectsToCurrentPlayer();
                PlayerProgression prog = PlayerProgression.get((ServerWorld) player.getEntityWorld());
                PlayerProgression.PlayerStats pStats = prog.getStats(player);
                this.apRemaining = pStats.getEffective(PlayerProgression.Stat.AP)
                    + PlayerCombatStats.getSetApBonus(player);
                this.movePointsRemaining = pStats.getEffective(PlayerProgression.Stat.SPEED)
                    + PlayerCombatStats.getSetSpeedBonus(player);
                this.activeTrimScan = TrimEffects.scan(player);
                this.activeCombatEffects = activeTrimScan.getCombatEffects();
                if (effectContext != null) {
                    effectContext.update(player, arena, combatEffects, activeTrimScan);
                } else {
                    effectContext = new com.crackedgames.craftics.api.CombatEffectContext(player, arena, combatEffects, activeTrimScan);
                }
                sendSync();
                refreshHighlights();
            } else {
                endCombat();
                return;
            }
        }

        if (partyPlayers.size() == 0) {
            endCombat();
        }
    }

    // Resolves through party leader mapping so non-leaders find the right CombatManager
    public static CombatManager getActiveCombat(java.util.UUID playerUuid) {
        java.util.UUID leaderUuid = PARTY_COMBAT_LEADER.get(playerUuid);
        if (leaderUuid != null) {
            CombatManager leaderCm = INSTANCES.get(leaderUuid);
            if (leaderCm != null && leaderCm.active) return leaderCm;
        }
        // Event fallback: every between-level gate (events, trader, the boss/addon
        // intro narrator, the dig-site minigame) is set up on the leader's CM AFTER
        // endCombat → cleanupPartyTracking has already cleared PARTY_COMBAT_LEADER for
        // non-leader members. Without this lookup, a non-leader's EventChoicePayload /
        // DialogueChoicePayload routes to their own (inactive) CM, so the leader's
        // pending-set never drains and the party softlocks. Each set below is one
        // such gate; a player can only be tracked by one CM at a time, so first match
        // wins. (introPendingPlayers covers the "☠ Boss Approaching ☠ / Waiting for
        // party..." screen; without it MP parties hang there forever while solo works.)
        for (CombatManager cm : INSTANCES.values()) {
            if (cm.eventPendingPlayers.contains(playerUuid)) return cm;
            if (cm.traderPendingPlayers.contains(playerUuid)) return cm;
            if (cm.introPendingPlayers.contains(playerUuid)) return cm;
            if (cm.digSitePendingPlayers.contains(playerUuid)) return cm;
            if (cm.lootPendingPlayers.contains(playerUuid)) return cm;
        }
        return get(playerUuid);
    }

    /**
     * True when the player is actually mid-run: in active combat or held at a
     * between-level gate (event/trader/intro/dig-site pending set). Use this
     * for engagement checks - {@link #getActiveCombat} can NEVER return null
     * (its final fallback is {@code get(playerUuid)}, which creates an inactive
     * instance on demand), so {@code getActiveCombat(...) != null} is a
     * tautology, not a check.
     */
    public static boolean isEngaged(java.util.UUID playerUuid) {
        java.util.UUID leaderUuid = PARTY_COMBAT_LEADER.get(playerUuid);
        if (leaderUuid != null) {
            CombatManager leaderCm = INSTANCES.get(leaderUuid);
            if (leaderCm != null && leaderCm.active) return true;
        }
        for (CombatManager cm : INSTANCES.values()) {
            if (cm.eventPendingPlayers.contains(playerUuid)
                    || cm.traderPendingPlayers.contains(playerUuid)
                    || cm.introPendingPlayers.contains(playerUuid)
                    || cm.digSitePendingPlayers.contains(playerUuid)
                    || cm.lootPendingPlayers.contains(playerUuid)) return true;
        }
        CombatManager own = INSTANCES.get(playerUuid);
        return own != null && own.active;
    }

    public boolean isPartyMember(java.util.UUID uuid) {
        return partyPlayers.stream().anyMatch(p -> p.getUuid().equals(uuid));
    }

    private List<ServerPlayerEntity> getAllParticipants() {
        if (!partyPlayers.isEmpty()) return partyPlayers;
        return player != null ? List.of(player) : List.of();
    }

    private static final int FLASH_DAMAGE_COLOR = 0xFFBF1A;   // amber (matches AoE preview damage)
    private static final int FLASH_EFFECT_COLOR = 0x33B3FF;   // cyan  (matches AoE preview effect/support)

    /** Flash a multi-tile footprint on all party clients. No-op for <=1 tile. */
    private void sendTileFlash(java.util.Collection<GridPos> tiles, int color, int durationTicks) {
        if (tiles == null || tiles.size() <= 1) return;
        java.util.List<Integer> packed = new java.util.ArrayList<>(tiles.size() * 2);
        for (GridPos t : tiles) { packed.add(t.x()); packed.add(t.z()); }
        int[] arr = packed.stream().mapToInt(Integer::intValue).toArray();
        sendToAllParty(new com.crackedgames.craftics.network.TileFlashPayload(arr, color, durationTicks));
    }

    private void sendToAllParty(net.minecraft.network.packet.CustomPayload payload) {
        for (ServerPlayerEntity p : getAllParticipants()) {
            if (p == null) continue;
            if (p.isRemoved() || p.isDisconnected()) continue;
            if (p.networkHandler == null) continue;
            try {
                ServerPlayNetworking.send(p, payload);
            } catch (Throwable t) {
                // A failing packet encode/send to one party member must never
                // propagate up the call stack -otherwise an unrelated player
                // downstream in the loop gets skipped, and in the worst case
                // the server tick loop catches the exception and marks the
                // whole tick as failed, which can cascade into timeouts.
                CrafticsMod.LOGGER.error(
                    "Failed to send {} to {}: {}",
                    payload.getId(), p.getName().getString(), t.toString(), t);
            }
        }
    }

    // ─── Dynamic music ──────────────────────────────────────────────────────
    // Last soundtrack key broadcast to the party ("" = stopped). refreshMusic()
    // recomputes the desired track from current combat/event/trader state and only
    // sends a MusicSyncPayload when it actually changes -so it's safe to call every
    // tick. The client cross-fades to whatever key it receives.
    private String lastSentMusicKey = "";

    /**
     * Recipients for music packets. During active combat this is the party roster; during
     * an event interlude {@code endCombat()} has cleared {@code player}/party tracking, so we
     * fall back to the surviving {@link EventManager}'s online participants (which is how the
     * event code itself reaches players). Without this fallback, event music reached nobody.
     */
    private List<ServerPlayerEntity> musicRecipients() {
        List<ServerPlayerEntity> all = getAllParticipants();
        if (!all.isEmpty()) return all;
        if (eventManager != null && server != null) {
            return eventManager.getOnlineParticipants(server.getOverworld());
        }
        return List.of();
    }

    /** Recompute the desired soundtrack from current state and broadcast it on change. */
    public void refreshMusic() {
        String biomeId = null;
        boolean bossLevel = false;
        if (levelDef instanceof com.crackedgames.craftics.level.GeneratedLevelDefinition gld
                && gld.getBiomeTemplate() != null) {
            biomeId = gld.getBiomeTemplate().biomeId;
            bossLevel = gld.getBiomeTemplate().isBossLevel(gld.getLevelNumber());
        }
        TraderCategory traderType =
            activeTraderOffer != null ? activeTraderOffer.type() : null;
        com.crackedgames.craftics.sound.MusicTracks track =
            com.crackedgames.craftics.sound.MusicDirector.select(
                active, biomeId, bossLevel, eventRoomType, traderType, trialIsOminous);
        String key = (track == null) ? "" : track.key;
        if (key.equals(lastSentMusicKey)) return;
        lastSentMusicKey = key;
        com.crackedgames.craftics.network.MusicSyncPayload payload =
            new com.crackedgames.craftics.network.MusicSyncPayload(key);
        for (ServerPlayerEntity p : musicRecipients()) {
            if (p == null || p.isRemoved() || p.isDisconnected() || p.networkHandler == null) continue;
            try {
                ServerPlayNetworking.send(p, payload);
            } catch (Throwable t) {
                CrafticsMod.LOGGER.error("Failed to send music to {}: {}",
                    p.getName().getString(), t.toString(), t);
            }
        }
    }

    /** Push the current music key to one member (e.g. a player who just joined the run). */
    public void sendMusicTo(ServerPlayerEntity p) {
        if (p == null || p.isRemoved() || p.isDisconnected() || p.networkHandler == null) return;
        try {
            ServerPlayNetworking.send(p,
                new com.crackedgames.craftics.network.MusicSyncPayload(lastSentMusicKey));
        } catch (Throwable t) {
            CrafticsMod.LOGGER.error("Failed to send music to {}: {}",
                p.getName().getString(), t.toString(), t);
        }
    }

    private void sendMessageToAllChat(String msg) {
        for (ServerPlayerEntity p : getAllParticipants()) {
            if (p != null) {
                p.sendMessage(Text.literal(msg), false);
            }
        }
    }

    private void cleanupPartyTracking() {
        for (ServerPlayerEntity member : partyPlayers) {
            PARTY_COMBAT_LEADER.remove(member.getUuid());
        }
        partyPlayers.clear();
        deadPartyMembers.clear();
    }

    // Uses EventManager instead of partyPlayers because partyPlayers gets cleared by endCombat
    private List<ServerPlayerEntity> getOnlinePartyMembers(ServerPlayerEntity referencePlayer) {
        if (eventManager != null) {
            return eventManager.getOnlineParticipants((ServerWorld) referencePlayer.getEntityWorld());
        }
        return List.of(referencePlayer);
    }

    // ─────────────────────────────────────────────────────────────────────
    // Party-combat leader helpers
    //
    // The `this.player` field has TWO meanings in party combat that must not
    // be conflated:
    //
    //   • The "combat leader" -the player who originally started the biome
    //     run. Stable for the entire combat. Identified by `leaderUuid`, set
    //     once in startCombat() and cleared in endCombat().
    //
    //   • The "current turn player" -the party member whose turn it is right
    //     now. `this.player` is reassigned to this by switchToTurnPlayer() on
    //     every turn rotation. At victory, it points at whoever dealt the
    //     killing blow -NOT the leader.
    //
    // Code that means "the leader" must use getCombatLeader(). Only code that
    // needs "whoever is acting right now" should use `this.player` directly.
    // ─────────────────────────────────────────────────────────────────────

    /**
     * Resolve the stable combat leader entity. Returns null if the leader has
     * disconnected. Not meaningful before startCombat() or after endCombat().
     */
    public ServerPlayerEntity getCombatLeader() {
        if (leaderUuid == null) {
            return player;  // pre-startCombat, or solo where leader == this.player
        }
        for (ServerPlayerEntity p : partyPlayers) {
            if (p != null && p.getUuid().equals(leaderUuid)) return p;
        }
        if (player != null && player.getUuid().equals(leaderUuid)) return player;
        return null;
    }

    /**
     * True when `this.player` has drifted from the combat leader due to turn
     * rotation. Callers that think they're operating on "the leader" via
     * `this.player` are almost certainly wrong when this is true.
     */
    private boolean isTurnPlayerDivergentFromLeader() {
        return leaderUuid != null
            && player != null
            && !player.getUuid().equals(leaderUuid);
    }

    /**
     * Take a defensive copy of the current combat participants. Call this
     * BEFORE endCombat() so the returned list survives the state wipe and can
     * be passed into transitionPartyToArena() for the next level.
     * <p>
     * Resolution order: partyPlayers (authoritative while combat is active) →
     * eventManager (durable across endCombat) → [this.player] fallback.
     */
    private List<ServerPlayerEntity> snapshotParticipants() {
        if (!partyPlayers.isEmpty()) {
            return new ArrayList<>(partyPlayers);
        }
        if (eventManager != null && player != null) {
            return new ArrayList<>(
                eventManager.getOnlineParticipants((ServerWorld) player.getEntityWorld()));
        }
        return player != null ? new ArrayList<>(List.of(player)) : new ArrayList<>();
    }

    /** Start a dev/test arena -handles teleport, client payload, and combat start in one call. */
    public void startDevArena(ServerPlayerEntity player, GridArena arena, LevelDefinition levelDef) {
        GridPos startGrid = arena.getPlayerStart();
        arena.setPlayerGridPos(startGrid);
        BlockPos spawnPos = arena.gridToBlockPos(startGrid);
        player.requestTeleport(spawnPos.getX() + 0.5, spawnPos.getY(), spawnPos.getZ() + 0.5);
        ServerPlayNetworking.send(player, makeEnterPayload(arena));
        addPartyMember(player);
        startCombat(player, arena, levelDef);
    }

    /**
     * Convenience overload that derives the members list from current state.
     * Prefer the explicit-members overload when crossing an endCombat boundary,
     * because partyPlayers is wiped and the derivation falls through to
     * eventManager which may not reflect who was actually participating.
     */
    private void transitionPartyToArena(ServerPlayerEntity leader, GridArena newArena, LevelDefinition newLevelDef) {
        transitionPartyToArena(leader, null, newArena, newLevelDef);
    }

    /**
     * Transition the whole party into a new arena.
     *
     * @param leader          the combat leader -MUST match {@code leaderUuid}
     *                        or we log a warning and continue with the passed
     *                        value. Do NOT pass {@code this.player} in party
     *                        combat; use {@link #getCombatLeader()} instead,
     *                        since {@code this.player} rotates per turn.
     * @param explicitMembers authoritative snapshot of participants. Pass this
     *                        when called AFTER endCombat() has cleared party
     *                        state (use snapshotParticipants() before endCombat
     *                        to capture it). Pass {@code null} to derive from
     *                        current state (partyPlayers → eventManager).
     */
    private void transitionPartyToArena(ServerPlayerEntity leader,
                                        List<ServerPlayerEntity> explicitMembers,
                                        GridArena newArena,
                                        LevelDefinition newLevelDef) {
        // --- Sanity-check the leader argument. ---
        if (leader == null) {
            CrafticsMod.LOGGER.error("transitionPartyToArena: leader is null -aborting transition");
            return;
        }
        // Anchor on this combat's real host (this CM's INSTANCES key), NOT whoever
        // the caller passed. Event finalizers commonly pass the last voter / current
        // turn player, which may be a non-host party member. If that wrong player
        // becomes the new "leader", startCombat below rewrites leaderUuid +
        // PARTY_COMBAT_LEADER to point at them, so every OTHER member's actions
        // mis-route to their own inactive CM -- they get no turn and the per-tick
        // MoveSlotManager strips their move item.
        //
        // The old check was gated on `leaderUuid != null`, but during an event
        // interlude endCombat has already nulled leaderUuid (and emptied partyPlayers,
        // so getCombatLeader() returns null too) -- so the correction was silently
        // skipped exactly when it mattered. resolveCmOwnerPlayer recovers the host
        // from the INSTANCES key, which survives endCombat.
        ServerPlayerEntity resolvedHost = resolveCmOwnerPlayer(leader);
        if (resolvedHost != null && !resolvedHost.getUuid().equals(leader.getUuid())) {
            CrafticsMod.LOGGER.warn(
                "transitionPartyToArena: caller passed '{}' but this combat's host is '{}'; anchoring on host",
                leader.getName().getString(), resolvedHost.getName().getString());
            leader = resolvedHost;
        }

        // --- Resolve the members list with an explicit fallback chain. ---
        List<ServerPlayerEntity> members;
        if (explicitMembers != null && !explicitMembers.isEmpty()) {
            members = new ArrayList<>(explicitMembers);
        } else {
            members = new ArrayList<>(getOnlinePartyMembers(leader));
            if (members.isEmpty() || (members.size() == 1 && !partyPlayers.isEmpty())) {
                // Fallback to partyPlayers if getOnlinePartyMembers returned a
                // smaller list than we know is participating. This catches the
                // case where eventManager was nulled/stale.
                members = new ArrayList<>(partyPlayers);
            }
        }

        // --- Guarantee leader is in the members list. ---
        boolean leaderInList = false;
        for (ServerPlayerEntity m : members) {
            if (m != null && m.getUuid().equals(leader.getUuid())) { leaderInList = true; break; }
        }
        if (!leaderInList) {
            members.add(0, leader);
        }

        // --- Drop any stale/disconnected entities. ---
        members.removeIf(m -> m == null || m.isRemoved() || m.isDisconnected() || m.networkHandler == null);
        if (members.isEmpty()) {
            CrafticsMod.LOGGER.error("transitionPartyToArena: no valid members after filtering -aborting");
            return;
        }

        CrafticsMod.LOGGER.info(
            "transitionPartyToArena: leader={}, members={} → '{}'",
            leader.getName().getString(),
            members.stream().map(m -> m.getName().getString()).toList(),
            newLevelDef != null ? newLevelDef.getName() : "?");

        // --- Build the teleport order: leader first, then everyone else. ---
        List<ServerPlayerEntity> orderedMembers = new ArrayList<>();
        orderedMembers.add(leader);
        for (ServerPlayerEntity m : members) {
            if (!m.getUuid().equals(leader.getUuid())) orderedMembers.add(m);
        }

        ServerWorld spawnWorld = (ServerWorld) leader.getEntityWorld();
        GridPos startGrid = newArena.getPlayerStart();
        // Floor-aware search so nobody lands over a pit/void: schematic arenas (trial
        // chambers) have genuine gaps the grid can still report as "walkable", which was
        // dropping fanned-out party members into death pits on spawn.
        GridPos safeLeaderGrid = findNearestSafeSpawn(spawnWorld, newArena, startGrid, new java.util.HashSet<>());
        if (safeLeaderGrid == null) safeLeaderGrid = startGrid;
        newArena.setPlayerGridPos(safeLeaderGrid);

        EnterCombatPayload enterPayload = makeEnterPayload(newArena);

        // Revive dead party members with 2 hearts for new level
        for (ServerPlayerEntity member : members) {
            if (deadPartyMembers.remove(member.getUuid())) {
                member.setHealth(4); // 2 hearts
                member.clearStatusEffects();
                member.changeGameMode(net.minecraft.world.GameMode.ADVENTURE);
                sendMessageTo(member, "§a§l\u2726 REVIVED! §rYou're back with 2 hearts!");
            }
        }

        // Pick a spawn layout and resolve desired positions for each member.
        SpawnLayout layout = pickSpawnLayout(newArena, orderedMembers.size(), newLevelDef);
        List<GridPos> desiredSpawns = computeDesiredSpawns(
            layout, newArena, safeLeaderGrid, orderedMembers.size());

        java.util.Set<GridPos> reservedSpawns = new java.util.HashSet<>();
        for (int i = 0; i < orderedMembers.size(); i++) {
            ServerPlayerEntity member = orderedMembers.get(i);
            GridPos desired = desiredSpawns.get(i);
            GridPos chosen = findNearestSafeSpawn(spawnWorld, newArena, desired, reservedSpawns);
            if (chosen == null) chosen = safeLeaderGrid;
            reservedSpawns.add(chosen);

            BlockPos spawnPos = newArena.gridToBlockPos(chosen);
            member.requestTeleport(spawnPos.getX() + 0.5, spawnPos.getY(), spawnPos.getZ() + 0.5);
            ServerPlayNetworking.send(member, enterPayload);
            if (!member.getUuid().equals(leader.getUuid())) {
                member.changeGameMode(net.minecraft.world.GameMode.ADVENTURE);
            }
        }

        // Must happen before startCombat so sendSync/highlights reach all participants
        for (ServerPlayerEntity member : orderedMembers) {
            addPartyMember(member);
        }

        startCombat(leader, newArena, newLevelDef);

        // addPartyMember above ran while this.player was still null (cleared by prior endCombat),
        // so leader routing wasn't established -- fix it now
        for (ServerPlayerEntity member : orderedMembers) {
            if (!member.getUuid().equals(leader.getUuid())) {
                PARTY_COMBAT_LEADER.put(member.getUuid(), leader.getUuid());
            }
        }

        spawnSavedPets();

        // startCombat only handles the leader -- replicate chunks/feather/title for party members
        if (members.size() > 1) {
            ServerWorld world = (ServerWorld) leader.getEntityWorld();
            BlockPos origin = newArena.getOrigin();
            int chunkMargin = 48;
            int minCX = (origin.getX() - chunkMargin) >> 4;
            int maxCX = (origin.getX() + newArena.getWidth() + chunkMargin) >> 4;
            int minCZ = (origin.getZ() - chunkMargin) >> 4;
            int maxCZ = (origin.getZ() + newArena.getHeight() + chunkMargin) >> 4;

            for (ServerPlayerEntity member : members) {
                if (member.getUuid().equals(leader.getUuid())) continue;
                for (int cx = minCX; cx <= maxCX; cx++) {
                    for (int cz = minCZ; cz <= maxCZ; cz++) {
                        var chunk = world.getChunk(cx, cz);
                        if (chunk != null) {
                            member.networkHandler.chunkDataSender.add(chunk);
                        }
                    }
                }
                // Move item is persistent \u2014 server tick keeps it stocked.
                com.crackedgames.craftics.item.MoveSlotManager.enforce(member);
                // Vitality / trim HP bonus is applied to the leader inside
                // startCombat; non-leader party members were getting nothing,
                // so a Vitality-spec'd player 2 fought with base HP. Apply
                // the same bonus here using THEIR stats + trim scan.
                applyHpBonusFromStats(member);
                boolean partyBoss = newLevelDef instanceof com.crackedgames.craftics.level.GeneratedLevelDefinition pgld
                    && pgld.getBiomeTemplate() != null && pgld.getBiomeTemplate().isBossLevel(pgld.getLevelNumber());
                if (partyBoss) {
                    member.networkHandler.sendPacket(new net.minecraft.network.packet.s2c.play.TitleFadeS2CPacket(10, 60, 20));
                    member.networkHandler.sendPacket(new net.minecraft.network.packet.s2c.play.TitleS2CPacket(
                        Text.literal("\u00a74\u00a7l\u2620 BOSS FIGHT \u2620")));
                    member.networkHandler.sendPacket(new net.minecraft.network.packet.s2c.play.SubtitleS2CPacket(
                        Text.literal("\u00a7c" + newLevelDef.getName())));
                } else {
                    member.networkHandler.sendPacket(new net.minecraft.network.packet.s2c.play.TitleFadeS2CPacket(5, 40, 15));
                    member.networkHandler.sendPacket(new net.minecraft.network.packet.s2c.play.TitleS2CPacket(
                        Text.literal("\u00a7e" + newLevelDef.getName())));
                }
            }
        }
    }

    /**
     * Schedule the return-to-battle transition after an event finishes. Shows a
     * loading screen to the whole party immediately, then holds for at least
     * {@link #EVENT_RETURN_HOLD_TICKS} (the build, which is the slow part, happens
     * behind the screen when the timer fires). Counted down in {@link #tick()} so the
     * server thread is never blocked. Relies on {@code pendingNextLevelDef}/
     * {@code pendingBiome} still being set; they are read and cleared when it fires.
     */
    private void scheduleEventReturnTransition(ServerPlayerEntity referencePlayer) {
        if (referencePlayer == null || pendingNextLevelDef == null || pendingBiome == null) return;
        // Resolve to the ORIGINAL combat leader (the CM owner), not whoever
        // happened to finish the event last. transitionPartyToArena uses this
        // as `leader` for the new arena -passing the wrong player makes them
        // the new "leader", which scrambles partyPlayers ordering, turnQueue
        // (so they go first), leaderUuid, and PARTY_COMBAT_LEADER routing -
        // the real host then can't end their turn because their actions get
        // mis-routed to the new "leader"'s inactive CM.
        this.eventReturnLeader = resolveCmOwnerPlayer(referencePlayer);
        this.eventReturnTicks = EVENT_RETURN_HOLD_TICKS;
        for (ServerPlayerEntity p : getOnlinePartyMembers(referencePlayer)) {
            ServerPlayNetworking.send(p, new com.crackedgames.craftics.network.LoadingScreenPayload(
                true, "§eLoading Battle...", "§7Preparing the arena..."));
        }
    }

    /** Resolve which player owns this {@link CombatManager} instance -i.e. the
     *  player UUID this CM is keyed by in {@link #INSTANCES}. That's the original
     *  combat leader, regardless of who currently holds the turn. Falls back to
     *  {@code fallback} if the owner is offline or can't be resolved. */
    private ServerPlayerEntity resolveCmOwnerPlayer(ServerPlayerEntity fallback) {
        // Resolve the server from the fallback, or from the retained handle (survives
        // endCombat) so this still works when called with a null fallback between levels.
        net.minecraft.server.MinecraftServer srv = (fallback != null) ? fallback.getServer() : this.server;
        if (srv == null) return fallback;
        for (var entry : INSTANCES.entrySet()) {
            if (entry.getValue() == this) {
                ServerPlayerEntity owner = srv.getPlayerManager().getPlayer(entry.getKey());
                if (owner != null && !owner.isRemoved() && !owner.isDisconnected()) {
                    return owner;
                }
                break;
            }
        }
        return fallback;
    }

    /** Fire a scheduled event-return transition: build the next arena and enter battle.
     *  The incoming EnterCombatPayload dismisses the loading screen on each client. */
    private void fireEventReturnTransition() {
        ServerPlayerEntity leader = eventReturnLeader;
        eventReturnLeader = null;
        if (leader == null || leader.isRemoved() || leader.isDisconnected()) {
            // partyPlayers was emptied by endCombat -> cleanupPartyTracking at the start of
            // the interlude, so firstOnlinePartyMember() can return null. Resolve from durable
            // state first: this CM's owner (its INSTANCES key), then any party member.
            leader = resolveCmOwnerPlayer(null);
            if (leader == null) leader = firstOnlinePartyMember();
        }
        if (leader == null || pendingNextLevelDef == null || pendingBiome == null) {
            CrafticsMod.LOGGER.error(
                "fireEventReturnTransition aborted (leader={}, pendingDef={}, pendingBiome={}); "
                + "{} saved pet(s) at risk -rescuing to hub so they aren't lost",
                leader, pendingNextLevelDef, pendingBiome, savedPets.size());
            rescueSavedPetsToHubFallback(leader);
            pendingNextLevelDef = null;
            pendingBiome = null;
            pendingEventBiomeOrdinal = 0;
            return;
        }
        try {
            ServerWorld world = (ServerWorld) leader.getEntityWorld();
            GridArena nextArena = buildArena(world, pendingNextLevelDef);
            CrafticsMod.LOGGER.info("Event return: entering next level with {} saved pet(s).",
                savedPets.size());
            transitionPartyToArena(leader, nextArena, pendingNextLevelDef);
        } catch (Throwable t) {
            // The deferred transition runs under tickAll()'s blanket catch, which would
            // otherwise SWALLOW this after endCombat already discarded the live ally/mount
            // mobs -silently losing the party. Log it and rescue the captured pets to the
            // hub instead of dropping them.
            CrafticsMod.LOGGER.error("fireEventReturnTransition failed; rescuing pets to hub", t);
            rescueSavedPetsToHubFallback(leader);
            try { teleportToHub(leader); } catch (Throwable ignored) {}
            try { ServerPlayNetworking.send(leader, new ExitCombatPayload(false)); } catch (Throwable ignored) {}
        } finally {
            pendingNextLevelDef = null;
            pendingBiome = null;
            pendingEventBiomeOrdinal = 0;
        }
    }

    /** Last resort when the event-return transition can't build the next arena: push the
     *  in-memory saved pets back to the hub so the golems/mount aren't lost forever (they
     *  were removed from the hub world when the run began, and are never persisted to disk). */
    private void rescueSavedPetsToHubFallback(ServerPlayerEntity leader) {
        if (savedPets.isEmpty()) return;
        ServerPlayerEntity owner = (leader != null) ? leader : resolveCmOwnerPlayer(null);
        if (owner == null) return;
        try {
            ServerWorld w = (ServerWorld) owner.getEntityWorld();
            CrafticsSavedData d = CrafticsSavedData.get(w);
            HubPetCollector.restorePetsToHub(w, owner, savedPets, d);
            savedPets.clear();
            CrafticsMod.LOGGER.info("Rescued saved pets to the hub after a failed event return.");
        } catch (Throwable t) {
            CrafticsMod.LOGGER.warn("rescueSavedPetsToHubFallback failed: {}", t.getMessage());
        }
    }

    private GridArena buildArena(ServerWorld world, LevelDefinition def) {
        GridArena built = buildArenaInner(world, def);
        // Every battle start funnels through here, so this is the one choke point where
        // leftover arena mobs from a fight that never cleaned up (crash, force-quit,
        // chunk-unload mid-teardown) can be caught BEFORE the new battle spawns on top
        // of them. Those orphans are spawned persistent, AI-disabled and invulnerable,
        // so without this they stand in the arena forever as untargetable "ghosts".
        if (built != null) purgeGhostMobs(world, built);
        return built;
    }

    /**
     * Discard every entity still carrying a Craftics arena tag inside {@code arena}'s
     * volume. Safe by construction: this runs before the new fight spawns anything, and
     * an arena volume is never shared by two live fights, so anything tagged in it now
     * is by definition an orphan from a fight that failed to tear down.
     */
    private static void purgeGhostMobs(ServerWorld world, GridArena arena) {
        net.minecraft.util.math.BlockPos o = arena.getOrigin();
        // Generous vertical margin: flying combatants (ghasts, dragons) hover well above
        // the floor, and a ghost is worth over-sweeping for inside our own arena box.
        net.minecraft.util.math.Box volume = new net.minecraft.util.math.Box(
            o.getX() - 3, o.getY() - 6, o.getZ() - 3,
            o.getX() + arena.getWidth() + 3, o.getY() + 24, o.getZ() + arena.getHeight() + 3);
        java.util.List<net.minecraft.entity.Entity> ghosts = world.getOtherEntities(null, volume,
            e -> e.getCommandTags().contains("craftics_arena")
                || e.getCommandTags().contains("craftics_arena_mount")
                || e.getCommandTags().contains("craftics_visual_projectile")
                || e.getCommandTags().contains("craftics_stack_visual"));
        for (net.minecraft.entity.Entity ghost : ghosts) {
            ghost.discard();
        }
        if (!ghosts.isEmpty()) {
            CrafticsMod.LOGGER.info("Purged {} ghost arena mob(s) at {} before starting combat",
                ghosts.size(), o);
        }

        // NATURAL spawns are ghosts of a different kind: a Creaking sprouted from a decorative
        // tree heart (Pale Gardens), or a stray zombie from surrounding terrain, is not part of
        // any battle but will happily attack the player through it. Sweep untagged hostiles in
        // and just outside the arena too.
        java.util.List<net.minecraft.entity.Entity> naturals = world.getOtherEntities(null,
            volume.expand(8, 0, 8),
            e -> e instanceof net.minecraft.entity.mob.HostileEntity
                && e.getCommandTags().isEmpty());
        for (net.minecraft.entity.Entity stray : naturals) {
            stray.discard();
        }
        if (!naturals.isEmpty()) {
            CrafticsMod.LOGGER.info("Removed {} naturally-spawned hostile(s) around the arena at {}",
                naturals.size(), o);
        }

        // And stop the tap: any creaking_heart block in or around the arena would keep
        // spawning fresh Creaking all fight. Petrify them into plain wood. Matched by
        // registry id rather than a Blocks constant, so this also catches the Pale Garden
        // BACKPORT mod's heart on 1.21.1-1.21.3, where the vanilla constant doesn't exist.
        // Runs before this fight spawns anything, so the boss fight's own heart (placed
        // later, as a combat entity) is never touched - only decoration and leftovers.
        // The heart may be vanilla (1.21.4+) or the Pale Garden backport mod's (1.21.1-1.21.3).
        var heartBlock = blockByIdOrNull("minecraft", "creaking_heart");
        if (heartBlock == null) heartBlock = blockByIdOrNull("palegardenbackport", "creaking_heart");
        if (heartBlock != null) {
            var woodBlock = blockByIdOrNull("minecraft", "pale_oak_wood");
            if (woodBlock == null) woodBlock = blockByIdOrNull("palegardenbackport", "pale_oak_wood");
            if (woodBlock == null) woodBlock = net.minecraft.block.Blocks.OAK_WOOD;
            int petrified = 0;
            for (net.minecraft.util.math.BlockPos p : net.minecraft.util.math.BlockPos.iterate(
                    o.getX() - 16, o.getY() - 6, o.getZ() - 16,
                    o.getX() + arena.getWidth() + 16, o.getY() + 24, o.getZ() + arena.getHeight() + 16)) {
                if (world.getBlockState(p).isOf(heartBlock)) {
                    world.setBlockState(p, woodBlock.getDefaultState(),
                        net.minecraft.block.Block.FORCE_STATE);
                    petrified++;
                }
            }
            if (petrified > 0) {
                CrafticsMod.LOGGER.info("Petrified {} creaking heart(s) around the arena at {}",
                    petrified, o);
            }
        }
    }

    /** A block by registry id, or null when nothing is registered under it. containsId + get is
     *  the one lookup shape that exists unchanged across every supported MC version. */
    private static net.minecraft.block.Block blockByIdOrNull(String namespace, String path) {
        try {
            net.minecraft.util.Identifier id = net.minecraft.util.Identifier.of(namespace, path);
            if (!net.minecraft.registry.Registries.BLOCK.containsId(id)) return null;
            return net.minecraft.registry.Registries.BLOCK.get(id);
        } catch (Throwable t) {
            return null;
        }
    }

    private GridArena buildArenaInner(ServerWorld world, LevelDefinition def) {
        // Addon event levels (e.g. Artifacts mimic fight) can override the world
        // origin so they don't get placed in a random far-away row based on their
        // synthetic level number. When an override is present, skip the pre-built
        // cache entirely -event arenas are one-shot and never pre-generated.
        if (worldOwnerUuid != null) {
            com.crackedgames.craftics.world.CrafticsSavedData data =
                com.crackedgames.craftics.world.CrafticsSavedData.get(world);
            net.minecraft.util.math.BlockPos overrideOrigin = def.getOverrideOrigin(worldOwnerUuid, data);
            if (overrideOrigin != null) {
                CrafticsMod.LOGGER.info(
                    "buildArena: level '{}' uses override origin {} (skipping pre-built cache)",
                    def.getName(), overrideOrigin);
                return com.crackedgames.craftics.level.ArenaBuilder.buildAt(world, def, overrideOrigin);
            }
        }

        // Try pre-built arena first (instant -no block placement needed)
        // Only use the pre-gen cache for normal biome levels (GeneratedLevelDefinition).
        // Event levels (trial chambers, ambushes, treasure vaults) use synthetic level
        // numbers that would resolve to the wrong biome in ArenaPreGenerator.
        if (worldOwnerUuid != null && def instanceof com.crackedgames.craftics.level.GeneratedLevelDefinition) {
            com.crackedgames.craftics.world.CrafticsSavedData data =
                com.crackedgames.craftics.world.CrafticsSavedData.get(world);
            com.crackedgames.craftics.world.CrafticsSavedData.PlayerData pd =
                data.getPlayerData(worldOwnerUuid);
            if (pd.arenasPreGenerated) {
                // Lazy pre-gen: ensureArena builds this level's arena if this is
                // the first visit, otherwise returns the cached metadata cheaply.
                int[] meta = com.crackedgames.craftics.level.ArenaPreGenerator
                    .ensureArena(world, worldOwnerUuid, def.getLevelNumber());
                if (meta != null) {
                    // Auto-repair: if the stored arena is corrupted (e.g. the
                    // schematic left a hole in the floor, chunks got wiped by
                    // a world-edit), rebuild it in place before scanning so
                    // the player never drops into the void mid-combat.
                    // Snowy arenas always regenerate to restore melted ice/snow.
                    boolean isSnowy = def instanceof com.crackedgames.craftics.level.GeneratedLevelDefinition gld
                        && gld.getBiomeTemplate() != null
                        && "snowy".equals(gld.getBiomeTemplate().biomeId);
                    // The Tidecaller (river boss) floods half its arena PERMANENTLY by design -
                    // the terrain safeguard deliberately exempts plain WATER so the Deluge is
                    // real. But scanExisting reads that water back as legitimate terrain on the
                    // next visit, so without a rebuild the boss room stays flooded forever.
                    // Same cure as snowy: regenerate every time.
                    boolean isFloodedBossRoom = def instanceof com.crackedgames.craftics.level.GeneratedLevelDefinition rgld
                        && rgld.getBiomeTemplate() != null
                        && "river".equals(rgld.getBiomeTemplate().biomeId)
                        && rgld.getBiomeTemplate().isBossLevel(def.getLevelNumber());
                    boolean alwaysRegen = isSnowy || isFloodedBossRoom;
                    if (alwaysRegen || com.crackedgames.craftics.level.ArenaPreGenerator.isCorrupted(
                            world, worldOwnerUuid, def.getLevelNumber())) {
                        if (!alwaysRegen) sendMessage("§eDetected corrupted arena, rebuilding");
                        boolean repaired = com.crackedgames.craftics.level.ArenaPreGenerator
                            .regenerateLevel(world, worldOwnerUuid, def.getLevelNumber());
                        if (repaired) {
                            meta = pd.getArenaMetadata(def.getLevelNumber());
                            if (!alwaysRegen) sendMessage("§aArena rebuilt.");
                        }
                    }
                    if (meta != null) {
                        net.minecraft.util.math.BlockPos origin = new net.minecraft.util.math.BlockPos(
                            meta[0], meta[1], meta[2]);
                        int gridW = meta[3], gridH = meta[4];

                        // Snowy arenas: replace any remaining water with ice
                        if (isSnowy) {
                            for (int dx = 0; dx < gridW; dx++) {
                                for (int dz = 0; dz < gridH; dz++) {
                                    net.minecraft.util.math.BlockPos bp = origin.add(dx, 0, dz);
                                    // Check floor level and one below (water can pool)
                                    for (int dy = -1; dy <= 1; dy++) {
                                        net.minecraft.util.math.BlockPos check = bp.up(dy);
                                        if (world.getBlockState(check).getBlock() == net.minecraft.block.Blocks.WATER) {
                                            world.setBlockState(check,
                                                net.minecraft.block.Blocks.ICE.getDefaultState(),
                                                net.minecraft.block.Block.FORCE_STATE);
                                        }
                                    }
                                }
                            }
                        }

                        com.crackedgames.craftics.core.GridPos playerStart =
                            new com.crackedgames.craftics.core.GridPos(meta[5], meta[6]);
                        boolean[][] arenaMask = pd.getArenaMask(def.getLevelNumber(), gridW, gridH);
                        return com.crackedgames.craftics.level.ArenaBuilder.scanExisting(
                            world, origin, gridW, gridH, playerStart, def.getLevelNumber(), arenaMask);
                    }
                }
            }
            return com.crackedgames.craftics.level.ArenaBuilder.build(world, def, worldOwnerUuid);
        }
        return com.crackedgames.craftics.level.ArenaBuilder.build(world, def);
    }

    private static void teleportToHub(ServerPlayerEntity p) {
        com.crackedgames.craftics.world.HubTeleports.toHub(p);
    }

