    private boolean isFrostboundBossAttacker() {
        return currentEnemy != null && currentEnemy.isBoss()
            && "boss:snowy".equals(currentEnemy.getAiKey());
    }

    private void applyFrostboundSlownessOnHit() {
        addEffectHooked(CombatEffects.EffectType.SLOWNESS, 2, 1);
        sendMessage("§b  Frostbound chill! Slowness II for 2 turns.");
    }

    /**
     * Resolve terrain creation/transformation.
     */
    /**
     * Ignite any flammable tiles among {@code tiles} (tall grass/fern, cactus,
     * wood/leaf/wool obstacles, etc.) into temporary FIRE tiles that burn down
     * and spread on later turns (see tickFireSpread). Called by fire-based
     * attacks -Fire Aspect cone, bow Flame, fire knockback -so any flammable
     * obstacle caught in the attack is set alight. Returns the count ignited.
     */
    private int igniteFlammableTiles(Iterable<GridPos> tiles) {
        if (arena == null || player == null) return 0;
        ServerWorld world = (ServerWorld) player.getEntityWorld();
        int ignited = 0;
        for (GridPos pos : tiles) {
            if (!arena.isInBounds(pos)) continue;
            GridTile tile = arena.getTile(pos);
            if (tile == null || !FlammableTiles.isFlammable(tile)) continue;
            // Clear any standing block (tall grass/fern occupy Y+1) so the
            // obstacle is visibly burned away, then set the floor to FIRE.
            BlockPos floor = new BlockPos(
                arena.getOrigin().getX() + pos.x(),
                arena.getOrigin().getY(),
                arena.getOrigin().getZ() + pos.z());
            world.setBlockState(floor.up(1), Blocks.AIR.getDefaultState(),
                net.minecraft.block.Block.NOTIFY_LISTENERS | net.minecraft.block.Block.FORCE_STATE);
            world.setBlockState(floor.up(2), Blocks.AIR.getDefaultState(),
                net.minecraft.block.Block.NOTIFY_LISTENERS | net.minecraft.block.Block.FORCE_STATE);
            tile.setTemporaryType(TileType.FIRE, FlammableTiles.FIRE_BURN_TURNS);
            world.setBlockState(floor, tile.getBlockType().getDefaultState());
            world.spawnParticles(net.minecraft.particle.ParticleTypes.FLAME,
                floor.getX() + 0.5, floor.getY() + 0.5, floor.getZ() + 0.5,
                10, 0.3, 0.3, 0.3, 0.02);
            ignited++;
        }
        return ignited;
    }

    /**
     * Per-turn fire propagation. Every active FIRE tile spreads to its
     * orthogonally-adjacent flammable tiles, igniting them as fresh FIRE tiles
     * (which burn down and spread further on subsequent turns). Spread is
     * computed from a snapshot so newly-lit tiles don't chain across the whole
     * arena in a single turn. Called once per round from the turn tick.
     */
    private void tickFireSpread() {
        if (arena == null || player == null) return;
        java.util.List<GridPos> sources = new java.util.ArrayList<>();
        for (int x = 0; x < arena.getWidth(); x++) {
            for (int z = 0; z < arena.getHeight(); z++) {
                GridTile tile = arena.getTile(x, z);
                if (tile != null && tile.getType() == TileType.FIRE) {
                    sources.add(new GridPos(x, z));
                }
            }
        }
        if (sources.isEmpty()) return;
        java.util.LinkedHashSet<GridPos> toIgnite = new java.util.LinkedHashSet<>();
        int[][] dirs = {{1, 0}, {-1, 0}, {0, 1}, {0, -1}};
        for (GridPos src : sources) {
            for (int[] d : dirs) {
                GridPos n = new GridPos(src.x() + d[0], src.z() + d[1]);
                if (!arena.isInBounds(n)) continue;
                GridTile nt = arena.getTile(n);
                if (nt != null && FlammableTiles.isFlammable(nt)) toIgnite.add(n);
            }
        }
        int spread = igniteFlammableTiles(toIgnite);
        if (spread > 0) {
            sendMessage("§6The fire spreads to " + spread + " more tile" + (spread == 1 ? "" : "s") + "!");
        }
    }

    /**
     * Maximum lifetime (in turns) for blocking / floor-destroying terrain a boss
     * tries to create permanently. Long enough to stay tactically threatening,
     * short enough that the arena always recovers and can never be permanently
     * flooded or partitioned into an unreachable layout.
     */
    private static final int BOSS_BLOCKING_TERRAIN_DURATION = 6;

    private void resolveCreateTerrain(EnemyAction.CreateTerrain ct) {
        ServerWorld world = (ServerWorld) player.getEntityWorld();
        int duration = ct.duration();
        if (currentEnemy != null && currentEnemy.isBoss() && duration <= 0) {
            TileType tt = ct.terrainType();
            if (tt == TileType.FIRE || tt == TileType.LAVA) {
                // Prevent permanent trap patterns from boss lava/magma; always decay.
                duration = 3;
            } else if (tt == TileType.OBSTACLE || tt == TileType.VOID
                    || tt == TileType.DEEP_WATER) {
                // Same safeguard for blocking / floor-destroying terrain: a boss must
                // never PERMANENTLY wall off the arena or delete the floor. Left
                // permanent, Chorus plants, Rockbreaker boulders, and Void Herald
                // collapses accumulate every turn and can isolate the player on an
                // island or seal the boss out of melee reach -an unrecoverable
                // softlock. Force a finite lifetime so the arena always heals back to
                // a navigable state while the terrain stays threatening while active.
                duration = BOSS_BLOCKING_TERRAIN_DURATION;
            }
        }
        // Get biome-appropriate floor block for NORMAL terrain
        net.minecraft.block.Block biomeFloorBlock = null;
        if (ct.terrainType() == TileType.NORMAL) {
            biomeFloorBlock = getBiomeFloorBlock();
        }
        int changed = 0;
        for (GridPos pos : ct.tiles()) {
            if (!arena.isInBounds(pos)) continue;
            GridTile tile = arena.getTile(pos);
            if (tile == null) continue;

            if (duration > 0) {
                tile.setTemporaryType(ct.terrainType(), duration);
            } else {
                tile.setType(ct.terrainType());
            }
            // Frostbound ice walls: use literal above-floor ice obstacle blocks
            // (same layer as player-placed walls), while leaving the floor tile
            // itself intact so they "break down" cleanly when duration expires.
            boolean snowyIceWall = ct.terrainType() == TileType.OBSTACLE
                && currentEnemy != null
                && "boss:snowy".equals(currentEnemy.getAiKey());
            if (snowyIceWall) {
                tile.setBlockType(Blocks.PACKED_ICE);
            }
            // Override the block type for NORMAL tiles to match the arena biome
            if (biomeFloorBlock != null) {
                tile.setBlockType(biomeFloorBlock);
            }
            // Update the visual block in the world (floor level, not above)
            BlockPos bp = new BlockPos(
                arena.getOrigin().getX() + pos.x(),
                arena.getOrigin().getY(),
                arena.getOrigin().getZ() + pos.z());
            if (ct.terrainType() == TileType.POWDER_SNOW) {
                world.setBlockState(bp.down(), Blocks.STONE.getDefaultState());
            }
            if (snowyIceWall) {
                world.setBlockState(bp.up(), Blocks.PACKED_ICE.getDefaultState());
            } else {
                world.setBlockState(bp, tile.getBlockType().getDefaultState());
                // Snow-layer overlays can hide newly-created obstacle terrain in
                // snowy arenas; clear the overlay so unwalkable tiles are visible.
                if (ct.terrainType() == TileType.OBSTACLE) {
                    BlockPos abovePos = bp.up();
                    if (world.getBlockState(abovePos).getBlock() instanceof net.minecraft.block.SnowBlock) {
                        world.setBlockState(abovePos, Blocks.AIR.getDefaultState());
                    }
                }
            }

            // Particles for the transformation
            world.spawnParticles(net.minecraft.particle.ParticleTypes.POOF,
                bp.getX() + 0.5, bp.getY() + 0.5, bp.getZ() + 0.5,
                3, 0.3, 0.3, 0.3, 0.01);
            changed++;
        }
        // Only the enemy path announces the reshape. Player-initiated terrain (e.g. the
        // netherite mount's lava line) runs with currentEnemy null and sends its own
        // message, so skip here to avoid an NPE and a duplicate line.
        if (changed > 0 && currentEnemy != null) {
            String terrainName = ct.terrainType().name().toLowerCase();
            sendMessage("§e  " + currentEnemy.getDisplayName() + " reshapes " + changed
                + " tiles to " + terrainName + "!");
        }
    }

    /** Resolve a Spider-style web placement: drop cobwebs at floor+1 on each
     *  target tile via the arena web-overlay system so the floor stays intact
     *  underneath and pathfinding treats the tile as slowing (not blocked).
     *  Delegates to {@link #placeWebOverlays}. */
    private void resolvePlaceWeb(EnemyAction.PlaceWeb pw) {
        java.util.List<GridPos> inBounds = new java.util.ArrayList<>();
        for (GridPos pos : pw.tiles()) {
            if (arena.isInBounds(pos)) inBounds.add(pos);
        }
        if (inBounds.isEmpty()) return;
        placeWebOverlays(inBounds, pw.duration());
        if (currentEnemy != null) {
            sendMessage("§e  " + currentEnemy.getDisplayName() + " lays "
                + inBounds.size() + " cobweb" + (inBounds.size() == 1 ? "" : "s") + "!");
        }
    }

    /**
     * Resolve a line attack -damage all entities along a line.
     */
    private void resolveLineAttack(EnemyAction.LineAttack la) {
        GridPos playerGridPos = arena.getPlayerGridPos();
        ServerWorld world = (ServerWorld) player.getEntityWorld();
        boolean hitPlayer = false;

        // Determine line particle type based on the current boss
        net.minecraft.particle.ParticleEffect lineParticle = net.minecraft.particle.ParticleTypes.CRIT;
        net.minecraft.particle.ParticleEffect trailParticle = net.minecraft.particle.ParticleTypes.SMOKE;
        if (currentEnemy != null) {
            String aiKey = currentEnemy.getAiKey();
            if (aiKey != null) {
                if (aiKey.contains("ashen_warlord") || aiKey.contains("AshenWarlord")) {
                    lineParticle = net.minecraft.particle.ParticleTypes.FLAME;
                    trailParticle = net.minecraft.particle.ParticleTypes.SOUL_FIRE_FLAME;
                } else if (aiKey.contains("hexweaver") || aiKey.contains("Hexweaver")) {
                    lineParticle = net.minecraft.particle.ParticleTypes.WITCH;
                    trailParticle = net.minecraft.particle.ParticleTypes.SOUL;
                } else if (aiKey.contains("hollow_king") || aiKey.contains("HollowKing")) {
                    lineParticle = net.minecraft.particle.ParticleTypes.CAMPFIRE_COSY_SMOKE;
                    trailParticle = net.minecraft.particle.ParticleTypes.ASH;
                } else if (aiKey.contains("revenant") || aiKey.contains("Revenant")) {
                    lineParticle = net.minecraft.particle.ParticleTypes.SMOKE;
                    trailParticle = net.minecraft.particle.ParticleTypes.SOUL;
                } else if (aiKey.contains("crimson") || aiKey.contains("Crimson")) {
                    lineParticle = net.minecraft.particle.ParticleTypes.CRIMSON_SPORE;
                    trailParticle = net.minecraft.particle.ParticleTypes.FLAME;
                } else if (aiKey.contains("wither") || aiKey.contains("Wither")) {
                    lineParticle = net.minecraft.particle.ParticleTypes.SOUL;
                    trailParticle = net.minecraft.particle.ParticleTypes.LARGE_SMOKE;
                } else if (aiKey.contains("tidecaller") || aiKey.contains("Tidecaller")) {
                    lineParticle = net.minecraft.particle.ParticleTypes.SPLASH;
                    trailParticle = net.minecraft.particle.ParticleTypes.BUBBLE;
                } else if (aiKey.contains("warped_forest")) {
                    // Void Walker -void beam
                    lineParticle = net.minecraft.particle.ParticleTypes.PORTAL;
                    trailParticle = net.minecraft.particle.ParticleTypes.REVERSE_PORTAL;
                } else if (aiKey.contains("dragons_nest")) {
                    // Ender Dragon breath -magenta dragon breath + portal shimmer
                    lineParticle = net.minecraft.particle.ParticleTypes.DRAGON_BREATH;
                    trailParticle = net.minecraft.particle.ParticleTypes.PORTAL;
                }
            }
        }

        java.util.Set<GridPos> lineTiles = new java.util.HashSet<>();
        for (int i = 0; i < la.length(); i++) {
            GridPos tile = new GridPos(la.start().x() + la.dx() * i, la.start().z() + la.dz() * i);
            if (!arena.isInBounds(tile)) continue;
            lineTiles.add(tile);
            if (tile.equals(playerGridPos)) hitPlayer = true;

            // Spawn line particles along each tile
            BlockPos bp = arena.gridToBlockPos(tile);
            world.spawnParticles(lineParticle,
                bp.getX() + 0.5, bp.getY() + 0.8, bp.getZ() + 0.5,
                5, 0.2, 0.4, 0.2, 0.02);
            world.spawnParticles(trailParticle,
                bp.getX() + 0.5, bp.getY() + 0.3, bp.getZ() + 0.5,
                3, 0.15, 0.2, 0.15, 0.01);

            // Damage enemies in the line (friendly fire)
            if (CrafticsMod.CONFIG.friendlyFireEnabled()) {
                CombatEntity occupant = arena.getOccupant(tile);
                if (occupant != null && occupant != currentEnemy && occupant.isAlive()) {
                    int dealt = occupant.takeDamage(la.damage());
                    sendMessage("§6  Line hits " + occupant.getDisplayName() + " for " + dealt + "!");
                    checkAndHandleDeath(occupant);
                }
            }
        }
        // Damage EVERY party member standing on a line tile, not just the host.
        // A non-leader teammate standing in the beam previously took no damage
        // because the line was only tested against arena.getPlayerGridPos().
        // Each hit routes through the this.player swap for correct per-victim
        // dodge/armor/effects/death handling.
        java.util.List<ServerPlayerEntity> lineVictims = new java.util.ArrayList<>();
        if (partyPlayers.size() > 1) {
            for (ServerPlayerEntity member : partyPlayers) {
                if (member == null || member.isRemoved() || member.isDisconnected()) continue;
                if (deadPartyMembers.contains(member.getUuid())) continue;
                if (lineTiles.contains(gridPosOf(member))) lineVictims.add(member);
            }
        } else if (hitPlayer) {
            lineVictims.add(player);
        }
        boolean gameOverFromLine = false;
        for (ServerPlayerEntity victim : lineVictims) {
            ServerPlayerEntity savedLinePlayer = this.player;
            boolean lineSwapped = victim != savedLinePlayer;
            if (lineSwapped) { this.player = victim; retargetEffectsToCurrentPlayer(); }
            boolean victimDied = false;
            try {
                int actual = damagePlayer(la.damage());
                sendMessage("§c  Line attack hits " + (lineSwapped ? victim.getName().getString() : "you")
                    + " for " + actual + " damage! (HP: " + getPlayerHp() + ")");
                if (getPlayerHp() <= 0) {
                    victimDied = true;
                    handlePlayerDeathOrGameOver();
                    gameOverFromLine = (partyPlayers.size() <= 1 || !active);
                }
            } finally {
                if (!victimDied) { this.player = savedLinePlayer; retargetEffectsToCurrentPlayer(); }
            }
            if (gameOverFromLine) return;
        }
    }

    private boolean tryDestroyRevenantSummonMarker(GridPos clickedTile) {
        GridPos playerPos = arena.getPlayerGridPos();
        Item weapon = player.getMainHandStack().getItem();
        int range = getEffectiveWeaponRange();
        if (range > 1) range += getScaffoldRangeBonus(playerPos);

        int dist = PlayerCombatStats.isBow(player)
            ? playerPos.manhattanDistance(clickedTile)
            : Math.max(Math.abs(playerPos.x() - clickedTile.x()), Math.abs(playerPos.z() - clickedTile.z()));
        if (dist > range) {
            sendMessage("§cThat grave marker is out of range!");
            return false;
        }

        int attackCost = WeaponAbility.getAttackCost(weapon);
        if (weapon == Items.CROSSBOW) {
            attackCost = Math.max(1, attackCost - PlayerCombatStats.getQuickCharge(player));
        }
        int rogueReduction = PlayerCombatStats.getSetApCostReduction(player);
        if (rogueReduction > 0) {
            attackCost = Math.max(1, attackCost - rogueReduction);
        }
        if (apRemaining < attackCost) {
            sendMessage("§cNeed " + attackCost + " AP to attack! (have " + apRemaining + ")");
            return false;
        }

        apRemaining -= attackCost;
        ItemStack weaponStack = player.getMainHandStack();
        if (weaponStack.isDamageable()) {
            weaponStack.damage(7, player, net.minecraft.entity.EquipmentSlot.MAINHAND);
            if (weaponStack.isEmpty() || weaponStack.getDamage() >= weaponStack.getMaxDamage()) {
                sendMessage("§c§lYour weapon broke!");
            }
        }

        removeRevenantSummonMarker(clickedTile);
        player.getWorld().playSound(null, arena.gridToBlockPos(clickedTile),
            net.minecraft.sound.SoundEvents.BLOCK_BONE_BLOCK_BREAK,
            net.minecraft.sound.SoundCategory.PLAYERS, 1.0f, 0.9f);
        sendMessage("§aYou smash the zombie head before the corpse can rise!");
        return true;
    }

    private boolean isRevenantZombieSummon(EnemyAction.SummonMinions sm) {
        return currentEnemy != null
            && currentEnemy.getAiKey() != null
            && currentEnemy.getAiKey().contains("revenant")
            && "minecraft:zombie".equals(sm.entityTypeId());
    }

    private boolean isRevenantSummonMarker(GridPos pos) {
        return TILE_EFFECT_REVENANT_HEAD.equals(tileEffects.get(pos));
    }

    private void syncSpecialBossWarningMarkers(com.crackedgames.craftics.combat.ai.boss.BossWarning warning) {
        EnemyAction resolveAction = warning.getResolveAction();
        if (resolveAction instanceof EnemyAction.SummonMinions sm
                && "minecraft:zombie".equals(sm.entityTypeId())
                && currentEnemy != null
                && currentEnemy.getAiKey() != null
                && currentEnemy.getAiKey().contains("revenant")) {
            syncRevenantSummonMarkers(warning.getAffectedTiles());
        }
    }

    private void syncRevenantSummonMarkers(java.util.List<GridPos> desiredTiles) {
        java.util.Set<GridPos> desired = new java.util.HashSet<>(desiredTiles);
        java.util.List<GridPos> existing = new java.util.ArrayList<>();
        for (var entry : tileEffects.entrySet()) {
            if (TILE_EFFECT_REVENANT_HEAD.equals(entry.getValue())) {
                existing.add(entry.getKey());
            }
        }
        for (GridPos pos : existing) {
            if (!desired.contains(pos)) {
                removeRevenantSummonMarker(pos);
            }
        }
        for (GridPos pos : desired) {
            placeRevenantSummonMarker(pos);
        }
    }

    private void clearRevenantSummonMarkers(java.util.List<GridPos> positions) {
        for (GridPos pos : positions) {
            removeRevenantSummonMarker(pos);
        }
    }

    private void clearAllRevenantSummonMarkers() {
        java.util.List<GridPos> markers = new java.util.ArrayList<>();
        for (var entry : tileEffects.entrySet()) {
            if (TILE_EFFECT_REVENANT_HEAD.equals(entry.getValue())) {
                markers.add(entry.getKey());
            }
        }
        clearRevenantSummonMarkers(markers);
    }

    private void placeRevenantSummonMarker(GridPos pos) {
        tileEffects.put(pos, TILE_EFFECT_REVENANT_HEAD);
        ServerWorld world = (ServerWorld) player.getEntityWorld();
        BlockPos headPos = arena.gridToBlockPos(pos).up();
        if (!world.getBlockState(headPos).isAir() && !world.getBlockState(headPos).isOf(Blocks.ZOMBIE_HEAD)) {
            return;
        }
        world.setBlockState(headPos,
            Blocks.ZOMBIE_HEAD.getDefaultState().with(net.minecraft.block.SkullBlock.ROTATION, 0));
        world.spawnParticles(net.minecraft.particle.ParticleTypes.ASH,
            headPos.getX() + 0.5, headPos.getY() + 0.2, headPos.getZ() + 0.5,
            5, 0.2, 0.1, 0.2, 0.01);
    }

    private void removeRevenantSummonMarker(GridPos pos) {
        tileEffects.remove(pos, TILE_EFFECT_REVENANT_HEAD);
        if (player == null) return;
        ServerWorld world = (ServerWorld) player.getEntityWorld();
        BlockPos headPos = arena.gridToBlockPos(pos).up();
        if (world.getBlockState(headPos).isOf(Blocks.ZOMBIE_HEAD)) {
            world.setBlockState(headPos, Blocks.AIR.getDefaultState());
            world.spawnParticles(net.minecraft.particle.ParticleTypes.POOF,
                headPos.getX() + 0.5, headPos.getY() + 0.2, headPos.getZ() + 0.5,
                4, 0.15, 0.1, 0.15, 0.01);
        }
    }

    /**
     * Resolve a boss self-modification (buff/debuff).
     */
    private void resolveModifySelf(CombatEntity boss, EnemyAction.ModifySelf ms) {
        ServerWorld world = (ServerWorld) player.getEntityWorld();
        MobEntity bMob = boss.getMobEntity();
        double bx = bMob != null ? bMob.getX() : 0;
        double by = bMob != null ? bMob.getY() + 1.0 : 0;
        double bz = bMob != null ? bMob.getZ() : 0;

        switch (ms.stat()) {
            case "speed" -> {
                boss.setSpeedBonus(boss.getSpeedBonus() + ms.amount());
                // Speed boost -wind swirl
                if (bMob != null) {
                    world.spawnParticles(net.minecraft.particle.ParticleTypes.CLOUD,
                        bx, by, bz, 8, 0.4, 0.6, 0.4, 0.03);
                    world.spawnParticles(net.minecraft.particle.ParticleTypes.SWEEP_ATTACK,
                        bx, by - 0.3, bz, 2, 0.2, 0.1, 0.2, 0.0);
                }
                sendMessage("§d  " + boss.getDisplayName() + " gains +" + ms.amount() + " speed!");
            }
            case "defense" -> {
                boss.setDefensePenalty(boss.getDefensePenalty() - ms.amount());
                if (ms.duration() > 0) {
                    boss.setDefensePenaltyTurns(ms.duration());
                }
                // Defense boost -armored shimmer
                if (bMob != null) {
                    world.spawnParticles(net.minecraft.particle.ParticleTypes.ENCHANTED_HIT,
                        bx, by, bz, 12, 0.4, 0.6, 0.4, 0.02);
                    world.spawnParticles(net.minecraft.particle.ParticleTypes.END_ROD,
                        bx, by + 0.3, bz, 5, 0.3, 0.5, 0.3, 0.01);
                }
                sendMessage("§d  " + boss.getDisplayName() + " gains +" + ms.amount() + " defense!");
            }
            case "attack" -> {
                boss.setAttackPenalty(boss.getAttackPenalty() - ms.amount());
                // Attack boost -aggressive red sparks
                if (bMob != null) {
                    world.spawnParticles(net.minecraft.particle.ParticleTypes.CRIT,
                        bx, by, bz, 10, 0.3, 0.5, 0.3, 0.03);
                    world.spawnParticles(net.minecraft.particle.ParticleTypes.DAMAGE_INDICATOR,
                        bx, by + 0.3, bz, 5, 0.2, 0.3, 0.2, 0.01);
                }
                sendMessage("§d  " + boss.getDisplayName() + " gains +" + ms.amount() + " attack!");
            }
            case "hp", "heal" -> {
                boss.heal(ms.amount());
                // Heal -green sparkles + hearts
                if (bMob != null) {
                    world.spawnParticles(net.minecraft.particle.ParticleTypes.HAPPY_VILLAGER,
                        bx, by, bz, 10, 0.4, 0.6, 0.4, 0.02);
                    world.spawnParticles(net.minecraft.particle.ParticleTypes.HEART,
                        bx, by + 0.5, bz, 3, 0.3, 0.3, 0.3, 0.0);
                }
                sendMessage("§a  " + boss.getDisplayName() + " heals for " + ms.amount() + " HP!");
            }
            default -> {
                if (bMob != null) {
                    world.spawnParticles(net.minecraft.particle.ParticleTypes.ENCHANT,
                        bx, by, bz, 8, 0.3, 0.5, 0.3, 0.02);
                }
                sendMessage("§d  " + boss.getDisplayName() + " modifies " + ms.stat() + "!");
            }
        }
    }

    /**
     * Resolve forced movement -push/pull a target entity.
     */
    private void resolveForcedMovement(EnemyAction.ForcedMovement fm) {
        ServerWorld fmWorld = (ServerWorld) player.getEntityWorld();
        if (fm.targetEntityId() == -1) {
            // Move the player the boss actually targeted (closest live member), not
            // the last-acting member that arena.getPlayerGridPos()/this.player point
            // at. The push direction was computed against that member, so the origin
            // must be their tile or the wrong player gets displaced from the wrong
            // spot (and void-fall damage hits the wrong player). Routed via the
            // this.player swap so the void-fall + rift handling apply to them.
            ServerPlayerEntity savedFmPlayer = this.player;
            GridPos savedFmGrid = arena.getPlayerGridPos();
            ServerPlayerEntity fmTarget = currentEnemy != null
                ? findClosestPartyTarget(currentEnemy.getGridPos()) : this.player;
            boolean fmSwapped = fmTarget != null && fmTarget != savedFmPlayer;
            if (fmSwapped) {
                this.player = fmTarget;
                retargetEffectsToCurrentPlayer();
                arena.setPlayerGridPos(gridPosOf(fmTarget));
            }
            boolean fmTargetDied = false;
            try {
            // Move the player -spawn wind particles along push/pull path
            GridPos playerGridPos = arena.getPlayerGridPos();
            GridPos landingPos = playerGridPos;
            for (int i = 1; i <= fm.tiles(); i++) {
                GridPos candidate = new GridPos(playerGridPos.x() + fm.dx() * i, playerGridPos.z() + fm.dz() * i);
                if (!arena.isInBounds(candidate) || arena.isEnemyOccupied(candidate)) break;
                GridTile tile = arena.getTile(candidate);
                if (tile != null && tile.getType() == TileType.VOID) {
                    // Player pushed into void -take fall damage
                    int fallDmg = damagePlayer(5);
                    sendMessage("§c  Pushed into the void for " + fallDmg + " damage! (HP: " + getPlayerHp() + ")");
                    if (getPlayerHp() <= 0) { fmTargetDied = true; handlePlayerDeathOrGameOver(); return; }
                    break;
                }
                if (tile == null || !tile.isWalkable()) break;
                // Wind trail along movement path
                BlockPos pathBp = arena.gridToBlockPos(candidate);
                fmWorld.spawnParticles(net.minecraft.particle.ParticleTypes.CLOUD,
                    pathBp.getX() + 0.5, pathBp.getY() + 0.8, pathBp.getZ() + 0.5,
                    3, 0.2, 0.3, 0.2, 0.02);
                fmWorld.spawnParticles(net.minecraft.particle.ParticleTypes.SWEEP_ATTACK,
                    pathBp.getX() + 0.5, pathBp.getY() + 0.5, pathBp.getZ() + 0.5,
                    1, 0.1, 0.1, 0.1, 0.0);
                landingPos = candidate;
            }
            if (!landingPos.equals(playerGridPos)) {
                arena.setPlayerGridPos(landingPos);
                BlockPos bp = arena.gridToBlockPos(landingPos);
                player.requestTeleport(bp.getX() + 0.5, bp.getY(), bp.getZ() + 0.5);
                broadcastPlayerPositionToOthers(player);
                // Landing impact
                fmWorld.spawnParticles(net.minecraft.particle.ParticleTypes.CLOUD,
                    bp.getX() + 0.5, bp.getY() + 0.5, bp.getZ() + 0.5,
                    5, 0.3, 0.3, 0.3, 0.01);
                sendMessage("§e  Pushed " + playerGridPos.manhattanDistance(landingPos) + " tiles!");
                // Void Walker: Void Pull may have dragged the player onto one of the boss's own rifts.
                handleVoidRiftEntry(landingPos);
            }
            } finally {
                if (fmSwapped && !fmTargetDied) {
                    this.player = savedFmPlayer;
                    retargetEffectsToCurrentPlayer();
                    arena.setPlayerGridPos(savedFmGrid);
                }
            }
        } else {
            // Move an enemy entity
            CombatEntity target = findEnemyById(fm.targetEntityId());
            if (target != null && target.isAlive()) {
                knockEnemyBack(target, fm.dx(), fm.dz(), fm.tiles());
            }
        }
    }

    /**
     * Highlight a warning tile for the player (red glow effect).
     */
    private void highlightWarningTile(GridPos tile) {
        // Send warning tile highlight to client for rendering
        if (player != null) {
            sendToAllParty(new CombatEventPayload(
                CombatEventPayload.EVENT_TILE_WARNING, 0, 0, 0, tile.x(), tile.z()
            ));
        }
    }

    /**
     * Render a boss warning. Some warnings only use particles/client overlays,
     * while line-style telegraphs also place a temporary floor marker.
     */
    private void renderBossWarning(com.crackedgames.craftics.combat.ai.boss.BossWarning warning) {
        if (warning == null) return;
        syncSpecialBossWarningMarkers(warning);
        // Always highlight affected tiles via the client-side red overlay
        for (GridPos tile : warning.getAffectedTiles()) {
            highlightWarningTile(tile);
        }

        // Spawn thematic particles based on warning type and color
        switch (warning.getType()) {
            case GROUND_CRACK -> {
                // Pick thematic crack particles based on boss color
                net.minecraft.particle.ParticleEffect crackParticle = getWarningParticleForColor(warning.getColor());
                spawnWarningParticles(warning.getAffectedTiles(), crackParticle, 3);
                // Additional rumble particles for all ground cracks
                spawnWarningParticles(warning.getAffectedTiles(), net.minecraft.particle.ParticleTypes.CAMPFIRE_COSY_SMOKE, 1);
            }
            case GATHERING_PARTICLES -> {
                // Converging particles -boss is charging up
                net.minecraft.particle.ParticleEffect gatherParticle = getWarningParticleForColor(warning.getColor());
                spawnWarningParticles(warning.getAffectedTiles(), gatherParticle, 2);
                spawnWarningParticles(warning.getAffectedTiles(), net.minecraft.particle.ParticleTypes.ENCHANT, 3);
            }
            case TILE_HIGHLIGHT -> {
                // Danger zone -subtle shimmer particles on top of the red overlay
                net.minecraft.particle.ParticleEffect shimmerParticle = getWarningParticleForColor(warning.getColor());
                spawnWarningParticles(warning.getAffectedTiles(), shimmerParticle, 2);
            }
            case DIRECTIONAL -> {
                // Directional wind/spark particles. When the warning carries a real
                // direction, particles DRIFT along it (velocity mode) so even the
                // server-side layer reads "that way", matching the client arrows.
                if (warning.hasDirection() && player != null && arena != null) {
                    ServerWorld dirWorld = (ServerWorld) player.getEntityWorld();
                    for (GridPos tile : warning.getAffectedTiles()) {
                        if (!arena.isInBounds(tile)) continue;
                        BlockPos bp = arena.gridToBlockPos(tile);
                        // count=0 -> offsets become velocity; speed scales the vector
                        dirWorld.spawnParticles(net.minecraft.particle.ParticleTypes.CLOUD,
                            bp.getX() + 0.5, bp.getY() + 1.2, bp.getZ() + 0.5,
                            0, warning.getDirX(), 0.02, warning.getDirZ(), 0.18);
                        dirWorld.spawnParticles(net.minecraft.particle.ParticleTypes.CRIT,
                            bp.getX() + 0.5, bp.getY() + 1.0, bp.getZ() + 0.5,
                            0, warning.getDirX(), 0.0, warning.getDirZ(), 0.3);
                    }
                } else {
                    spawnWarningParticles(warning.getAffectedTiles(), net.minecraft.particle.ParticleTypes.CLOUD, 2);
                    spawnWarningParticles(warning.getAffectedTiles(), net.minecraft.particle.ParticleTypes.CRIT, 1);
                }
            }
            case ENTITY_GLOW -> {
                // Boss is powering up -bright sparks
                spawnWarningParticles(warning.getAffectedTiles(), net.minecraft.particle.ParticleTypes.END_ROD, 2);
                spawnWarningParticles(warning.getAffectedTiles(), net.minecraft.particle.ParticleTypes.ENCHANTED_HIT, 1);
            }
            case SOUND_ONLY -> {} // No particles for sound-only warnings
        }
    }

    /**
     * Pick a thematic warning particle based on the boss warning ARGB color.
     * Uses the dominant color channel to determine the boss theme.
     */
    private net.minecraft.particle.ParticleEffect getWarningParticleForColor(int argb) {
        int r = (argb >> 16) & 0xFF;
        int g = (argb >> 8) & 0xFF;
        int b = argb & 0xFF;

        // Fire/lava bosses: heavy red, low blue
        if (r > 180 && b < 100 && g < 150) return net.minecraft.particle.ParticleTypes.FLAME;
        // Ice/water bosses: heavy blue
        if (b > 150 && r < 100) return net.minecraft.particle.ParticleTypes.SNOWFLAKE;
        // Water/tidal: moderate blue with some green
        if (b > 130 && g > 80 && r < 100) return net.minecraft.particle.ParticleTypes.SPLASH;
        // Nature/chorus: heavy green
        if (g > 150 && r < 150 && b < 150) return net.minecraft.particle.ParticleTypes.HAPPY_VILLAGER;
        // Void/ender: purple tones (r and b both high, g low)
        if (r > 60 && b > 100 && g < 100) return net.minecraft.particle.ParticleTypes.PORTAL;
        // Wither/dark: very dark colors
        if (r < 80 && g < 80 && b < 80) return net.minecraft.particle.ParticleTypes.SOUL;
        // Sand/earth: tan/brown
        if (r > 150 && g > 100 && b < 100) return net.minecraft.particle.ParticleTypes.ASH;
        // White/bright: phase transitions
        if (r > 200 && g > 200 && b > 200) return net.minecraft.particle.ParticleTypes.FLASH;
        // Default
        return net.minecraft.particle.ParticleTypes.CRIT;
    }

    private void spawnWarningParticles(java.util.List<GridPos> tiles,
                                       net.minecraft.particle.ParticleEffect particle,
                                       int countPerTile) {
        if (player == null || arena == null) return;
        ServerWorld world = (ServerWorld) player.getEntityWorld();
        for (GridPos tile : tiles) {
            if (!arena.isInBounds(tile)) continue;
            BlockPos bp = arena.gridToBlockPos(tile);
            world.spawnParticles(
                particle,
                bp.getX() + 0.5,
                bp.getY() + 0.15,
                bp.getZ() + 0.5,
                countPerTile,
                0.18,
                0.02,
                0.18,
                0.01
            );
        }
    }

    /**
     * Spawn telegraph particles when a BossAbility warning is first placed.
     * These give the player an immediate visual cue that danger is incoming.
     */
    private void spawnBossAbilityTelegraphParticles(EnemyAction.BossAbility ba) {
        if (player == null || arena == null) return;
        ServerWorld world = (ServerWorld) player.getEntityWorld();
        String name = ba.abilityName();
        java.util.List<GridPos> tiles = ba.warningTiles();
        if (tiles == null || tiles.isEmpty()) return;

        // Pick telegraph particles based on ability name
        net.minecraft.particle.ParticleEffect primary;
        net.minecraft.particle.ParticleEffect secondary;
        switch (name) {
            case "ash_storm" -> { primary = net.minecraft.particle.ParticleTypes.ASH; secondary = net.minecraft.particle.ParticleTypes.SOUL_FIRE_FLAME; }
            case "wither_slash", "wither_applied" -> { primary = net.minecraft.particle.ParticleTypes.SOUL; secondary = net.minecraft.particle.ParticleTypes.SMOKE; }
            case "ground_slam" -> { primary = net.minecraft.particle.ParticleTypes.LAVA; secondary = net.minecraft.particle.ParticleTypes.FLAME; }
            case "absorb" -> { primary = net.minecraft.particle.ParticleTypes.LAVA; secondary = net.minecraft.particle.ParticleTypes.FLAME; }
            case "fortify_shell", "fortify_shell_reflect" -> { primary = net.minecraft.particle.ParticleTypes.END_ROD; secondary = net.minecraft.particle.ParticleTypes.ENCHANTED_HIT; }
            case "soul_chain" -> { primary = net.minecraft.particle.ParticleTypes.SOUL_FIRE_FLAME; secondary = net.minecraft.particle.ParticleTypes.SOUL; }
            case "void_rift", "void_beam", "null_burst", "ender_roar" -> { primary = net.minecraft.particle.ParticleTypes.PORTAL; secondary = net.minecraft.particle.ParticleTypes.REVERSE_PORTAL; }
            case "darkness_pulse", "tremor_stomp" -> { primary = net.minecraft.particle.ParticleTypes.SCULK_SOUL; secondary = net.minecraft.particle.ParticleTypes.LARGE_SMOKE; }
            case "lights_out" -> { primary = net.minecraft.particle.ParticleTypes.LARGE_SMOKE; secondary = net.minecraft.particle.ParticleTypes.SMOKE; }
            default -> { primary = net.minecraft.particle.ParticleTypes.ENCHANT; secondary = net.minecraft.particle.ParticleTypes.CRIT; }
        }

        // Spawn a modest burst on each warned tile (not too many -these persist visually)
        for (GridPos tile : tiles) {
            if (!arena.isInBounds(tile)) continue;
            BlockPos bp = arena.gridToBlockPos(tile);
            world.spawnParticles(primary,
                bp.getX() + 0.5, bp.getY() + 0.5, bp.getZ() + 0.5,
                3, 0.2, 0.3, 0.2, 0.01);
            world.spawnParticles(secondary,
                bp.getX() + 0.5, bp.getY() + 0.2, bp.getZ() + 0.5,
                2, 0.15, 0.15, 0.15, 0.005);
        }
    }


    /**
     * Tick all temporary terrain tiles (fire, lava, etc.) -called at the start of each turn.
     */
    private void tickTemporaryTerrain() {
        ServerWorld world = (ServerWorld) player.getEntityWorld();
        for (int x = 0; x < arena.getWidth(); x++) {
            for (int z = 0; z < arena.getHeight(); z++) {
                GridTile tile = arena.getTile(x, z);
                if (tile != null && tile.getTurnsRemaining() > 0) {
                    TileType before = tile.getType();
                    tile.tickTurn();
                    if (tile.getType() != before) {
                        BlockPos bp = new BlockPos(
                            arena.getOrigin().getX() + x,
                            arena.getOrigin().getY(),
                            arena.getOrigin().getZ() + z);
                        // Temporary wall-style obstacle terrain is rendered in the
                        // obstacle layer (Y+1); clear it when the tile restores.
                        if (before == TileType.OBSTACLE) {
                            world.setBlockState(bp.up(), Blocks.AIR.getDefaultState());
                        }
                        world.setBlockState(bp, tile.getBlockType().getDefaultState());
                    }
                }
            }
        }
    }

    /**
     * Advance all active dragon breath waves. Each wave moves 3 tiles per turn,
     * placing fire and damaging the player if they stand in the path. Waves run
     * autonomously -the dragon can keep choosing attacks while waves march.
     */
    private void tickDragonBreathWaves() {
        if (player == null || arena == null) return;
        for (CombatEntity e : enemies) {
            if (!e.isAlive() || !e.isBoss()) continue;
            EnemyAI ai = resolveAi(e);
            if (!(ai instanceof com.crackedgames.craftics.combat.ai.DragonAI dragonAi)) continue;
            if (dragonAi.getActiveWaves().isEmpty()) continue;

            List<GridPos> burned = dragonAi.tickWaves(arena);
            if (burned.isEmpty()) continue;

            ServerWorld world = (ServerWorld) player.getEntityWorld();

            // Update world blocks for the newly-fired tiles
            for (GridPos pos : burned) {
                GridTile tile = arena.getTile(pos);
                if (tile == null) continue;
                BlockPos bp = new BlockPos(
                    arena.getOrigin().getX() + pos.x(),
                    arena.getOrigin().getY(),
                    arena.getOrigin().getZ() + pos.z());
                world.setBlockState(bp, tile.getBlockType().getDefaultState());

                // Dragon breath particles on the wave front
                world.spawnParticles(net.minecraft.particle.ParticleTypes.DRAGON_BREATH,
                    bp.getX() + 0.5, bp.getY() + 0.8, bp.getZ() + 0.5,
                    5, 0.3, 0.4, 0.3, 0.03);
                world.spawnParticles(net.minecraft.particle.ParticleTypes.PORTAL,
                    bp.getX() + 0.5, bp.getY() + 0.5, bp.getZ() + 0.5,
                    3, 0.2, 0.3, 0.2, 0.05);
            }

            // Damage EVERY party member standing on a burned tile, not just the host.
            // Previously the wave only checked arena.getPlayerGridPos() so teammates
            // walked through the fire wall unharmed. Each victim is routed via the
            // this.player swap for correct per-victim dodge/armor/effects/death.
            java.util.Set<GridPos> burnedSet = new java.util.HashSet<>(burned);
            java.util.List<ServerPlayerEntity> waveVictims = new java.util.ArrayList<>();
            if (partyPlayers.size() > 1) {
                for (ServerPlayerEntity member : partyPlayers) {
                    if (member == null || member.isRemoved() || member.isDisconnected()) continue;
                    if (deadPartyMembers.contains(member.getUuid())) continue;
                    if (burnedSet.contains(gridPosOf(member))) waveVictims.add(member);
                }
            } else if (burnedSet.contains(arena.getPlayerGridPos())) {
                waveVictims.add(player);
            }
            int waveDmg = e.getAttackPower() + (dragonAi.isDragonPhaseTwo() ? 3 : 0);
            boolean gameOverFromWave = false;
            for (ServerPlayerEntity victim : waveVictims) {
                ServerPlayerEntity savedWavePlayer = this.player;
                boolean waveSwapped = victim != savedWavePlayer;
                if (waveSwapped) { this.player = victim; retargetEffectsToCurrentPlayer(); }
                boolean victimDied = false;
                try {
                    int actual = damagePlayer(waveDmg);
                    sendMessage("§5§l⌇ Dragon breath wave hits "
                        + (waveSwapped ? victim.getName().getString() : "you") + " for " + actual + " damage!");
                    world.spawnParticles(net.minecraft.particle.ParticleTypes.DAMAGE_INDICATOR,
                        victim.getX(), victim.getY() + 1.0, victim.getZ(),
                        5, 0.3, 0.3, 0.3, 0.01);
                    if (getPlayerHp() <= 0) {
                        victimDied = true;
                        handlePlayerDeathOrGameOver();
                        gameOverFromWave = (partyPlayers.size() <= 1 || !active);
                    }
                } finally {
                    if (!victimDied) { this.player = savedWavePlayer; retargetEffectsToCurrentPlayer(); }
                }
                if (gameOverFromWave) { sendSync(); return; }
            }
            if (!waveVictims.isEmpty()) sendSync();

            // Sound effect for the advancing wave
            world.playSound(null, player.getBlockPos(),
                net.minecraft.sound.SoundEvents.ENTITY_ENDER_DRAGON_GROWL,
                net.minecraft.sound.SoundCategory.HOSTILE, 0.5f, 1.5f);
        }
    }

    private void primePendingTnt(GridPos tile, String message) {
        primePendingTnt(tile, message, 1);
    }

    /**
     * @param fuseRounds rounds until detonation. 1 = explodes at the next round
     *                   transition (player TNT -they placed it knowing it'd
     *                   blow up "next round"). 2+ = gives the target at least
     *                   one full turn with the physical TNT block visible
     *                   before it detonates (boss TNT -otherwise the warning
     *                   resolves and the round transition fires the explosion
     *                   in the same beat, leaving the player no chance to
     *                   react to the actual block).
     */
    private void primePendingTnt(GridPos tile, String message, int fuseRounds) {
        if (!arena.isInBounds(tile)) return;

        for (PendingTnt existing : pendingTnts) {
            if (existing.tile().equals(tile)) return;
        }

        BlockPos tntBp = arena.gridToBlockPos(tile);
        ServerWorld world = (ServerWorld) player.getEntityWorld();
        world.setBlockState(tntBp, Blocks.TNT.getDefaultState());
        world.spawnParticles(net.minecraft.particle.ParticleTypes.SMOKE,
            tntBp.getX() + 0.5, tntBp.getY() + 0.8, tntBp.getZ() + 0.5,
            8, 0.2, 0.3, 0.2, 0.01);
        highlightWarningTile(tile);
        pendingTnts.add(new PendingTnt(tile, tntBp, Math.max(1, fuseRounds)));
        if (message != null && !message.isEmpty()) {
            sendMessage(message);
        }
    }

    /**
     * Register a light zone at the given position with specified radius.
     * Light zones negate darkness effects for the player standing within them.
     */
    private void registerLightZone(GridPos pos, int radius) {
        if (arena.isInBounds(pos)) {
            litZones.put(pos, radius);
        }
    }

    /**
     * Spawn a falling-block anvil visual above the target enemy, queue the
     * actual damage to apply when it lands (~12 ticks). The block is
     * non-damaging on impact -Craftics' base damage applies instead.
     *
     * Vanilla FallingBlockEntity converts itself into a REAL anvil block the
     * tick it lands (well before our discard countdown), so we record the
     * landing floor position up front: tickPendingAnvils clears it on resolve,
     * and endCombat's placed-block restore guarantees it never survives the
     * level even if the timing slips. Otherwise a left-behind anvil sits at
     * floor+1 and gets re-read as a permanent OBSTACLE on the next visit.
     */
    private void spawnAnvilDrop(int targetEntityId, int damage) {
        CombatEntity victim = null;
        for (CombatEntity e : enemies) {
            if (e.getEntityId() == targetEntityId) { victim = e; break; }
        }
        if (victim == null || !victim.isAlive()) return;
        ServerWorld world = (ServerWorld) player.getEntityWorld();
        // The falling anvil settles on the floor the VICTIM stands on. On sunken
        // tiles (water, deep water, lava, low ground, powder snow) the victim -and
        // thus the floor the anvil lands on- sits one block below the flat overlay
        // Y that gridToBlockPos returns. Using gridToBlockPos here made the anvil
        // land lower than the recorded/cleanup position, so on those tiles the real
        // anvil block was never cleared and got re-read as a permanent obstacle.
        // Anchor the landing to the victim's actual standing Y instead.
        BlockPos overlayBp = arena.gridToBlockPos(victim.getGridPos());
        int landY = (int) Math.floor(arena.getEntityY(victim.getGridPos()));
        BlockPos targetBp = new BlockPos(overlayBp.getX(), landY, overlayBp.getZ());
        recordPlacedBlock(targetBp);
        double cx = targetBp.getX() + 0.5;
        double cz = targetBp.getZ() + 0.5;
        // Spawn 6 blocks above the landing floor so the fall is visible but quick.
        double spawnY = targetBp.getY() + 6.0;

        //? if <=1.21.1 {
        net.minecraft.entity.FallingBlockEntity fbe =
            net.minecraft.entity.EntityType.FALLING_BLOCK.create(world);
        //?} else {
        /*net.minecraft.entity.FallingBlockEntity fbe =
            net.minecraft.entity.EntityType.FALLING_BLOCK.create(world, net.minecraft.entity.SpawnReason.TRIGGERED);
        *///?}
        if (fbe == null) return;
        net.minecraft.nbt.NbtCompound nbt = new net.minecraft.nbt.NbtCompound();
        fbe.writeNbt(nbt);
        nbt.put("BlockState",
            net.minecraft.nbt.NbtHelper.fromBlockState(Blocks.ANVIL.getDefaultState()));
        nbt.putBoolean("DropItem", false);
        nbt.putBoolean("HurtEntities", false);
        nbt.putInt("Time", 1);
        fbe.readNbt(nbt);
        fbe.setPosition(cx, spawnY, cz);
        fbe.setVelocity(0, -0.4, 0);
        fbe.timeFalling = 1;
        world.spawnEntity(fbe);

        pendingAnvils.add(new PendingAnvil(targetEntityId, damage, fbe.getUuid(), 14, targetBp.toImmutable()));

        world.playSound(null, targetBp,
            net.minecraft.sound.SoundEvents.BLOCK_ANVIL_FALL,
            net.minecraft.sound.SoundCategory.PLAYERS, 1.0f, 0.85f);
    }

    /**
     * Tick pending anvil drops once per combat tick. When the countdown hits
     * 0, discard the visual entity, apply the queued Special damage, and run
     * the death check. Mirrors the pendingTnts tick pattern.
     */
    private void tickPendingAnvils() {
        if (pendingAnvils.isEmpty()) return;
        ServerWorld world = (ServerWorld) player.getEntityWorld();
        java.util.Iterator<PendingAnvil> it = pendingAnvils.iterator();
        while (it.hasNext()) {
            PendingAnvil pa = it.next();
            int next = pa.ticksLeft() - 1;
            if (next > 0) {
                // Replace with a decremented copy (record is immutable).
                int idx = pendingAnvils.indexOf(pa);
                pendingAnvils.set(idx, new PendingAnvil(pa.targetEntityId(), pa.damage(), pa.fbeUuid(), next,
                    pa.landingPos()));
                // Iterator is now stale -we set in place so continue.
                continue;
            }
            it.remove();
            // Discard the visual falling block, and clear the real anvil block if
            // vanilla already converted it on landing (it lands in ~5-7 ticks, well
            // before this 14-tick countdown). Restore the floor we recorded at spawn
            // so the stage shows the anvil fall, then nothing left behind.
            net.minecraft.entity.Entity fbe = world.getEntity(pa.fbeUuid());
            if (fbe != null) fbe.discard();
            // Clear the real anvil block vanilla left when the falling block landed.
            // The exact rest Y can vary by a block depending on what was solid in the
            // column (liquids/offset-Y tiles settle the anvil lower), so scan a small
            // vertical band around the recorded landing position rather than a single
            // cell, restoring whatever was there before (or air).
            if (pa.landingPos() != null) {
                for (int dy = 1; dy >= -2; dy--) {
                    BlockPos check = pa.landingPos().up(dy);
                    if (world.getBlockState(check).isOf(Blocks.ANVIL)) {
                        net.minecraft.block.BlockState original = placedBlockRestores.get(check);
                        world.setBlockState(check,
                            original != null ? original : Blocks.AIR.getDefaultState());
                        break;
                    }
                }
            }

            CombatEntity victim = null;
            for (CombatEntity e : enemies) {
                if (e.getEntityId() == pa.targetEntityId()) { victim = e; break; }
            }
            if (victim == null || !victim.isAlive()) continue;
            // Special, like every other utility item, and like this method's own message has
            // always claimed. It used to call takeDamage directly, which meant an anvil got no
            // Special affinity bonus and ignored mob resistances while telling the player it had
            // dealt "Special damage".
            int dealt = applySpecialUtilityDamage(victim, pa.damage());
            BlockPos vbp = arena.gridToBlockPos(victim.getGridPos());
            world.playSound(null, vbp,
                net.minecraft.sound.SoundEvents.BLOCK_ANVIL_LAND,
                net.minecraft.sound.SoundCategory.PLAYERS, 1.0f, 1.0f);
            world.spawnParticles(new net.minecraft.particle.BlockStateParticleEffect(
                    net.minecraft.particle.ParticleTypes.BLOCK,
                    Blocks.ANVIL.getDefaultState()),
                vbp.getX() + 0.5, vbp.getY() + 0.3, vbp.getZ() + 0.5,
                14, 0.4, 0.1, 0.4, 0.05);
            sendMessage("§8Anvil crushes " + victim.getDisplayName()
                + " for " + dealt + " Special damage!");
            checkAndHandleDeath(victim);
            sendSync();
            refreshHighlights();
        }
        // checkAndHandleDeath never ends the fight on its own, so a deferred anvil
        // landing the final blow would soft-lock the level. Re-run the same
        // win-condition check every other damage path uses (see handleAttack /
        // tryHandleInstrument) once all anvils this tick have resolved.
        if (phase != CombatPhase.GAME_OVER && phase != CombatPhase.LEVEL_COMPLETE
                && enemies.stream().noneMatch(e -> e.isAlive() && !e.isAlly())) {
            handleVictory();
        }
    }

    /**
     * Drop a real block in the world for a placed utility-item tile effect, and
     * mark the tile as OBSTACLE when the block is a full cube so pathing
     * respects the wall. Non-full-cube blocks (campfire, scaffolding, spore
     * blossom, bell) leave the tile walkable.
     */
    private void placeUtilityBlock(String effectType, GridPos effectPos) {
        if (effectPos == null || !arena.isInBounds(effectPos)) return;
        net.minecraft.block.Block block;
        boolean obstacle;
        boolean atFloorLevel; // honey/slime sit IN the floor (trap), not on top of it
        switch (effectType) {
            case "campfire"      -> { block = Blocks.CAMPFIRE;      obstacle = false; atFloorLevel = false; }
            case "scaffold"      -> { block = Blocks.SCAFFOLDING;   obstacle = false; atFloorLevel = false; }
            case "spore_blossom" -> { block = Blocks.SPORE_BLOSSOM; obstacle = false; atFloorLevel = false; }
            case "bell"          -> { block = Blocks.BELL;          obstacle = false; atFloorLevel = false; }
            case "jukebox"       -> { block = Blocks.JUKEBOX;       obstacle = true;  atFloorLevel = false; }
            case "sponge"        -> { block = Blocks.SPONGE;        obstacle = true;  atFloorLevel = false; }
            // Honey + slime are TRAPS, not walls -they replace the floor block
            // so the enemy walks ONTO them and triggers the effect. Tile stays
            // walkable so pathing AI doesn't route around them.
            case "honey"         -> { block = Blocks.HONEY_BLOCK;   obstacle = false; atFloorLevel = true;  }
            case "slime"         -> { block = Blocks.SLIME_BLOCK;   obstacle = false; atFloorLevel = true;  }
            // Powder snow keeps the existing TileType.POWDER_SNOW behavior
            // (mobs sink into it / freeze) rather than becoming an OBSTACLE.
            // The tile type is set by the caller's setType branch. It sits at floor
            // level (replacing the floor block) like honey/slime -placing it in the
            // Y+1 overlay space left the snow floating one block above the ground.
            case "powder_snow"   -> { block = Blocks.POWDER_SNOW;   obstacle = false; atFloorLevel = true; }
            default -> { return; } // not a utility-block effect
        }
        BlockPos bp = arena.gridToBlockPos(effectPos);
        if (atFloorLevel) bp = bp.down();
        ServerWorld world = (ServerWorld) player.getEntityWorld();
        recordPlacedBlock(bp);
        world.setBlockState(bp, block.getDefaultState(),
            net.minecraft.block.Block.NOTIFY_LISTENERS | net.minecraft.block.Block.FORCE_STATE);
        GridTile tile = arena.getTile(effectPos);
        if (tile != null) {
            if (obstacle) {
                tile.setType(TileType.OBSTACLE);
                tile.setBlockType(block);
            } else if (!atFloorLevel) {
                // Don't overwrite the floor block type for floor-level traps
                // (honey/slime) -we need the original block ID preserved so
                // the trap can restore the floor on consumption.
                tile.setBlockType(block);
            }
        }
    }

    /**
     * Unregister a light zone at the given position.
     */
    private void unregisterLightZone(GridPos pos) {
        litZones.remove(pos);
    }

    /**
     * Check if a given position is within a lit zone (torch/lantern radius).
     * Returns true if the position is within the radius of any light source.
     */
    private boolean isPositionLit(GridPos pos) {
        if (pos == null) return false;
        for (java.util.Map.Entry<GridPos, Integer> light : litZones.entrySet()) {
            GridPos lightPos = light.getKey();
            int radius = light.getValue();
            int dist = Math.max(Math.abs(pos.x() - lightPos.x()), Math.abs(pos.z() - lightPos.z()));
            if (dist <= radius) {
                return true;
            }
        }
        return false;
    }

    /**
     * Detonate all pending TNT blocks. Called at the start of each new round.
     * Deals AoE damage (8/5/3 by manhattan distance), damages the player too if close,
     * removes the TNT block, and spawns a big explosion effect.
     */
    private void detonatePendingTnts() {
        if (pendingTnts.isEmpty()) return;
        ServerWorld world = (ServerWorld) player.getEntityWorld();

        // Decrement fuses; only blow up the ones that hit 0 this tick. TNT
        // placed with fuseRounds=2 (boss demolition cache) just had its block
        // appear last round transition; the player needs this round to see
        // the physical TNT and step away before it detonates.
        List<PendingTnt> exploding = new ArrayList<>();
        for (var it = pendingTnts.iterator(); it.hasNext(); ) {
            PendingTnt t = it.next();
            t.fuseRounds--;
            if (t.fuseRounds <= 0) {
                exploding.add(t);
                it.remove();
            }
        }
        if (exploding.isEmpty()) return;

        for (PendingTnt tnt : exploding) {
            GridPos center = tnt.tile();
            BlockPos bp = tnt.blockPos();
            BlockPos floorBp = bp.down();

            // Remove the TNT block -replace with the arena floor
            GridTile floorTile = arena.getTile(center);
            world.setBlockState(bp, Blocks.AIR.getDefaultState());
            if (floorTile != null) {
                world.setBlockState(floorBp, floorTile.getBlockType().getDefaultState());
            }

            // --- Explosion particles ---
            world.spawnParticles(net.minecraft.particle.ParticleTypes.EXPLOSION_EMITTER,
                bp.getX() + 0.5, bp.getY() + 1.0, bp.getZ() + 0.5,
                1, 0.0, 0.0, 0.0, 0.0);
            world.spawnParticles(net.minecraft.particle.ParticleTypes.EXPLOSION,
                bp.getX() + 0.5, bp.getY() + 1.0, bp.getZ() + 0.5,
                5, 1.0, 0.8, 1.0, 0.0);
            world.spawnParticles(net.minecraft.particle.ParticleTypes.FLAME,
                bp.getX() + 0.5, bp.getY() + 1.0, bp.getZ() + 0.5,
                25, 1.5, 1.0, 1.5, 0.05);
            world.spawnParticles(net.minecraft.particle.ParticleTypes.LAVA,
                bp.getX() + 0.5, bp.getY() + 0.5, bp.getZ() + 0.5,
                12, 1.0, 0.5, 1.0, 0.0);
            world.spawnParticles(net.minecraft.particle.ParticleTypes.LARGE_SMOKE,
                bp.getX() + 0.5, bp.getY() + 1.5, bp.getZ() + 0.5,
                15, 1.2, 1.0, 1.2, 0.03);
            world.spawnParticles(net.minecraft.particle.ParticleTypes.CAMPFIRE_COSY_SMOKE,
                bp.getX() + 0.5, bp.getY() + 2.0, bp.getZ() + 0.5,
                8, 0.8, 0.5, 0.8, 0.01);

            // Explosion sound
            world.playSound(null, bp,
                net.minecraft.sound.SoundEvents.ENTITY_GENERIC_EXPLODE.value(),
                net.minecraft.sound.SoundCategory.BLOCKS, 1.5f, 0.9f);

            sendMessage("§c§lBOOM! §r§7TNT detonates!");

            // --- AoE damage to enemies ---
            int totalDamage = 0;
            int enemiesHit = 0;
            int killCount = 0;
            for (CombatEntity enemy : new ArrayList<>(enemies)) {
                if (!enemy.isAlive()) continue;
                int dist = Math.abs(enemy.getGridPos().x() - center.x())
                         + Math.abs(enemy.getGridPos().z() - center.z());
                if (dist <= 2) {
                    // Flat blast damage plus a percent of max HP by ring (center/adjacent/outer)
                    // so TNT stays lethal against late-game HP pools. Bosses take 1/3 (8/5/3%).
                    double hpPct = dist == 0 ? 0.24 : (dist == 1 ? 0.15 : 0.09);
                    int dmg = (dist == 0 ? 8 : (dist == 1 ? 5 : 3)) + enemy.percentMaxHpDamage(hpPct);
                    int dealt = applySpecialUtilityDamage(enemy, dmg);
                    totalDamage += dealt;
                    enemiesHit++;
                    if (!enemy.isAlive()) {
                        killCount++;
                        checkAndHandleDeath(enemy);
                    }
                }
            }

            // Track TNT kills for achievement
            if (killCount > 0) {
                achievementTracker.recordTntKills(killCount);
            }

            // Self-damage if player is close. Route through damagePlayer so
            // the Craftics combat HP actually drops (and party-aware death
            // detection fires) -the old player.setHealth(max(1, ...)) only
            // touched vanilla health, clamped at 1, and left combat HP
            // untouched. Result: a "fatal" blast that never killed the
            // player's combat state, but later damage processed the queued
            // death only after a turn skip -the softlock the user hit.
            // Self-damage every party member in the 2-tile blast radius, not just
            // the host. With per-victim distance tiers (6/4/2) and the this.player
            // swap so each member's own dodge/armor/effects/death handling applies.
            java.util.List<ServerPlayerEntity> tntVictims = new java.util.ArrayList<>();
            if (partyPlayers.size() > 1) {
                for (ServerPlayerEntity member : partyPlayers) {
                    if (member == null || member.isRemoved() || member.isDisconnected()) continue;
                    if (deadPartyMembers.contains(member.getUuid())) continue;
                    if (center.manhattanDistance(gridPosOf(member)) <= 2) tntVictims.add(member);
                }
            } else {
                GridPos playerPos = arena.getPlayerGridPos();
                if (center.manhattanDistance(playerPos) <= 2) tntVictims.add(player);
            }
            boolean tntHitAnyone = false;
            boolean gameOverFromTnt = false;
            for (ServerPlayerEntity victim : tntVictims) {
                tntHitAnyone = true;
                ServerPlayerEntity savedTntPlayer = this.player;
                boolean tntSwapped = victim != savedTntPlayer;
                if (tntSwapped) { this.player = victim; retargetEffectsToCurrentPlayer(); }
                boolean victimDied = false;
                try {
                    int victimDist = center.manhattanDistance(gridPosOf(victim));
                    int selfDmgRaw = victimDist == 0 ? 6 : (victimDist == 1 ? 4 : 2);
                    int selfDmg = damagePlayer(selfDmgRaw);
                    sendMessage("§c  Blast hit " + enemiesHit + " enemies for " + totalDamage + " total! "
                        + (tntSwapped ? victim.getName().getString() : "You") + " took " + selfDmg + " blast damage!");
                    if (getPlayerHp() <= 0) {
                        victimDied = true;
                        handlePlayerDeathOrGameOver();
                        gameOverFromTnt = (partyPlayers.size() <= 1 || !active);
                    }
                } finally {
                    if (!victimDied) { this.player = savedTntPlayer; retargetEffectsToCurrentPlayer(); }
                }
                if (gameOverFromTnt) { sendSync(); return; }
            }
            if (!tntHitAnyone && enemiesHit > 0) {
                sendMessage("§7  Hit " + enemiesHit + " enemies for " + totalDamage + " total damage!");
            }
        }
        // A deferred TNT landing the final blow would soft-lock the level:
        // checkAndHandleDeath despawns the enemy but never ends the fight. Re-run
        // the win check every other damage path uses, once all TNT this tick has
        // resolved and only if the blast didn't already trigger a player game-over.
        if (phase != CombatPhase.GAME_OVER && phase != CombatPhase.LEVEL_COMPLETE
                && enemies.stream().noneMatch(e -> e.isAlive() && !e.isAlly())) {
            handleVictory();
            return;
        }
        sendSync();
    }

    // ===== Boss Callback Hooks =====

    /**
     * Called when the player deals damage to a boss enemy.
     * Dispatches to boss-specific reaction callbacks.
     */
    private void notifyBossOfDamage(CombatEntity target, int damageDealt) {
        if (!target.isBoss()) return;
        EnemyAI ai = resolveAi(target);

        // ShulkerArchitect: notify it was damaged (primes Fortify Shell)
        if (ai instanceof ShulkerArchitectAI sa) {
            sa.notifyDamaged();
        }

        // Rockbreaker P2: notify it was damaged (primes the retaliatory slam)
        if (ai instanceof com.crackedgames.craftics.combat.ai.boss.RockbreakerAI rb) {
            rb.notifyDamaged();
        }

        // MoltenKing: at 50% HP, the original boss dies and cleanly splits into 2
        // smaller copies (size 2) that each act as independent bosses. Gen 1 does
        // NOT split further -this fires only for Gen 0.
        if (ai instanceof MoltenKingAI mk && mk.canSplit()
                && !target.hasSplit() && target.isAlive()
                && target.getCurrentHp() <= target.getMaxHp() / 2) {
            target.markSplit();
            String nextGenKey = mk.getNextGenAiKey();
            if (nextGenKey != null) {
                int splitSize = 2; // gen 1 = 2x2 footprint
                int splitHp = Math.max(5, target.getMaxHp() / 2);
                int splitAtk = Math.max(1, target.getAttackPower() - 1);
                int splitDef = Math.max(0, target.getDefense() - 1);

                // The parent occupies a 4x4 area starting at its gridPos. We pick up
                // to 2 non-overlapping 2x2 sub-quadrants of that area to place the
                // split copies -this guarantees they fit inside the footprint the
                // parent just vacated.
                GridPos origin = target.getGridPos();
                int parentSize = target.getMaxSize(); // Molten King is square (4x4 gen 0)
                List<GridPos> quadrantOrigins = new ArrayList<>();
                for (int dx = 0; dx + splitSize <= parentSize; dx += splitSize) {
                    for (int dz = 0; dz + splitSize <= parentSize; dz += splitSize) {
                        quadrantOrigins.add(new GridPos(origin.x() + dx, origin.z() + dz));
                    }
                }
                java.util.Collections.shuffle(quadrantOrigins);

                // Kill the parent FIRST so the sub-quadrants become unoccupied before
                // the split copies are placed. This also prevents the parent's mob
                // entity from lingering as a "ghost" alongside the new copies.
                target.takeDamage(target.getCurrentHp() + 100);
                checkAndHandleDeath(target);

                // Filter to quadrants whose every tile is now walkable and free.
                List<GridPos> splitPositions = new ArrayList<>();
                for (GridPos q : quadrantOrigins) {
                    if (splitPositions.size() >= 2) break;
                    boolean ok = true;
                    for (int dx = 0; dx < splitSize && ok; dx++) {
                        for (int dz = 0; dz < splitSize && ok; dz++) {
                            GridPos tile = new GridPos(q.x() + dx, q.z() + dz);
                            if (!arena.isInBounds(tile) || arena.isOccupied(tile)) { ok = false; break; }
                            GridTile gt = arena.getTile(tile);
                            if (gt == null || !gt.isWalkable()) { ok = false; break; }
                        }
                    }
                    if (ok) splitPositions.add(q);
                }

                if (!splitPositions.isEmpty()) {
                    pendingMoltenSplitKey = nextGenKey;
                    pendingMoltenSplitSize = splitSize;
                    EnemyAction split = new EnemyAction.SummonMinions(
                        "minecraft:magma_cube", splitPositions.size(), splitPositions,
                        splitHp, splitAtk, splitDef);
                    dispatchBossSubAction(split);
                }
            }
        }
    }

    /**
     * Called when the player finishes moving.
     * Notifies Warden boss of player movement for vibration sense.
     */
    private void notifyBossesPlayerMoved(GridPos destination, int tilesMoved) {
        for (CombatEntity e : enemies) {
            if (!e.isAlive() || !e.isBoss()) continue;
            EnemyAI ai = resolveAi(e);
            if (ai instanceof WardenAI warden) {
                warden.onPlayerMove(destination, tilesMoved);
            }
        }
    }

    /**
     * Called at the end of the player's turn.
     * Ticks pending boss warnings (telegraphed attacks).
     */
    private void tickBossWarnings() {
        for (CombatEntity e : enemies) {
            if (!e.isAlive() || !e.isBoss()) continue;
            EnemyAI ai = resolveAi(e);
            if (ai instanceof BossAI boss) {
                boss.tickWarning();
            }
        }
        // Also tick Void Walker rift lifetimes.
        tickVoidRifts();
        // Tick Sandstorm Pharaoh sand-mine lifetimes (arm fresh mines, expire old ones).
        tickSandMines();
        // Tick down the Curse of the Sands.
        if (curseOfSandsTurns > 0) {
            curseOfSandsTurns--;
            if (curseOfSandsTurns == 0) {
                sendMessage("§7The curse of the sands lifts.");
            }
        }
    }

    /**
     * Take {@code enemy} off the grid and out of reach: no attack, AoE, splash, or chain can
     * touch it until {@link #surfaceEnemy} puts it back.
     *
     * <p>Every exit from this state MUST go through surfaceEnemy. The untargetable flag and the
     * missing occupancy tiles are the same fact stored twice, and a boss that keeps the flag is
     * unkillable, so the two calls are a matched pair.
     */
    private void burrowEnemy(CombatEntity enemy) {
        arena.removeEntity(enemy);
        enemy.setUntargetable(true);

        MobEntity mob = enemy.getMobEntity();
        if (mob != null) mob.setInvisible(true);

        if (player != null && player.getEntityWorld() instanceof ServerWorld sw) {
            BlockPos bp = arena.gridToBlockPos(enemy.getGridPos());
            sw.spawnParticles(net.minecraft.particle.ParticleTypes.CAMPFIRE_COSY_SMOKE,
                bp.getX() + 1.0, bp.getY() + 0.2, bp.getZ() + 1.0, 30, 0.8, 0.1, 0.8, 0.02);
            sw.playSound(null, bp, net.minecraft.sound.SoundEvents.BLOCK_ROOTED_DIRT_BREAK,
                net.minecraft.sound.SoundCategory.HOSTILE, 1.4f, 0.5f);
        }
        sendSync();
    }

    /**
     * Put a burrowed {@code enemy} back on the grid at {@code anchor} and make it targetable
     * again. This ALWAYS surfaces: a null or refused anchor falls back to the tile it went under
     * at, and even a refused re-placement still clears the flag. Leaving the boss untargetable
     * because no tile was free would make the fight unwinnable, which is strictly worse than a
     * boss standing on an awkward tile.
     */
    private void surfaceEnemy(CombatEntity enemy, GridPos anchor, String message) {
        GridPos target = anchor != null ? anchor : enemy.getGridPos();
        if (!com.crackedgames.craftics.combat.ai.AIUtils
                .canPlaceFootprintIgnoringSelf(arena, target, enemy)) {
            target = enemy.getGridPos();
        }
        enemy.setGridPos(target);
        // Placement can still be refused (its old tiles may be taken while it was under). The
        // boss surfaces regardless: an entity with no occupancy tile is far less broken than one
        // that is permanently untargetable, and the flag below is what actually gates damage.
        arena.placeEntity(enemy);
        enemy.setUntargetable(false);

        EnemyAI surfaceAi = resolveAi(enemy);
        if (surfaceAi instanceof RevenantAI revenant) revenant.clearBurrowState();

        MobEntity mob = enemy.getMobEntity();
        if (mob != null) {
            mob.setInvisible(false);
            BlockPos bp = arena.gridToBlockPos(target);
            mob.requestTeleport(bp.getX() + 0.5, arena.getEntityY(target), bp.getZ() + 0.5);
        }

        if (message != null) sendMessage(message);
        if (player != null && player.getEntityWorld() instanceof ServerWorld sw) {
            BlockPos bp = arena.gridToBlockPos(target);
            sw.spawnParticles(net.minecraft.particle.ParticleTypes.EXPLOSION,
                bp.getX() + 1.0, bp.getY() + 0.5, bp.getZ() + 1.0, 6, 0.6, 0.2, 0.6, 0.0);
            sw.playSound(null, bp, net.minecraft.sound.SoundEvents.ENTITY_ZOMBIE_INFECT,
                net.minecraft.sound.SoundCategory.HOSTILE, 1.5f, 0.6f);
        }
        sendSync();
    }

    /**
     * Called when a minion/entity in a boss fight dies.
     * Dispatches boss-specific callbacks for minion death.
     */
    private void notifyBossOfMinionDeath(CombatEntity deadEntity) {
        for (CombatEntity e : enemies) {
            if (!e.isAlive() || !e.isBoss()) continue;
            EnemyAI ai = resolveAi(e);

            // ShulkerArchitect: turret destroyed
            if (ai instanceof ShulkerArchitectAI sa) {
                if (deadEntity.getGridPos() != null) {
                    sa.removeTurret(deadEntity.getGridPos());
                }
            }

            // Broodmother: notify the AI that an egg sac was lost so its
            // spawn-cap bookkeeping stays accurate. The actual block + particle
            // cleanup happens unconditionally in checkAndHandleDeath so it
            // still runs if the broodmother died first.
            if (ai instanceof BroodmotherAI bm
                    && "craftics:egg_sac".equals(deadEntity.getEntityTypeId())) {
                bm.onEggSacDestroyed(deadEntity.getGridPos());
                sendMessage("§a✦ Egg sac destroyed! Spawn capacity reduced.");
            }

            // Bastion Brute: the three banners are asymmetric, so the AI reports which one fell
            // and the message names it. Filtered on the type id because this loop sees every
            // death at a tracked tile, not just banners.
            if (ai instanceof BastionBruteAI brute
                    && "craftics:war_banner".equals(deadEntity.getEntityTypeId())) {
                String bannerMessage = brute.onWarBannerDestroyed(deadEntity.getGridPos(), e);
                if (bannerMessage != null) sendMessage(bannerMessage);
            }

            // Revenant: a lost grave narrows the zombie cap permanently. Filtered on the type id
            // because this loop sees every death at a tracked tile, not just graves. The block
            // cleanup itself runs in checkAndHandleDeath so it still happens if the boss died first.
            if (ai instanceof RevenantAI revenant
                    && "craftics:grave".equals(deadEntity.getEntityTypeId())) {
                revenant.onGraveDestroyed(deadEntity.getGridPos());
                sendMessage("§a✦ Grave destroyed! The dead stay down.");

                // Last grave broken while it was under: the escape network is gone, so the
                // retreat fails and it claws out where it dug in. Spending the untouchable turn
                // on the network instead of waiting is the strongest play, and this is the payoff.
                if (revenant.getGraveCount() == 0 && revenant.isBurrowed()) {
                    GridPos forced = revenant.forceSurfaceOnLastGraveLost(e, arena);
                    surfaceEnemy(e, forced, "§6§l✦ The last grave collapses! §e"
                        + e.getDisplayName() + " is dragged back into the light!");
                }
            }
        }
    }

    /**
     * Called after a boss entity is spawned and placed on the arena.
     * Initializes boss-specific fight setup.
     */
    /**
     * The on-screen "it just got worse" beat when a boss crosses into phase two:
     * combat-log line, a subtitle for every party member, a roar, a particle
     * burst on the boss, and a client-side shake/flash via EVENT_BOSS_MOMENT.
     * Server-driven so all co-op clients see the same moment.
     */
    private void announceBossPhaseTwo(CombatEntity boss) {
        sendMessage("§4§l" + boss.getDisplayName() + " enters Phase 2!");

        for (ServerPlayerEntity member : getAllParticipants()) {
            if (member == null || member.isRemoved() || member.isDisconnected()
                    || member.networkHandler == null) continue;
            member.networkHandler.sendPacket(
                new net.minecraft.network.packet.s2c.play.TitleFadeS2CPacket(5, 35, 15));
            member.networkHandler.sendPacket(
                new net.minecraft.network.packet.s2c.play.SubtitleS2CPacket(
                    Text.literal("§4§l" + boss.getDisplayName() + " Phase 2")));
            // Empty title so the subtitle shows even when no title is queued.
            member.networkHandler.sendPacket(
                new net.minecraft.network.packet.s2c.play.TitleS2CPacket(Text.literal("")));
        }

        MobEntity bossMob = boss.getMobEntity();
        if (player != null && player.getEntityWorld() instanceof ServerWorld sw) {
            double bx, by, bz;
            if (bossMob != null) {
                bx = bossMob.getX(); by = bossMob.getY() + 1.0; bz = bossMob.getZ();
            } else {
                BlockPos bp = arena.gridToBlockPos(boss.getGridPos());
                bx = bp.getX() + 0.5; by = bp.getY() + 1.0; bz = bp.getZ() + 0.5;
            }
            sw.spawnParticles(net.minecraft.particle.ParticleTypes.ANGRY_VILLAGER,
                bx, by + 0.5, bz, 12, 0.6, 0.8, 0.6, 0.0);
            sw.spawnParticles(net.minecraft.particle.ParticleTypes.LARGE_SMOKE,
                bx, by, bz, 20, 0.5, 0.7, 0.5, 0.04);
            sw.spawnParticles(net.minecraft.particle.ParticleTypes.FLASH,
                bx, by, bz, 1, 0, 0, 0, 0);
        }
        // ROAR pose: head back, arms wide, plus the ring burst + roar sound
        // that MobAnimations owns for this state.
        if (bossMob != null) {
            com.crackedgames.craftics.combat.animation.MobAnimations.set(bossMob,
                com.crackedgames.craftics.combat.animation.AnimState.ROAR);
        }
        // The arena itself flinches: dragon growl, a shockwave rolling out from
        // the boss that bounces its own minions, blood flash, ENRAGED overhead.
        if (player != null && player.getEntityWorld() instanceof ServerWorld phaseWorld) {
            com.crackedgames.craftics.vfx.boss.BossAttackVfx.phaseTransition(phaseWorld, arena, boss);
        }

        sendToAllParty(new CombatEventPayload(
            CombatEventPayload.EVENT_BOSS_MOMENT, boss.getEntityId(),
            CombatEventPayload.BOSS_MOMENT_PHASE_TWO, 0,
            boss.getGridPos().x(), boss.getGridPos().z()
        ));
    }

    private void initBossSetup(CombatEntity bossEntity) {
        EnemyAI ai = resolveAi(bossEntity);

        if (ai instanceof BroodmotherAI broodmother) {
            List<GridPos> sacPositions = broodmother.initEggSacs(arena);
            ServerWorld world = (ServerWorld) player.getEntityWorld();
            for (GridPos pos : sacPositions) {
                placeEggSacEntity(broodmother, pos, world);
            }
        }

        // Bastion Brute: war banners feed its speed, which feeds Momentum. Only banners the
        // grid actually accepted are registered, or the AI would grant speed for a banner the
        // player has no tile to attack.
        if (ai instanceof BastionBruteAI brute) {
            ServerWorld world = (ServerWorld) player.getEntityWorld();
            for (BastionBruteAI.BannerPlacement bp : brute.initWarBanners(arena)) {
                CombatEntity banner = placeBlockObject("craftics:war_banner", bp.pos(),
                    WAR_BANNER_HP, -(warBannerIdCounter++), warBannerBlock(bp.typeName()), world);
                if (banner != null) brute.registerWarBanner(bp);
            }
        }

        // Revenant: graves are the source of every zombie it raises. Only graves the grid actually
        // accepted are registered, or the AI would raise off a tile the player cannot attack.
        if (ai instanceof RevenantAI revenant) {
            ServerWorld world = (ServerWorld) player.getEntityWorld();
            for (GridPos pos : revenant.initGraves(arena)) {
                CombatEntity grave = placeBlockObject("craftics:grave", pos,
                    GRAVE_HP, -(graveIdCounter++), Blocks.COBBLESTONE_WALL, world);
                if (grave != null) revenant.registerGrave(pos);
            }
        }

        // Ender Dragon: backgroundBoss parked above the arena (same pattern as ghast).
        // The mob entity sits 100 blocks above the arena centre; the PhaseManager is
        // forced to HOVER so it never fights our per-tick position enforcement.
        // The dragon occupies a 3×7 cluster of centre tiles for targeting.
        if (ai instanceof com.crackedgames.craftics.combat.ai.DragonAI) {
            int arenaW = arena.getWidth();
            int arenaH = arena.getHeight();

            arena.removeEntity(bossEntity);
            bossEntity.setBackgroundBoss(true);

            // Set grid position to centre but do NOT place occupancy tiles yet.
            // The dragon starts in ATTACKING state (off-stage, not targetable).
            // tickDragonPositionEnforcer adds occupancy tiles when it transitions
            // to PERCHING state.
            int bw = 3, bh = 7;
            int ox = (arenaW - bw) / 2;
            int oz = (arenaH - bh) / 2;
            bossEntity.setGridPos(new GridPos(ox, oz));
            bossEntity.setSize(1);

            // Clear any enemies from the perch zone so they don't block it later
            for (int dx = 0; dx < bw; dx++) {
                for (int dz = 0; dz < bh; dz++) {
                    GridPos slot = new GridPos(ox + dx, oz + dz);
                    CombatEntity existing = arena.getOccupant(slot);
                    if (existing != null && existing != bossEntity) {
                        GridPos relocated = findNearestValidSpawn(arena,
                            new GridPos(ox + dx, oz + dz + bh), existing.getSizeX(), existing.getSizeZ(), false);
                        if (relocated != null) {
                            arena.moveEntity(existing, relocated);
                            MobEntity eMob = existing.getMobEntity();
                            if (eMob != null) {
                                BlockPos bp = arena.gridToBlockPos(relocated);
                                eMob.refreshPositionAndAngles(
                                    bp.getX() + 0.5, bp.getY(), bp.getZ() + 0.5, eMob.getYaw(), eMob.getPitch());
                            }
                        }
                    }
                }
            }

            // Park mob entity 100 blocks above centre -within entity tracking range
            // The per-tick enforcer (tickDragonPositionEnforcer) keeps it there
            // while in ATTACKING state.
            MobEntity dragonMob = bossEntity.getMobEntity();
            if (dragonMob != null) {
                dragonMob.setAiDisabled(true);
                dragonMob.setNoGravity(true);
                dragonMob.noClip = true;
                dragonMob.setInvisible(true);
                // Neutralise the vanilla PhaseManager -HOVER is passive and won't
                // fight our per-tick position enforcement.
                if (dragonMob instanceof net.minecraft.entity.boss.dragon.EnderDragonEntity spawnDragon) {
                    spawnDragon.getPhaseManager().setPhase(
                        net.minecraft.entity.boss.dragon.phase.PhaseType.HOVER);
                }
                double cx = arena.getOrigin().getX() + arenaW / 2.0;
                double cy = arena.getOrigin().getY() + 100;
                double cz = arena.getOrigin().getZ() + arenaH / 2.0;
                forceDragonPosition(dragonMob, cx, cy, cz);
            }
        }

        // Wailing Revenant (Ghast): position OUTSIDE the arena on the low-Z edge.
        // The mob sits beyond the front row, facing +Z (toward the arena).
        // The entire front row (z = 0) is registered as targetable.
        if (ai instanceof WailingRevenantAI) {
            int arenaW = arena.getWidth();
            int arenaH = arena.getHeight();

            // Remove from current grid position
            arena.removeEntity(bossEntity);

            // Mark as background boss -tiles it occupies don't block movement
            bossEntity.setBackgroundBoss(true);

            // Anchor at grid (0, 0) with size 1
            bossEntity.setGridPos(new GridPos(0, 0));
            bossEntity.setSize(1);

            // Register the boss on every tile in the front row (z=0) for targeting.
            // These tiles are still walkable thanks to the backgroundBoss flag.
            // If another enemy already occupies a tile, move it away first.
            for (int x = 0; x < arenaW; x++) {
                GridPos bossSlot = new GridPos(x, 0);
                CombatEntity existing = arena.getOccupant(bossSlot);
                if (existing != null && existing != bossEntity) {
                    // Relocate the existing enemy to the nearest open tile
                    GridPos relocated = findNearestValidSpawn(arena,
                        new GridPos(x, 1), existing.getSizeX(), existing.getSizeZ(), false);
                    if (relocated != null) {
                        arena.moveEntity(existing, relocated);
                        MobEntity eMob = existing.getMobEntity();
                        if (eMob != null) {
                            BlockPos bp = arena.gridToBlockPos(relocated);
                            eMob.refreshPositionAndAngles(
                                bp.getX() + 0.5, bp.getY(), bp.getZ() + 0.5, eMob.getYaw(), eMob.getPitch());
                        }
                    }
                }
                arena.getOccupants().put(bossSlot, bossEntity);
            }

            // Place the mob entity OUTSIDE the arena, beyond the front edge.
            MobEntity mob = bossEntity.getMobEntity();
            if (mob != null) {
                double bossX = arena.getOrigin().getX() + (arenaW - 1) / 2.0 + 0.5; // true center of grid
                double bossZ = arena.getOrigin().getZ() - 10.0; // 10 blocks beyond front edge
                double bossY = arena.getOrigin().getY() + 2.0;
                mob.refreshPositionAndAngles(bossX, bossY, bossZ, 0.0f, 0.0f); // yaw 0 = face +Z
                mob.setYaw(0.0f);
                mob.setHeadYaw(0.0f);
                mob.setBodyYaw(0.0f);
            }
        }
    }

    /**
     * Place a single egg sac entity at the given position.
     * Egg sacs are 1HP destructible entities that block all entities except the Broodmother.
     */
    private void placeEggSacEntity(BroodmotherAI broodmother, GridPos pos, ServerWorld world) {
        int fakeEntityId = -(eggSacIdCounter++);
        // attackPower=0 intended (egg sacs don't attack), but CombatEntity clamps to min 1
        CombatEntity eggSac = new CombatEntity(fakeEntityId, "craftics:egg_sac", pos,
            1, 0, 0, 1);
        eggSac.setPassableForBoss(true);
        eggSac.setAiOverrideKey("craftics:egg_sac");

        enemies.add(eggSac);
        arena.placeEntity(eggSac);

        // Place turtle egg block in the world. gridToBlockPos returns the
        // entity standing block (origin.y + 1) -placing the egg there sits
        // it on top of the arena floor. Using bp.up(1) would float it at
        // head level with an air gap below.
        BlockPos bp = arena.gridToBlockPos(pos);
        world.setBlockState(bp, Blocks.TURTLE_EGG.getDefaultState(),
            net.minecraft.block.Block.NOTIFY_ALL);

        // Spawn placement particles
        world.spawnParticles(net.minecraft.particle.ParticleTypes.ITEM_SLIME,
            bp.getX() + 0.5, bp.getY() + 1.5, bp.getZ() + 0.5,
            8, 0.3, 0.2, 0.3, 0.01);
    }

    /**
     * The world block for each war banner. Distinct colours so the three levers are told apart at
     * a glance, which is the whole point of making them asymmetric: white for the March, red for
     * Fury, black for the Horde. Falls back to red rather than throwing, since an unrecognised
     * banner should still be visible and breakable.
     */
    private static net.minecraft.block.Block warBannerBlock(String typeName) {
        return switch (typeName) {
            case "march" -> Blocks.WHITE_BANNER;
            case "horde" -> Blocks.BLACK_BANNER;
            default -> Blocks.RED_BANNER;
        };
    }

    /**
     * Place a block-backed destructible object on the grid: a real HP combatant with no mob
     * entity, drawn as a world block. Returns null if the grid refused the tile.
     *
     * Immovable is mandatory: knockback would move the grid entry while the world block stayed
     * put, leaving an unhittable ghost. The Creaking heart sets this for the same reason; the
     * egg sac does not, and only gets away with it because nothing shoves it.
     */
    private CombatEntity placeBlockObject(String typeId, GridPos pos, int hp, int fakeEntityId,
                                          net.minecraft.block.Block block, ServerWorld world) {
        // attackPower=0 intended (these never attack), but CombatEntity clamps to min 1
        CombatEntity obj = new CombatEntity(fakeEntityId, typeId, pos, hp, 0, 0, 1);
        obj.setPassableForBoss(true);
        obj.setAiOverrideKey(typeId);
        obj.setImmovable(true);

        // A refused placement would otherwise leave a combatant in `enemies` with no grid
        // tile: unkillable, and the room never clears.
        if (!arena.placeEntity(obj)) {
            return null;
        }
        enemies.add(obj);

        // gridToBlockPos returns the entity standing block (origin.y + 1), so the
        // object sits on the arena floor rather than floating at head level.
        BlockPos bp = arena.gridToBlockPos(pos);
        world.setBlockState(bp, block.getDefaultState(),
            net.minecraft.block.Block.NOTIFY_ALL);
        return obj;
    }

    /**
     * Place cobweb blocks at Y+1 and register web overlays in the arena.
     * Webs apply slowness and last the given number of turns.
     */
    private void placeWebOverlays(List<GridPos> positions, int turns) {
        ServerWorld world = (ServerWorld) player.getEntityWorld();
        for (GridPos pos : positions) {
            if (!arena.isInBounds(pos)) continue;
            arena.setWebOverlay(pos, turns);
            BlockPos bp = arena.gridToBlockPos(pos);
            world.setBlockState(bp.up(1), net.minecraft.block.Blocks.COBWEB.getDefaultState(),
                net.minecraft.block.Block.NOTIFY_ALL);
            // Placement particles
            world.spawnParticles(net.minecraft.particle.ParticleTypes.ITEM_SLIME,
                bp.getX() + 0.5, bp.getY() + 1.5, bp.getZ() + 0.5,
                5, 0.3, 0.2, 0.3, 0.01);
        }
    }

    /**
     * Remove a web overlay at the given position -clears the cobweb block and arena tracking.
     */
    private void removeWebOverlay(GridPos pos) {
        arena.clearWebOverlay(pos);
        ServerWorld world = (ServerWorld) player.getEntityWorld();
        BlockPos bp = arena.gridToBlockPos(pos);
        world.setBlockState(bp.up(1), net.minecraft.block.Blocks.AIR.getDefaultState(),
            net.minecraft.block.Block.NOTIFY_ALL);
    }

    /**
     * Trigger or reset the ghast scream animation (open mouth texture).
     * Only affects ghast entities.
     */
    private void triggerGhastScream(CombatEntity entity, boolean screaming) {
        MobEntity mob = entity.getMobEntity();
        if (mob instanceof net.minecraft.entity.mob.GhastEntity ghast) {
            ghast.setShooting(screaming);
            if (screaming) {
                // Play ghast scream sound
                ServerWorld world = (ServerWorld) player.getEntityWorld();
                world.playSound(null, mob.getBlockPos(),
                    net.minecraft.sound.SoundEvents.ENTITY_GHAST_SCREAM,
                    net.minecraft.sound.SoundCategory.HOSTILE, 1.5f, 1.0f);
            }
        }
    }

    private static final String ARENA_TEAM_NAME = "craftics_nocollide";

    /**
     * Create a scoreboard team with collision disabled and add all arena mobs + players to it.
     * This prevents vanilla entity pushing during combat.
     */
    private void setupNoCollisionTeam() {
        if (player == null) return;
        ServerWorld world = (ServerWorld) player.getEntityWorld();
        net.minecraft.scoreboard.Scoreboard scoreboard = world.getScoreboard();

        // Create or get the team
        net.minecraft.scoreboard.Team team = scoreboard.getTeam(ARENA_TEAM_NAME);
        if (team == null) {
            team = scoreboard.addTeam(ARENA_TEAM_NAME);
        }
        team.setCollisionRule(net.minecraft.scoreboard.AbstractTeam.CollisionRule.NEVER);

        // Add all arena mobs
        for (CombatEntity e : enemies) {
            MobEntity mob = e.getMobEntity();
            if (mob != null) {
                scoreboard.addScoreHolderToTeam(mob.getUuidAsString(), team);
            }
        }
        // Add all players
        for (ServerPlayerEntity p : getAllParticipants()) {
            if (p != null) {
                scoreboard.addScoreHolderToTeam(p.getUuidAsString(), team);
            }
        }
    }

    /**
     * Remove the no-collision team on combat end.
     */
    private void cleanupNoCollisionTeam() {
        if (player == null) return;
        ServerWorld world = (ServerWorld) player.getEntityWorld();
        net.minecraft.scoreboard.Scoreboard scoreboard = world.getScoreboard();
        net.minecraft.scoreboard.Team team = scoreboard.getTeam(ARENA_TEAM_NAME);
        if (team != null) {
            scoreboard.removeTeam(team);
        }
    }

    private void startEnemyMove(List<GridPos> path) {
        // Obstacle collision: stop the mob the tile BEFORE a non-walkable
        // tile that appeared after the AI planned its path (eg the player
        // dropped an obstacle on the dash line). FIRE is treated as
        // walkable since some boss charges intentionally leave fire trails.
        for (int i = 0; i < path.size(); i++) {
            var tile = arena.getTile(path.get(i));
            if (tile != null && !tile.isWalkable()
                    && tile.getType() != com.crackedgames.craftics.core.TileType.FIRE) {
                path = new ArrayList<>(path.subList(0, i));
                sendMessage("§7" + currentEnemy.getDisplayName() + " slams into the obstacle!");
                break;
            }
        }
        // Cobweb trap: truncate path if enemy walks through a web
        for (int i = 0; i < path.size(); i++) {
            if (arena.hasWebOverlay(path.get(i))) {
                path = new ArrayList<>(path.subList(0, i + 1));
                // Break the cobweb
                GridPos webPos = path.get(path.size() - 1);
                arena.clearWebOverlay(webPos);
                BlockPos webBlockPos = new BlockPos(
                    arena.getOrigin().getX() + webPos.x(),
                    arena.getOrigin().getY() + 1,
                    arena.getOrigin().getZ() + webPos.z());
                if (player.getWorld() instanceof ServerWorld sw) {
                    sw.setBlockState(webBlockPos, Blocks.AIR.getDefaultState(),
                        net.minecraft.block.Block.NOTIFY_LISTENERS | net.minecraft.block.Block.FORCE_STATE);
                }
                sendMessage("§7" + currentEnemy.getDisplayName() + " is caught in cobwebs!");
                break;
            }
        }
        // Footprint-vs-player safety net: never let a sized mob step so that its
        // footprint covers the player's tile. A 2x2 mob's anchor can be a tile away
        // from the player yet still overlap them; size-blind AI planning could route
        // there. Truncate to the last tile that keeps the mob off the player. This
        // backstops every AI, including any that didn't use the sized pathfinder.
        if (currentEnemy != null && currentEnemy.isMultiTile()) {
            int szX = currentEnemy.getSizeX();
            int szZ = currentEnemy.getSizeZ();
            GridPos pPos = arena.getPlayerGridPos();
            for (int i = 0; i < path.size(); i++) {
                if (CombatEntity.minDistanceFromSizedEntity(path.get(i), szX, szZ, pPos) == 0) {
                    path = new ArrayList<>(path.subList(0, i));
                    break;
                }
            }
        }
        enemyMovePath = path;
        enemyMovePathIndex = 0;
        enemyMoveTickCounter = 0;
        enemyLerpInitialized = false;
        enemyTurnState = EnemyTurnState.MOVING;
        sendMessage("§7" + currentEnemy.getDisplayName() + " moves...");
        // Announce the mover so the HUD act-order strip can highlight the unit
        // whose turn it is -previously only attacks announced themselves, so
        // movement-only turns never lit up. Also lets the camera follow.
        GridPos moveDest = path.isEmpty() ? currentEnemy.getGridPos() : path.get(path.size() - 1);
        sendToAllParty(new CombatEventPayload(
            CombatEventPayload.EVENT_MOVED, currentEnemy.getEntityId(), 0, 0,
            moveDest.x(), moveDest.z()));
    }

    private void tickEnemyMoving() {
        if (enemyMovePathIndex >= enemyMovePath.size()) {
            // Movement done
            enemyLerpInitialized = false;

            // Projectile impact after movement completes
            if (pendingAction instanceof EnemyAction.ProjectileMove pm && pm.impacts()) {
                resolveProjectileImpact(currentEnemy, pm.impactPos());
                enemyTurnState = EnemyTurnState.DONE;
                enemyTurnDelay = CrafticsMod.CONFIG.enemyTurnDelay();
                return;
            }

            // If MoveAndAttack (any variant), proceed to attack
            if (pendingAction instanceof EnemyAction.MoveAndAttack
                    || pendingAction instanceof EnemyAction.MoveAttackMove
                    || pendingAction instanceof EnemyAction.MoveAndAttackMob
                    || pendingAction instanceof EnemyAction.MoveAndAttackWithKnockback) {
                startAttackAnimation(Math.max(1, CrafticsMod.CONFIG.enemyTurnDelay() / 2));
            } else {
                enemyTurnState = EnemyTurnState.DONE;
                enemyTurnDelay = Math.max(1, CrafticsMod.CONFIG.enemyTurnDelay() / 2);
            }
            return;
        }

        MobEntity mob = currentEnemy.getMobEntity();
        if (mob == null || !mob.isAlive() || mob.isRemoved()) {
            enemyLerpInitialized = false;
            enemyTurnState = EnemyTurnState.DONE;
            return;
        }

        // Init lerp for this tile
        if (!enemyLerpInitialized) {
            enemyLerpInitialized = true;
            enemyMoveTickCounter = 0;
            enemyLerpStartX = mob.getX();
            enemyLerpStartY = mob.getY();
            enemyLerpStartZ = mob.getZ();

            // Face movement direction
            // Face movement direction
            GridPos next = enemyMovePath.get(enemyMovePathIndex);
            GridPos prev = enemyMovePathIndex == 0 ? currentEnemy.getGridPos() : enemyMovePath.get(enemyMovePathIndex - 1);
            int dx = next.x() - prev.x();
            int dz = next.z() - prev.z();
            float yaw = (float) Math.toDegrees(Math.atan2(-dx, dz));
            if ("minecraft:ghast".equals(currentEnemy.getEntityTypeId())) {
                yaw = snapToCardinalYaw(yaw);
            }
            mob.setYaw(yaw);
            mob.setHeadYaw(yaw);
        }

        enemyMoveTickCounter++;
        GridPos next = enemyMovePath.get(enemyMovePathIndex);
        BlockPos endBlock = arena.gridToBlockPos(next);
        double endX = endBlock.getX() + (currentEnemy != null ? currentEnemy.getSizeX() / 2.0 : 0.5);
        double endY = arena.getEntityY(next, currentEnemy != null && currentEnemy.isFlying());
        double endZ = endBlock.getZ() + (currentEnemy != null ? currentEnemy.getSizeZ() / 2.0 : 0.5);

        int emTicks2 = getMoveTicks();
        float progress = Math.min(1.0f, (float) enemyMoveTickCounter / emTicks2);
        double x = enemyLerpStartX + (endX - enemyLerpStartX) * progress;
        double y = enemyLerpStartY + (endY - enemyLerpStartY) * progress;
        double z = enemyLerpStartZ + (endZ - enemyLerpStartZ) * progress;
        mob.requestTeleport(x, y, z);

        // Sync visual projectile entity position with the invisible tracking mob
        if (currentEnemy.isProjectile()) {
            syncVisualProjectile(currentEnemy, x, y + 0.5, z);
        }

        // Swoop trail particles -spawned every tick along the lerp path so the
        // dragon's flight is a visible sweep of breath particles across the arena.
        if (pendingAction instanceof EnemyAction.Swoop && mob.getWorld() instanceof ServerWorld sw) {
            boolean isDragon = currentEnemy.getAiKey() != null
                && currentEnemy.getAiKey().contains("dragons_nest");
            if (isDragon) {
                sw.spawnParticles(net.minecraft.particle.ParticleTypes.DRAGON_BREATH,
                    x, y + 1.5, z, 8, 0.6, 0.4, 0.6, 0.04);
                sw.spawnParticles(net.minecraft.particle.ParticleTypes.PORTAL,
                    x, y + 2.0, z, 6, 0.5, 0.3, 0.5, 0.08);
                sw.spawnParticles(net.minecraft.particle.ParticleTypes.LARGE_SMOKE,
                    x, y + 1.0, z, 3, 0.4, 0.3, 0.4, 0.01);
            } else {
                sw.spawnParticles(net.minecraft.particle.ParticleTypes.CLOUD,
                    x, y + 1.0, z, 4, 0.3, 0.3, 0.3, 0.02);
                sw.spawnParticles(net.minecraft.particle.ParticleTypes.SMOKE,
                    x, y + 0.5, z, 2, 0.2, 0.2, 0.2, 0.01);
            }
        }

        if (enemyMoveTickCounter >= emTicks2) {
            arena.moveEntity(currentEnemy, next);

            // Void Walker rift: teleport the enemy if they landed on one of the
            // portals. Cancel the remaining path so the lerp doesn't snap back.
            if (handleEnemyVoidRiftEntry(currentEnemy, next)) {
                enemyLerpInitialized = false;
                enemyMovePathIndex = enemyMovePath.size();
                enemyTurnState = EnemyTurnState.DONE;
                enemyTurnDelay = CrafticsMod.CONFIG.enemyTurnDelay();
                return;
            }

            // Check if enemy walked onto a void/death tile
            if (checkEnemyFallDeath(currentEnemy)) {
                enemyLerpInitialized = false;
                enemyTurnState = EnemyTurnState.DONE;
                enemyTurnDelay = CrafticsMod.CONFIG.enemyTurnDelay();
                return;
            }

            // Bow-laid traps fire the moment an enemy steps into them.
            if (triggerTileTrap(next, currentEnemy)) {
                enemyLerpInitialized = false;
                enemyMovePathIndex = enemyMovePath.size();
                enemyTurnState = EnemyTurnState.DONE;
                enemyTurnDelay = CrafticsMod.CONFIG.enemyTurnDelay();
                return;
            }

            // Check for hex trap tile effect
            if (tileEffects.containsKey(next) && "hex_trap".equals(tileEffects.get(next))) {
                tileEffects.remove(next);
                hexTrapTurnsRemaining = 0;
                int trapDmg = currentEnemy.takeDamage(12);
                currentEnemy.setStunned(true);
                sendMessage("§5\u2620 " + currentEnemy.getDisplayName() + " triggers a Hex Trap! " + trapDmg + " damage + stunned!");
                if (currentEnemy.getMobEntity() != null) {
                    ServerWorld sw = (ServerWorld) player.getEntityWorld();
                    sw.spawnParticles(net.minecraft.particle.ParticleTypes.WITCH,
                        currentEnemy.getMobEntity().getX(), currentEnemy.getMobEntity().getY() + 1.0,
                        currentEnemy.getMobEntity().getZ(), 20, 0.5, 0.5, 0.5, 0.1);
                    player.getWorld().playSound(null, currentEnemy.getMobEntity().getBlockPos(),
                        net.minecraft.sound.SoundEvents.ENTITY_ELDER_GUARDIAN_CURSE,
                        net.minecraft.sound.SoundCategory.HOSTILE, 0.8f, 1.2f);
                }
                checkAndHandleDeath(currentEnemy);
            }

            // Check for honey trap -enemy loses all remaining movement
            if (tileEffects.containsKey(next) && "honey".equals(tileEffects.get(next))) {
                sendMessage("§e" + currentEnemy.getDisplayName() + " is stuck in honey!");
                tileEffects.remove(next);
                enemyLerpInitialized = false;
                // Skip remaining movement -go directly to DONE
                enemyMovePathIndex = enemyMovePath.size();
                enemyTurnState = EnemyTurnState.DONE;
                enemyTurnDelay = CrafticsMod.CONFIG.enemyTurnDelay();
                // Restore the original floor block under the consumed honey.
                BlockPos honeyBp = arena.gridToBlockPos(next).down();
                ServerWorld honeyWorld = (ServerWorld) player.getEntityWorld();
                GridTile honeyTile = arena.getTile(next);
                net.minecraft.block.Block honeyRestore = honeyTile != null
                    ? honeyTile.getBlockType() : getBiomeFloorBlock();
                honeyWorld.setBlockState(honeyBp, honeyRestore.getDefaultState(),
                    net.minecraft.block.Block.NOTIFY_LISTENERS | net.minecraft.block.Block.FORCE_STATE);
                return;
            }

            // Check for slime trap -enemy bounces, gets stunned + loses
            // remaining movement. Consume the trap (one bounce per slime block).
            if (tileEffects.containsKey(next) && "slime".equals(tileEffects.get(next))) {
                sendMessage("§a" + currentEnemy.getDisplayName() + " bounces off the slime block!");
                tileEffects.remove(next);
                currentEnemy.setStunned(true);
                enemyLerpInitialized = false;
                enemyMovePathIndex = enemyMovePath.size();
                enemyTurnState = EnemyTurnState.DONE;
                enemyTurnDelay = CrafticsMod.CONFIG.enemyTurnDelay();
                // Replace the slime block visual with the original floor block.
                BlockPos slimeBp = arena.gridToBlockPos(next).down();
                ServerWorld slimeWorld = (ServerWorld) player.getEntityWorld();
                GridTile slimeTile = arena.getTile(next);
                net.minecraft.block.Block restoreFloor = slimeTile != null
                    ? slimeTile.getBlockType() : getBiomeFloorBlock();
                slimeWorld.setBlockState(slimeBp, restoreFloor.getDefaultState(),
                    net.minecraft.block.Block.NOTIFY_LISTENERS | net.minecraft.block.Block.FORCE_STATE);
                return;
            }

            // Water tile: soak non-immune enemies
            GridTile enemyLandingTile = arena.getTile(next);
            if (enemyLandingTile != null
                    && enemyLandingTile.getType() == com.crackedgames.craftics.core.TileType.WATER
                    && !isWaterImmune(currentEnemy.getEntityTypeId())) {
                currentEnemy.stackSoaked(2, 1);
                sendMessage("§b" + currentEnemy.getDisplayName() + " is soaked from wading through water!");
            }

            // Lava tile: 10 damage when enemy steps on it
            if (enemyLandingTile != null
                    && enemyLandingTile.getType() == com.crackedgames.craftics.core.TileType.LAVA) {
                int eLavaDmg = currentEnemy.takeDamage(10);
                sendMessage("§6" + currentEnemy.getDisplayName() + " steps in lava for " + eLavaDmg + " damage!");
                if (!currentEnemy.isAlive()) {
                    killEnemy(currentEnemy);
                    enemyLerpInitialized = false;
                    enemyTurnState = EnemyTurnState.DONE;
                    enemyTurnDelay = CrafticsMod.CONFIG.enemyTurnDelay();
                    return;
                }
            }


            // Check for cake -enemy heals 2 HP, one use consumed
            if (tileEffects.containsKey(next) && tileEffects.get(next).startsWith("cake")) {
                // cake format: "cake" or "cake:usesRemaining"
                String cakeData = tileEffects.get(next);
                int uses = 3;
                if (cakeData.contains(":")) {
                    try { uses = Integer.parseInt(cakeData.split(":")[1]); } catch (Exception ignored) {}
                }
                // Enemies heal from cake too
                if (currentEnemy.getCurrentHp() < currentEnemy.getMaxHp()) {
                    currentEnemy.heal(2);
                    sendMessage("§d" + currentEnemy.getDisplayName() + " eats cake! +2 HP");
                }
                uses--;
                if (uses <= 0) {
                    tileEffects.remove(next);
                } else {
                    tileEffects.put(next, "cake:" + uses);
                }
            }

            if (pendingAction instanceof EnemyAction.MoveAndAttack
                    && currentEnemy != null
                    && currentEnemy.isEnraged()
                    && currentEnemy.getAiKey() != null
                    && currentEnemy.getAiKey().contains("revenant")) {
                GridTile trailTile = arena.getTile(next);
                if (trailTile != null && trailTile.isWalkable()) {
                    trailTile.setType(TileType.FIRE);
                    trailTile.setTurnsRemaining(3);
                    BlockPos firePos = arena.gridToBlockPos(next);
                    ServerWorld fireWorld = (ServerWorld) player.getEntityWorld();
                    fireWorld.setBlockState(firePos, trailTile.getBlockType().getDefaultState());
                    fireWorld.spawnParticles(net.minecraft.particle.ParticleTypes.FLAME,
                        firePos.getX() + 0.5, firePos.getY() + 0.2, firePos.getZ() + 0.5,
                        3, 0.15, 0.05, 0.15, 0.01);
                }
            }

            enemyLerpInitialized = false;
            enemyMovePathIndex++;
        }
    }

    /**
     * Returns the ranged projectile effect name for a mob type, or null if melee.
     * Used to determine animation style (ranged aim vs melee lunge).
     */
    private static String getRangedProjectileType(String entityTypeId) {
        return switch (entityTypeId) {
            case "minecraft:skeleton", "minecraft:bogged" -> "arrow";
            case "minecraft:stray" -> "frost_arrow";
            case "minecraft:pillager" -> "crossbow";
            case "minecraft:blaze" -> "fireball";
            case "minecraft:ghast" -> "fireball";
            case "minecraft:witch" -> "potion";
            case "minecraft:shulker" -> "shulker_bullet";
            case "minecraft:llama", "minecraft:trader_llama" -> "llama_spit";
            case "minecraft:drowned" -> "trident";
            case "minecraft:breeze" -> "wind_charge";
            default -> null;
        };
    }

    /**
     * Mob-vs-mob stealth gate: if the predator's returned action targets a mob
     * that's on a tall-grass/fern tile and the predator isn't adjacent to it,
     * downgrade the action to Idle. The player case is handled pre-decision.
     */
    private EnemyAction gateMobTargetingThroughStealth(CombatEntity predator, EnemyAction action) {
        if (action == null) return action;
        Integer targetId = extractTargetMobId(action);
        if (targetId == null) return action;
        CombatEntity prey = null;
        if (enemies != null) {
            for (CombatEntity e : enemies) {
                if (e != null && e.getMobEntity() != null
                        && e.getMobEntity().getId() == targetId) { prey = e; break; }
            }
        }
        if (prey == null) return action;
        if (StealthTiles.isConcealedFrom(arena, predator.getGridPos(), prey.getGridPos(), player.getEntityWorld())) {
            return new EnemyAction.Idle();
        }
        return action;
    }

    private static Integer extractTargetMobId(EnemyAction a) {
        if (a instanceof EnemyAction.AttackMob am) return am.targetEntityId();
        if (a instanceof EnemyAction.MoveAndAttackMob mam) return mam.targetEntityId();
        return null;
    }

    /** Initialize attack animation and transition to ANIMATING state. */
    private void startAttackAnimation(int delay) {
        attackAnimTick = 0;
        attackAnimSwung = false;
        enemyTurnState = EnemyTurnState.ANIMATING;
        enemyTurnDelay = delay;
        if (currentEnemy != null && currentEnemy.getMobEntity() != null) {
            // Casters channel (arms raised) instead of cocking a melee windup.
            var style = com.crackedgames.craftics.combat.animation.MobAttackAnimations
                .styleFor(currentEnemy.getEntityTypeId(), false);
            com.crackedgames.craftics.combat.animation.MobAnimations.set(
                currentEnemy.getMobEntity(),
                com.crackedgames.craftics.combat.animation.MobAttackAnimations.windupPose(style));
        }
    }

    /**
     * Attack animation phase: mob-type-specific animations before damage is applied.
     * Ranged mobs lean back to aim then snap forward on release.
     * Melee mobs lunge forward then return. Spider crouches before pouncing.
     * On completion, transitions to ATTACKING to apply damage.
     */
    private void tickEnemyAnimating() {
        net.minecraft.entity.mob.MobEntity mob = currentEnemy.getMobEntity();
        if (mob == null || !mob.isAlive() || mob.isRemoved()) {
            enemyTurnState = EnemyTurnState.ATTACKING;
            return;
        }

        attackAnimTick++;

        String entityType = currentEnemy.getEntityTypeId();
        // Ranged mobs use ranged anim even when they MoveAndAttack (move to get LOS, then shoot)
        // Special case: drowned without tridents are pure melee, not ranged
        boolean isRanged = pendingAction instanceof EnemyAction.RangedAttack
            || (pendingAction instanceof EnemyAction.MoveAndAttack && getRangedProjectileType(entityType) != null
                && !"minecraft:drowned".equals(entityType))
            || (pendingAction instanceof EnemyAction.MoveAndAttack && "minecraft:drowned".equals(entityType)
                && currentEnemy.isDrownedWithTrident());

        // Tick 1: Face the player and initialize
        if (!attackAnimSwung) {
            attackAnimSwung = true;
            attackAnimOriginX = mob.getX();
            attackAnimOriginY = mob.getY();
            attackAnimOriginZ = mob.getZ();

            // Face toward the target -allies face their enemy target, enemies face chosen aggro target or player
            double dx, dz;
            if (currentEnemy.isAlly() && pendingAllyAttackTarget != null) {
                net.minecraft.entity.mob.MobEntity tgtMob = pendingAllyAttackTarget.getMobEntity();
                if (tgtMob != null) {
                    dx = tgtMob.getX() - mob.getX();
                    dz = tgtMob.getZ() - mob.getZ();
                } else {
                    net.minecraft.util.math.BlockPos tgtBlock =
                        arena.gridToBlockPos(pendingAllyAttackTarget.getGridPos());
                    dx = tgtBlock.getX() + 0.5 - mob.getX();
                    dz = tgtBlock.getZ() + 0.5 - mob.getZ();
                }
            } else if (currentEnemyPetAggroTarget != null) {
                net.minecraft.entity.mob.MobEntity tgtMob = currentEnemyPetAggroTarget.getMobEntity();
                if (tgtMob != null) {
                    dx = tgtMob.getX() - mob.getX();
                    dz = tgtMob.getZ() - mob.getZ();
                } else {
                    net.minecraft.util.math.BlockPos tgtBlock =
                        arena.gridToBlockPos(currentEnemyPetAggroTarget.getGridPos());
                    dx = tgtBlock.getX() + 0.5 - mob.getX();
                    dz = tgtBlock.getZ() + 0.5 - mob.getZ();
                }
            } else {
                // Face the closest party member, not just `this.player` (the
                // host). Without this, in MP a mob attacking player 2 still
                // pivots to face the host's tile, then plays its swing in the
                // wrong direction relative to who it's actually hitting.
                ServerPlayerEntity faceTarget = findClosestPartyTarget(currentEnemy.getGridPos());
                if (faceTarget == null) faceTarget = player;
                dx = faceTarget.getX() - mob.getX();
                dz = faceTarget.getZ() - mob.getZ();
            }
            float yaw = (float) Math.toDegrees(Math.atan2(-dx, dz));
            // Ghasts must always face a cardinal direction
            if ("minecraft:ghast".equals(entityType)) {
                yaw = snapToCardinalYaw(yaw);
            }
            mob.setYaw(yaw);
            mob.setHeadYaw(yaw);

            double dist = Math.sqrt(dx * dx + dz * dz);
            if (dist > 0.01) {
                attackAnimLungeX = dx / dist;
                attackAnimLungeZ = dz / dist;
            } else {
                attackAnimLungeX = 0;
                attackAnimLungeZ = 1;
            }

            // (The hand swing fires on each style's strike frame below, in sync
            // with the impact -the old code also swung here at windup start.)

            // Send attack anim event to client for mob-specific particles
            int attackType = isRanged ? 2
                : (pendingAction instanceof EnemyAction.AttackWithKnockback
                    || pendingAction instanceof EnemyAction.MoveAndAttackWithKnockback) ? 1 : 0;
            GridPos playerGridPos = arena.getPlayerGridPos();
            ServerPlayNetworking.send(player, new com.crackedgames.craftics.network.CombatEventPayload(
                com.crackedgames.craftics.network.CombatEventPayload.EVENT_MOB_ATTACK_ANIM,
                currentEnemy.getMobEntity().getId(), attackType, 0,
                playerGridPos.x(), playerGridPos.z()
            ));
        }

        // === Style-driven attack animation ===
        // The per-mob-type curves (and the addon registration point) live in
        // MobAttackAnimations -this used to be a ~250-line hardcoded chain of
        // isSpiderLike/isHeavyHitter/... branches that addons couldn't touch.
        var style = com.crackedgames.craftics.combat.animation.MobAttackAnimations
            .styleFor(entityType, isRanged);
        var frame = com.crackedgames.craftics.combat.animation.MobAttackAnimations
            .frameAt(style, attackAnimTick);

        mob.requestTeleport(
            attackAnimOriginX + attackAnimLungeX * frame.forward(),
            attackAnimOriginY + frame.rise(),
            attackAnimOriginZ + attackAnimLungeZ * frame.forward());

        if (frame.strike()) {
            mob.swingHand(net.minecraft.util.Hand.MAIN_HAND);
            // Melee strikes flash the ATTACK pose (biped arm snap + sweep FX);
            // ranged releases and caster lobs keep their own silhouette.
            if (com.crackedgames.craftics.combat.animation.MobAttackAnimations.strikeUsesAttackPose(style)) {
                com.crackedgames.craftics.combat.animation.MobAnimations.set(mob,
                    com.crackedgames.craftics.combat.animation.AnimState.ATTACK);
            }
        }

        if (frame.done()) {
            mob.requestTeleport(attackAnimOriginX, attackAnimOriginY, attackAnimOriginZ);
            // Ease the pose back to neutral instead of freezing mid-swing (the
            // old flow left WINDUP active until the safety tick expired it).
            com.crackedgames.craftics.combat.animation.MobAnimations.set(mob,
                com.crackedgames.craftics.combat.animation.AnimState.RECOIL);
            enemyTurnState = EnemyTurnState.ATTACKING;
            enemyTurnDelay = 0;
        }
    }

    private void tickEnemyAttacking() {
        // Ally pet attack resolution -damage applies after the animation completes
        if (currentEnemy.isAlly() && pendingAction instanceof EnemyAction.MoveAndAttackMob maam) {
            CombatEntity allyTarget = findEnemyById(maam.targetEntityId());
            pendingAllyAttackTarget = null;
            if (allyTarget != null && allyTarget.isAlive()) {
                int dealt = allyTarget.takeDamage(maam.damage());
                allyTarget.setAggroAllyEntityId(currentEnemy.getEntityId());
                // Special on-hit ability (strider burn, soak, slow, ...).
                String abilityMsg = allyTarget.isAlive()
                    ? com.crackedgames.craftics.combat.ai.ally.AllyAbilities.applyOnHit(currentEnemy, allyTarget)
                    : "";
                // Shovel Fang enchantments: the owner's shovel arms every pet they own. Seekers
                // are a spell's payload rather than a pet, so they carry no Fangs (matching how
                // they're excluded from Pet affinity and Honed).
                List<CombatEntity> fangShocked = new ArrayList<>();
                if (allyTarget.isAlive() && !currentEnemy.isSeekerProjectile()) {
                    ServerPlayerEntity fangOwner = resolveAllyOwner(currentEnemy.getOwnerUuid());
                    if (fangOwner != null && fangOwner.getEntityWorld() instanceof ServerWorld fangWorld) {
                        abilityMsg += ShovelEnchantEffects.applyOnAllyHit(
                            currentEnemy, allyTarget, fangOwner, arena, fangWorld, fangShocked);
                    }
                }
                if (currentEnemy.isLitOneShot() && allyTarget.isAlive()) {
                    allyTarget.stackBurning(3, 0); // Burning I; the 2 here used to be damage/turn
                }
                sendMessage("§a" + currentEnemy.getDisplayName() + " attacks "
                    + allyTarget.getDisplayName() + " for " + dealt + " damage!" + abilityMsg);
                // Addon combat effects: ally attack notification
                final CombatEntity fAlly = currentEnemy;
                final CombatEntity fAllyTarget = allyTarget;
                final int fAllyDealt = dealt;
                fireEffectHook(h -> h.onAllyAttack(effectContext, fAlly, fAllyTarget, fAllyDealt));
                if (!allyTarget.isAlive()) {
                    // Addon combat effects: ally kill notification
                    fireEffectHook(h -> h.onAllyKill(effectContext, fAlly, fAllyTarget));
                    // Route through the full death pipeline (NOT killEnemy) so a
                    // stacked target drops its next layer / rider instead of being
                    // hard-killed outright. killEnemy skips transformStackLayer, so
                    // an ally killing a Zombie Stack would vanish the whole stack
                    // with the baby never dropping. checkAndHandleDeath transforms
                    // the layer when one remains (target stays alive) and runs the
                    // real death side effects only when the last layer falls.
                    // Credit the ally's OWNER (not the current-turn player) for the kill -
                    // correct for party multiplayer loot/kill-streak attribution.
                    if (currentEnemy.getOwnerUuid() != null) {
                        allyTarget.setLastDamagerUuid(currentEnemy.getOwnerUuid());
                    }
                    // Generic on-kill ally hook (e.g. barrel golem bartering bonus loot).
                    // Hooks come from the AllyKillRegistry, populated by compat modules.
                    com.crackedgames.craftics.combat.ai.ally.AllyKillHook killHook =
                        com.crackedgames.craftics.combat.ai.ally.AllyKillRegistry.hookFor(currentEnemy.getEntityTypeId());
                    if (killHook != null) killHook.onKill(currentEnemy, allyTarget);
                    checkAndHandleDeath(allyTarget);
                    // Only credit the kill / check victory if the target actually
                    // died (a stack transform leaves it alive on the next layer).
                    // checkAndHandleDeath doesn't itself do kill-streak or the
                    // victory check, so mirror what killEnemy used to provide here.
                    if (!allyTarget.isAlive()) {
                        // killEnemy only counts non-ally deaths toward the streak;
                        // preserve that guard in case an ally ever targets an ally.
                        if (!allyTarget.isAlly()) {
                            onEnemyKilled(allyTarget);
                        }
                        if (enemies.stream().noneMatch(e -> e.isAlive() && !e.isAlly())) {
                            handleVictory();
                        }
                    }
                }
                // Thunder Fang's arc can kill things the ally never touched, so those need the
                // same death pipeline the direct victim just went through. Without this a
                // shocked-to-death enemy would stand there at 0 HP until something else nudged it.
                for (CombatEntity zapped : fangShocked) {
                    if (zapped.isAlive()) continue;
                    if (currentEnemy.getOwnerUuid() != null) {
                        zapped.setLastDamagerUuid(currentEnemy.getOwnerUuid());
                    }
                    checkAndHandleDeath(zapped);
                    if (!zapped.isAlive() && !zapped.isAlly()) {
                        onEnemyKilled(zapped);
                    }
                }
                if (!fangShocked.isEmpty()
                        && enemies.stream().noneMatch(e -> e.isAlive() && !e.isAlly())) {
                    handleVictory();
                }
                // Bee allies pay the same sting recoil as enemy bees do.
                if ("minecraft:bee".equals(currentEnemy.getEntityTypeId())) {
                    applyBeeStingRecoil(currentEnemy);
                }
                // Lit coal golem burns out after its one attack.
                if (currentEnemy.isLitOneShot()) {
                    sendMessage("§7The lit " + currentEnemy.getDisplayName() + " burns out.");
                    currentEnemy.takeDamage(currentEnemy.getCurrentHp() + currentEnemy.getDefense() + 9999);
                    checkAndHandleDeath(currentEnemy);
                }
                // A seeker IS its payload: reaching a target spends it. Detonate here
                // rather than in the AI, since only the manager can pull it off the grid.
                if (currentEnemy.isSeekerProjectile()) {
                    detonateSeeker(currentEnemy);
                }
            }
            sendSync();
            enemyTurnState = EnemyTurnState.DONE;
            enemyTurnDelay = 8;
            return;
        }

        // Handle mob-vs-mob attacks (MoveAndAttackMob)
        if (pendingAction instanceof EnemyAction.MoveAndAttackMob maam) {
            CombatEntity target = findEnemyById(maam.targetEntityId());
            if (target != null && target.isAlive()) {
                int bannerBonus = target.isAlly()
                    ? BannerEffects.defenseBonusAt(target.getGridPos(), tileEffects)
                    : 0;
                int dealt = target.takeDamage(maam.damage(), bannerBonus);
                sendMessage("§6" + currentEnemy.getDisplayName() + " attacks " + target.getDisplayName() + " for " + dealt + "!");
                checkAndHandleDeath(target);
            }
            sendSync();
            enemyTurnState = EnemyTurnState.DONE;
            enemyTurnDelay = CrafticsMod.CONFIG.enemyTurnDelay();
            return;
        }

        // Handle ranged attacks -no adjacency required.
        // Some AIs (like Breeze) use MoveAndAttack to reposition and then fire.
        EnemyAction.RangedAttack resolvedRanged = null;
        if (pendingAction instanceof EnemyAction.RangedAttack ra) {
            resolvedRanged = ra;
        } else if (pendingAction instanceof EnemyAction.MoveAndAttack maa) {
            String projectileType = getRangedProjectileType(currentEnemy.getEntityTypeId());
            if (projectileType != null) {
                resolvedRanged = new EnemyAction.RangedAttack(maa.damage(), projectileType);
            }
        }

        if (resolvedRanged != null) {
            // Ranged projectiles cannot fly over obstacles -check line of sight first.
            // MP target resolution: pick the closest live party member (not the
            // stale arena.getPlayerGridPos which only tracks the last-turn
            // player). Without this, a skeleton's arrow targets whoever's tile
            // the arena tracker happens to be on, and on the damage side
            // `this.player` may not match the intended target -so the wrong
            // player took the hit (often producing "skeleton attacked twice in
            // one turn" reports when the death handler then flipped
            // this.player mid-chain).
            // Confused enemy shooting an ally takes priority; else pet-aggro; else player.
            CombatEntity rangedTarget =
                (confusedRangedVictim != null && confusedRangedVictim.isAlive())
                    ? confusedRangedVictim
                    : ((currentEnemyPetAggroTarget != null && currentEnemyPetAggroTarget.isAlive())
                        ? currentEnemyPetAggroTarget : null);
            ServerPlayerEntity rangedTargetPlayer = rangedTarget != null
                ? null : findClosestPartyTarget(currentEnemy.getGridPos());
            GridPos rangedTargetPos = rangedTarget != null ? rangedTarget.getGridPos()
                : (rangedTargetPlayer != null
                    ? gridPosOf(rangedTargetPlayer)
                    : arena.getPlayerGridPos());
            if (!Pathfinding.hasLineOfSight(arena, currentEnemy.getGridPos(), rangedTargetPos)) {
                sendMessage("§7" + currentEnemy.getDisplayName() + "'s ranged attack is blocked by an obstacle.");
                sendSync();
                enemyTurnState = EnemyTurnState.DONE;
                enemyTurnDelay = CrafticsMod.CONFIG.enemyTurnDelay();
                return;
            }
            // Enemy bow enchantment effects: Power adds damage, Flame ignites, Punch knocks back
            int rangedBaseDmg = resolvedRanged.damage();
            boolean rangedFlame = false;
            int rangedFlameLevel = 0;
            int rangedPunchLevel = 0;
            if (currentEnemy != null && currentEnemy.getMobEntity() != null) {
                ItemStack ew = currentEnemy.getMobEntity().getMainHandStack();
                if (!ew.isEmpty()) {
                    int powerLvl = PlayerCombatStats.getEnchantLevel(ew, "minecraft:power");
                    if (powerLvl > 0) rangedBaseDmg += powerLvl;
                    rangedFlameLevel = PlayerCombatStats.getEnchantLevel(ew, "minecraft:flame");
                    if (rangedFlameLevel > 0) rangedFlame = true;
                    rangedPunchLevel = PlayerCombatStats.getEnchantLevel(ew, "minecraft:punch");
                }
            }
            int raDamage = (int)(rangedBaseDmg * com.crackedgames.craftics.CrafticsMod.CONFIG.enemyDamageMultiplier());
            // Confused-ranged victim (a fellow enemy) takes the CombatEntity damage path,
            // same as a pet-aggro target - so a confused skeleton's arrow lands on its ally.
            CombatEntity petTarget =
                (confusedRangedVictim != null && confusedRangedVictim.isAlive())
                    ? confusedRangedVictim
                    : ((currentEnemyPetAggroTarget != null && currentEnemyPetAggroTarget.isAlive())
                        ? currentEnemyPetAggroTarget : null);
            if (petTarget != null) {
                // Addon combat effects: modify ally incoming damage
                int raHookedDmg = fireEffectHookChained(raDamage,
                    (h, d) -> h.onAllyTakeDamage(effectContext, petTarget, currentEnemy, d));
                int raActual = petTarget.takeDamage(raHookedDmg);
                sendMessage("§c" + currentEnemy.getDisplayName() + " hits "
                    + petTarget.getDisplayName() + " for " + raActual + "!");
                if (!petTarget.isAlive()) {
                    fireEffectHook(h -> h.onAllyDeath(effectContext, petTarget));
                }
                checkAndHandleDeath(petTarget);
            } else {
                // Route the entire ranged post-hit chain to the actual target
                // player via the swap pattern (mirrors the melee path). Without
                // this, the first damagePlayer hits whoever this.player is at
                // ranged-attack time and any handler hand-off mid-chain leaks
                // subsequent damage onto the new turn-holder -producing the
                // "skeleton attacked twice in one turn" report where player 2
                // died then player 1 was hit immediately for follow-on damage.
                ServerPlayerEntity savedRangedPlayer = this.player;
                boolean raSwapped = rangedTargetPlayer != null && rangedTargetPlayer != savedRangedPlayer;
                if (raSwapped) {
                    this.player = rangedTargetPlayer;
                    retargetEffectsToCurrentPlayer();
                }
                boolean raTargetDied = false;
                try {
                int raActual = damagePlayer(raDamage, currentEnemy, DamageType.RANGED);

                // Evoker fangs: magic sound + fang particles at player position
                String raEntityType = currentEnemy.getEntityTypeId();
                if ("minecraft:evoker".equals(raEntityType) || "fangs".equals(resolvedRanged.effectName())) {
                    ServerWorld raWorld = (ServerWorld) player.getEntityWorld();
                    player.getWorld().playSound(null, player.getBlockPos(),
                        net.minecraft.sound.SoundEvents.ENTITY_EVOKER_FANGS_ATTACK,
                        net.minecraft.sound.SoundCategory.HOSTILE, 1.0f, 1.0f);
                    // Spawn evoker fang entities at the player's feet for visual effect
                    BlockPos fangPos = player.getBlockPos();
                    for (int fi = 0; fi < 3; fi++) {
                        double fx = fangPos.getX() + 0.5 + (Math.random() - 0.5) * 2;
                        double fz = fangPos.getZ() + 0.5 + (Math.random() - 0.5) * 2;
                        var fangs = new net.minecraft.entity.mob.EvokerFangsEntity(
                            raWorld, fx, fangPos.getY(), fz, 0, fi * 2, null);
                        raWorld.spawnEntity(fangs);
                    }
                    // Casting particles at the evoker
                    if (currentEnemy.getMobEntity() != null) {
                        raWorld.spawnParticles(net.minecraft.particle.ParticleTypes.WITCH,
                            currentEnemy.getMobEntity().getX(),
                            currentEnemy.getMobEntity().getY() + 1.5,
                            currentEnemy.getMobEntity().getZ(),
                            15, 0.3, 0.5, 0.3, 0.05);
                    }
                } else {
                    player.getWorld().playSound(null, player.getBlockPos(),
                        net.minecraft.sound.SoundEvents.ENTITY_ARROW_HIT_PLAYER,
                        net.minecraft.sound.SoundCategory.PLAYERS, 1.0f, 1.0f);
                }

                // On-hit effects only land if the shot connected (dodge/block negates them).
                if (!lastHitAvoided) {
                if (isFrostboundBossAttacker()) {
                    applyFrostboundSlownessOnHit();
                }
                // A pure-effect throw (e.g. the witch's poison potion) deals no impact
                // damage -skip the "hits you for 0" line and let the effect speak.
                if (raActual > 0) {
                    sendMessage("§c" + currentEnemy.getDisplayName() + " hits "
                        + (raSwapped ? rangedTargetPlayer.getName().getString() : "you")
                        + " for " + raActual + "!");
                }
                applyEnemyHitEffect(raEntityType);
                // Flame enchant on enemy bow ignites the player
                if (rangedFlame && !combatEffects.hasFireResistance()) {
                    addEffectHooked(CombatEffects.EffectType.BURNING, 2 + rangedFlameLevel, 0);
                    sendMessage("§6  Flaming arrow ignites you! (Burning for "
                        + (2 + rangedFlameLevel) + " turns)");
                }
                // Punch enchant: knock the player back
                if (rangedPunchLevel > 0) {
                    applyPlayerKnockback(currentEnemy.getGridPos(), rangedPunchLevel + 1, currentEnemy);
                    sendMessage("§e  Punch arrow knocks you back!");
                }
                } // end ranged on-hit effects (skipped on a fully avoided shot)
                checkOverwatchCounter(currentEnemy);

                if (getPlayerHp() <= 0) {
                    sendSync();
                    raTargetDied = true;
                    handlePlayerDeathOrGameOver();
                    return;
                }
                } finally {
                    if (!raTargetDied) {
                        this.player = savedRangedPlayer;
                        retargetEffectsToCurrentPlayer();
                    }
                }
            }

            sendSync();

            enemyTurnState = EnemyTurnState.DONE;
            enemyTurnDelay = CrafticsMod.CONFIG.enemyTurnDelay();
            return;
        }

        // Wolf-style hit-and-run: attack, then use retreat path in the same turn.
        if (pendingAction instanceof EnemyAction.MoveAttackMove mam) {
            CombatEntity petTarget = (currentEnemyPetAggroTarget != null && currentEnemyPetAggroTarget.isAlive())
                ? currentEnemyPetAggroTarget : null;
            // Same MP melee-target fix as the main path below -pick the
            // closest party member instead of arena.getPlayerGridPos().
            ServerPlayerEntity mamTargetPlayer = petTarget != null
                ? null : findClosestPartyTarget(currentEnemy.getGridPos());
            GridPos targetPos = petTarget != null ? petTarget.getGridPos()
                : (mamTargetPlayer != null
                    ? gridPosOf(mamTargetPlayer)
                    : arena.getPlayerGridPos());
            int distToTarget = currentEnemy.minDistanceTo(targetPos);
            if (distToTarget <= 1) {
                int damage = (int)(mam.damage() * com.crackedgames.craftics.CrafticsMod.CONFIG.enemyDamageMultiplier());
                if (petTarget != null) {
                    // Addon combat effects: modify ally incoming damage
                    final CombatEntity mamPet = petTarget;
                    int mamHookedDmg = fireEffectHookChained(damage,
                        (h, d) -> h.onAllyTakeDamage(effectContext, mamPet, currentEnemy, d));
                    int actual = petTarget.takeDamage(mamHookedDmg);
                    sendMessage("§c" + currentEnemy.getDisplayName() + " hits "
                        + petTarget.getDisplayName() + " for " + actual + "!");
                    if (!petTarget.isAlive()) {
                        fireEffectHook(h -> h.onAllyDeath(effectContext, mamPet));
                    }
                    checkAndHandleDeath(petTarget);
                } else {
                    ServerPlayerEntity savedMamPlayer = this.player;
                    boolean mamSwapped = mamTargetPlayer != null && mamTargetPlayer != savedMamPlayer;
                    if (mamSwapped) {
                        this.player = mamTargetPlayer;
                        retargetEffectsToCurrentPlayer();
                    }
                    boolean mamTargetDied = false;
                    try {
                        int actual = damagePlayer(damage, currentEnemy);
                        if (!lastHitAvoided) {
                        if (isFrostboundBossAttacker()) {
                            applyFrostboundSlownessOnHit();
                        }
                        player.getWorld().playSound(null, player.getBlockPos(),
                            net.minecraft.sound.SoundEvents.ENTITY_PLAYER_HURT,
                            net.minecraft.sound.SoundCategory.PLAYERS, 1.0f, 1.0f);
                        sendMessage("§c" + currentEnemy.getDisplayName() + " hits "
                            + (mamSwapped ? mamTargetPlayer.getName().getString() : "you")
                            + " for " + actual + "!");
                        applyEnemyHitEffect(currentEnemy.getEntityTypeId());
                        } // end on-hit effects (skipped on a fully avoided attack)
                        if (getPlayerHp() <= 0) {
                            sendSync();
                            mamTargetDied = true;
                            handlePlayerDeathOrGameOver();
                            return;
                        }
                    } finally {
                        if (!mamTargetDied) {
                            this.player = savedMamPlayer;
                            retargetEffectsToCurrentPlayer();
                        }
                    }
                }
            }

            // Continue turn with the retreat leg, if present.
            if (mam.retreatPath() != null && !mam.retreatPath().isEmpty()) {
                pendingAction = new EnemyAction.Move(mam.retreatPath());
                sendSync();
                startEnemyMove(mam.retreatPath());
                return;
            }

            sendSync();
            enemyTurnState = EnemyTurnState.DONE;
            enemyTurnDelay = CrafticsMod.CONFIG.enemyTurnDelay();
            return;
        }

        CombatEntity petTarget = (currentEnemyPetAggroTarget != null && currentEnemyPetAggroTarget.isAlive())
            ? currentEnemyPetAggroTarget : null;
        // In MP the mob targeted whichever party member was closest at AI-decision
        // time; if we reuse `arena.getPlayerGridPos()` here it points at the
        // leader and the mob's just-completed walk-up "lands out of range" of the
        // leader-only target, so the attack silently skips and the player sees
        // the wind-up animation but takes no damage. Resolve the actual closest
        // member so the mob hits whoever it walked up to.
        ServerPlayerEntity meleeTargetPlayer = petTarget != null
            ? null : findClosestPartyTarget(currentEnemy.getGridPos());
        GridPos targetPos = petTarget != null ? petTarget.getGridPos()
            : (meleeTargetPlayer != null
                ? gridPosOf(meleeTargetPlayer)
                : arena.getPlayerGridPos());

        // Validate melee range -enemy must be adjacent to its chosen target to hit
        int distToTarget = currentEnemy.minDistanceTo(targetPos);
        if (distToTarget > 1) {
            // Not in range -skip attack
            enemyTurnState = EnemyTurnState.DONE;
            enemyTurnDelay = CrafticsMod.CONFIG.enemyTurnDelay();
            return;
        }

        // Determine damage and knockback
        int damage = 0;
        int knockbackTiles = 0;
        if (pendingAction instanceof EnemyAction.Attack atk) damage = atk.damage();
        else if (pendingAction instanceof EnemyAction.MoveAndAttack maa) damage = maa.damage();
        else if (pendingAction instanceof EnemyAction.AttackWithKnockback akb) {
            damage = akb.damage();
            knockbackTiles = akb.knockbackTiles();
        } else if (pendingAction instanceof EnemyAction.MoveAndAttackWithKnockback maakb) {
            damage = maakb.damage();
            knockbackTiles = maakb.knockbackTiles();
        }

        // Enemy weapon enchantment effects: read mob's mainhand and apply on-hit effects
        int enemySharp = 0;
        int enemyFireAspect = 0;
        int enemySmite = 0;
        int enemyBane = 0;
        if (currentEnemy != null && currentEnemy.getMobEntity() != null) {
            ItemStack enemyWeapon = currentEnemy.getMobEntity().getMainHandStack();
            if (!enemyWeapon.isEmpty()) {
                enemySharp = PlayerCombatStats.getEnchantLevel(enemyWeapon, "minecraft:sharpness");
                if (enemySharp > 0) damage += enemySharp;
                int enemyKb = PlayerCombatStats.getEnchantLevel(enemyWeapon, "minecraft:knockback");
                if (enemyKb > 0) knockbackTiles += enemyKb;
                enemyFireAspect = PlayerCombatStats.getEnchantLevel(enemyWeapon, "minecraft:fire_aspect");
                enemySmite = PlayerCombatStats.getEnchantLevel(enemyWeapon, "minecraft:smite");
                enemyBane = PlayerCombatStats.getEnchantLevel(enemyWeapon, "minecraft:bane_of_arthropods");
            }
        }
        // Smite/Bane bonus damage applies if the player counts as undead/arthropod (rare, but supported)
        // For PvE these mostly add flat damage instead since the player isn't undead/arthropod
        boolean enemyHasFireAspect = enemyFireAspect > 0;
        boolean enemyHasSharpness = enemySharp > 0;
        boolean enemyHasSmite = enemySmite > 0;
        boolean enemyHasBane = enemyBane > 0;

        damage = (int)(damage * com.crackedgames.craftics.CrafticsMod.CONFIG.enemyDamageMultiplier());
        if (petTarget != null) {
            // Addon combat effects: modify ally incoming damage
            final CombatEntity melPet = petTarget;
            int melHookedDmg = fireEffectHookChained(damage,
                (h, d) -> h.onAllyTakeDamage(effectContext, melPet, currentEnemy, d));
            int actual = petTarget.takeDamage(melHookedDmg);
            sendMessage("§c" + currentEnemy.getDisplayName() + " hits "
                + petTarget.getDisplayName() + " for " + actual + "!");
            if (!petTarget.isAlive()) {
                fireEffectHook(h -> h.onAllyDeath(effectContext, melPet));
            }
            checkAndHandleDeath(petTarget);
        } else {
            // Route the ENTIRE post-hit chain (damage, on-hit bleed/burn/poison
            // effects, smite extra hit, knockback, thorns/counter retaliation,
            // death check) to the actual melee target in MP by swapping
            // `this.player` for the whole block. Every getPlayerHp / armor /
            // shield / setHealth / addEffect call that runs inside reads from
            // the right player. The restore in finally only fires if the
            // target didn't die -handlePlayerDeathOrGameOver already
            // reassigns this.player to the next alive member on death.
            ServerPlayerEntity savedTurnPlayer = this.player;
            boolean swapped = meleeTargetPlayer != null && meleeTargetPlayer != savedTurnPlayer;
            if (swapped) {
                this.player = meleeTargetPlayer;
                retargetEffectsToCurrentPlayer();
            }
            boolean targetDied = false;
            try {
            int actual = damagePlayer(damage, currentEnemy);

            // On-hit side effects only fire if the attack actually connected. A fully
            // avoided hit (AC dodge / Ethereal / shield block / Gilded Guard) applies
            // NO hit sound, damage message, weapon debuffs, knockback, thorns, or
            // counters -the avoid feedback was already shown inside damagePlayer.
            if (!lastHitAvoided) {
            if (isFrostboundBossAttacker()) {
                applyFrostboundSlownessOnHit();
            }
            // Combat sound at the actual target's position
            player.getWorld().playSound(null, player.getBlockPos(),
                net.minecraft.sound.SoundEvents.ENTITY_PLAYER_HURT,
                net.minecraft.sound.SoundCategory.PLAYERS, 1.0f, 1.0f);

            sendMessage("§c" + currentEnemy.getDisplayName() + " hits "
                + (swapped ? meleeTargetPlayer.getName().getString() : "you")
                + " for " + actual + "!");
            applyEnemyHitEffect(currentEnemy.getEntityTypeId());

            // Modded mob weapon on-hit debuff: a mob swinging a registered modded weapon
            // applies a short player-facing debuff (katana -> bleed, poison sword ->
            // poison, ...). this.player is already the swapped victim here, and
            // addEffectHooked targets this.player, so the right player gets it.
            if (currentEnemy.getMobEntity() != null) {
                ItemStack mobWeapon = currentEnemy.getMobEntity().getMainHandStack();
                if (!mobWeapon.isEmpty()) {
                    net.minecraft.util.Identifier wid =
                        net.minecraft.registry.Registries.ITEM.getId(mobWeapon.getItem());
                    var debuff = com.crackedgames.craftics.combat.ModdedMobWeapons.onHitDebuff(
                        wid != null ? wid.getPath() : null);
                    if (debuff != null) {
                        boolean skipBurn = debuff.type() == CombatEffects.EffectType.BURNING
                            && combatEffects.hasFireResistance();
                        if (!skipBurn && addEffectHooked(debuff.type(), debuff.turns(), debuff.amplifier())) {
                            sendMessage("§5  " + currentEnemy.getDisplayName() + "'s "
                                + mobWeapon.getName().getString() + " afflicts you!");
                        }
                    }
                }
            }

            // Enemy weapon Sharpness: applies bleed stacks to the player (1 stack per level, 3 turn duration)
            if (enemyHasSharpness) {
                int bleedDuration = 3;
                addEffectHooked(CombatEffects.EffectType.BLEEDING, bleedDuration, enemySharp - 1);
                sendMessage("§4  Sharpened weapon causes Bleeding " + enemySharp + "! (-" + enemySharp + " HP/turn for " + bleedDuration + " turns)");
            }

            // Enemy weapon Fire Aspect: ignite the player AND nearby tiles in a cone
            if (enemyHasFireAspect && !combatEffects.hasFireResistance()) {
                int burnTurns = 2 + enemyFireAspect;
                addEffectHooked(CombatEffects.EffectType.BURNING, burnTurns, enemyFireAspect - 1);
                // Cone of flame: convert tiles in front of the player to fire (in the direction the enemy attacked from).
                // Anchor on the actual victim (this.player after the MP target swap), not the
                // last-acting player's arena tile, so the cone spawns around the player who was hit.
                GridPos pPosFa = gridPosOf(player);
                GridPos ePosFa = currentEnemy.getGridPos();
                int faDx = Integer.signum(pPosFa.x() - ePosFa.x());
                int faDz = Integer.signum(pPosFa.z() - ePosFa.z());
                if (faDx == 0 && faDz == 0) faDx = 1;
                int coneDepth = enemyFireAspect + 1; // Lv1 = 2 deep, Lv2 = 3 deep
                java.util.List<GridPos> coneTiles = new ArrayList<>();
                for (int depth = 1; depth <= coneDepth; depth++) {
                    int halfWidth = depth - 1;
                    for (int w = -halfWidth; w <= halfWidth; w++) {
                        int cx, cz;
                        if (faDz == 0) {
                            cx = pPosFa.x() + faDx * depth;
                            cz = pPosFa.z() + w;
                        } else if (faDx == 0) {
                            cx = pPosFa.x() + w;
                            cz = pPosFa.z() + faDz * depth;
                        } else {
                            cx = pPosFa.x() + faDx * depth;
                            cz = pPosFa.z() + faDz * depth + w;
                        }
                        GridPos cp = new GridPos(cx, cz);
                        if (arena.isInBounds(cp)) coneTiles.add(cp);
                    }
                }
                if (!coneTiles.isEmpty()) {
                    resolveCreateTerrain(new EnemyAction.CreateTerrain(coneTiles, TileType.FIRE, 2));
                }
                sendMessage("§6  Flaming weapon ignites you! Burning " + (enemyFireAspect) + " for " + burnTurns + " turns! Cone of flame erupts!");
            }

            // Enemy weapon Bane of Arthropods: poison + slow (applies regardless of player type)
            if (enemyHasBane) {
                addEffectHooked(CombatEffects.EffectType.POISON, 3, Math.max(0, enemyBane - 1));
                addEffectHooked(CombatEffects.EffectType.SLOWNESS, 2, 0);
                sendMessage("§2  Venomous strike! Poisoned and slowed!");
            }

            // Enemy weapon Smite: bonus damage spike (vs the player it's a flat extra hit)
            if (enemyHasSmite) {
                int smiteDmg = enemySmite * 2;
                int smiteActual = damagePlayer(smiteDmg, currentEnemy);
                sendMessage("§e  Holy radiance! Smite deals " + smiteActual + " bonus damage!");
                if (getPlayerHp() <= 0) {
                    sendSync();
                    targetDied = true;
                    handlePlayerDeathOrGameOver();
                    return;
                }
            }

            // Apply knockback to player
            if (knockbackTiles > 0) {
                applyPlayerKnockback(currentEnemy.getGridPos(), knockbackTiles, currentEnemy);
            }

            // Enemy armor Thorns: reflect damage from any armor piece with Thorns
            if (currentEnemy.getMobEntity() != null) {
                int totalEnemyThorns = 0;
                for (net.minecraft.entity.EquipmentSlot slot : new net.minecraft.entity.EquipmentSlot[]{
                        net.minecraft.entity.EquipmentSlot.HEAD, net.minecraft.entity.EquipmentSlot.CHEST,
                        net.minecraft.entity.EquipmentSlot.LEGS, net.minecraft.entity.EquipmentSlot.FEET}) {
                    ItemStack piece = currentEnemy.getMobEntity().getEquippedStack(slot);
                    if (!piece.isEmpty()) {
                        totalEnemyThorns += PlayerCombatStats.getEnchantLevel(piece, "minecraft:thorns");
                    }
                }
                if (totalEnemyThorns > 0 && Math.random() < 0.3) {
                    int thornsRetaliate = damagePlayer(totalEnemyThorns, currentEnemy);
                    sendMessage("§2  Enemy thorns reflects " + thornsRetaliate + " damage!");
                    if (getPlayerHp() <= 0) {
                        sendSync();
                        targetDied = true;
                        handlePlayerDeathOrGameOver();
                        return;
                    }
                }
            }

            // Thorns: reflect damage back to attacker (Luck boosts proc chance)
            int thornsLevel = PlayerCombatStats.getThorns(player);
            if (thornsLevel > 0) {
                int defLuck = PlayerProgression.get((ServerWorld) player.getEntityWorld())
                    .getStats(player).getPoints(PlayerProgression.Stat.LUCK);
                if (Math.random() < (thornsLevel * 0.15) + (defLuck * 0.02)) {
                    int thornsDmg = currentEnemy.takeDamage(thornsLevel);
                    sendMessage("\u00a72Thorns reflects " + thornsDmg + " damage!");
                }
            }

            // Physical affinity: counterattack chance when attacked (Luck boosts proc chance)
            // Triggers based on having PHYSICAL affinity points, regardless of weapon held
            if (currentEnemy.isAlive()) {
                PlayerProgression.PlayerStats pStats = PlayerProgression.get(
                    (ServerWorld) player.getEntityWorld()).getStats(player);
                int physPts = pStats.getAffinityPoints(PlayerProgression.Affinity.PHYSICAL);
                int physLuck = pStats.getPoints(PlayerProgression.Stat.LUCK);
                double counterChance = physPts * 0.03 + physLuck * 0.02; // 3% per affinity + 2% per luck
                if (counterChance > 0 && Math.random() < counterChance) {
                    int counterDmg = performCounterAttack(currentEnemy,
                        computeMeleeAttackDamage(player.getMainHandStack().getItem()));
                    sendMessage("\u00a77\u270A Counter! You strike back for " + counterDmg + " damage!");
                    if (!currentEnemy.isAlive()) {
                        achievementTracker.recordCounterKill();
                        killEnemy(currentEnemy);
                    }
                }
            }

            // Immovable hybrid: reflect a flat amount back at melee attackers.
            if (activeHybridEffect() == HybridEffect.IMMOVABLE && currentEnemy.isAlive()) {
                int reflected = performCounterAttack(currentEnemy, HybridSetEffects.IMMOVABLE_REFLECT);
                sendMessage("\u00a78\u26cf Immovable! " + currentEnemy.getDisplayName()
                    + " takes " + reflected + " reflected damage.");
                if (!currentEnemy.isAlive()) killEnemy(currentEnemy);
            }

            // Counterpuncher hybrid: a chance to immediately strike a melee attacker back.
            if (activeHybridEffect() == HybridEffect.COUNTERPUNCHER && currentEnemy.isAlive()
                    && Math.random() < HybridSetEffects.COUNTERPUNCH_CHANCE) {
                net.minecraft.item.Item counterWeapon = hybridLastWeapon != null
                    ? hybridLastWeapon : player.getMainHandStack().getItem();
                int counterDmg = performCounterAttack(currentEnemy,
                    computeMeleeAttackDamage(counterWeapon));
                sendMessage("\u00a7e\u270A Counterpuncher! You strike back for " + counterDmg + " damage!");
                if (!currentEnemy.isAlive()) {
                    achievementTracker.recordCounterKill();
                    killEnemy(currentEnemy);
                }
            }

            } // end on-hit side effects (skipped entirely on a fully avoided attack)

            if (getPlayerHp() <= 0) {
                sendSync();
                targetDied = true;
                handlePlayerDeathOrGameOver();
                return;
            }
            } finally {
                if (!targetDied) {
                    this.player = savedTurnPlayer;
                    retargetEffectsToCurrentPlayer();
                }
            }
        }

        sendSync();

        enemyTurnState = EnemyTurnState.DONE;
        enemyTurnDelay = CrafticsMod.CONFIG.enemyTurnDelay();
    }

    /**
     * Find a free tile adjacent to the given target for Warp Drive teleportation.
     * Prefers the tile closest to the player's current position so the warp feels
     * like a "leap" rather than a random scatter. Returns null if every adjacent
     * tile is blocked or out of bounds.
     */
    private GridPos findWarpAdjacentTile(CombatEntity target) {
        if (target == null || arena == null) return null;
        GridPos playerPos = arena.getPlayerGridPos();
        // Iterate every tile occupied by the target (handles multi-tile bosses) and
        // collect their 4-neighbour tiles. Score each candidate by manhattan distance
        // from the player, choose the closest valid one.
        java.util.List<GridPos> targetTiles = GridArena.getOccupiedTiles(target);
        GridPos best = null;
        int bestScore = Integer.MAX_VALUE;
        int[][] dirs = { {1,0}, {-1,0}, {0,1}, {0,-1} };
        for (GridPos t : targetTiles) {
            for (int[] d : dirs) {
                GridPos cand = new GridPos(t.x() + d[0], t.z() + d[1]);
                if (!arena.isInBounds(cand)) continue;
                if (arena.isOccupied(cand)) continue;
                GridTile tile = arena.getTile(cand);
                if (tile == null) continue;
                if (tile.getType() == com.crackedgames.craftics.core.TileType.OBSTACLE) continue;
                if (tile.getType() == com.crackedgames.craftics.core.TileType.VOID) continue;
                int score = playerPos.manhattanDistance(cand);
                if (score < bestScore) {
                    bestScore = score;
                    best = cand;
                }
            }
        }
        return best;
    }

    /** Get effective weapon range including trim ATTACK_RANGE bonus. */
    private int getEffectiveWeaponRange() {
        int range = PlayerCombatStats.getWeaponRange(player);
        // Crossbow rook pattern is special (a sentinel, not a literal range) -don't
        // apply flat range bonuses or vision penalties to it.
        if (range != PlayerCombatStats.RANGE_CROSSBOW_ROOK) {
            if (activeTrimScan != null) range += activeTrimScan.get(TrimEffects.Bonus.ATTACK_RANGE);
            // Airtime lofts your shots: +2 range per level, ranged weapons only.
            if (combatEffects.getAirtimeLevel() > 0) {
                Item heldWeapon = player.getMainHandStack().getItem();
                boolean rangedWeapon = PlayerCombatStats.isBowItem(heldWeapon)
                    || heldWeapon == Items.CROSSBOW;
                if (rangedWeapon) range += 2 * combatEffects.getAirtimeLevel();
            }
            // Blindness (-2) and Darkness (-1) shrink vision/range, floored to 1.
            int visionPenalty = combatEffects.getBlindnessPenalty() + combatEffects.getDarknessPenalty();
            if (visionPenalty > 0) range = Math.max(1, range - visionPenalty);
        }
        return range;
    }

    /** OVERWATCH set bonus: counter-attack a ranged enemy that hit the player. */
    private void checkOverwatchCounter(CombatEntity attacker) {
        if (attacker == null || !attacker.isAlive()) return;
        if (activeTrimScan == null || activeTrimScan.setBonus() != TrimEffects.SetBonus.OVERWATCH) return;
        int counterDmg = attacker.takeDamage(PlayerCombatStats.getAttackPower(player));
        sendMessage("§c§l✦ Overwatch! §r§cCounter-shot for " + counterDmg + " damage!");
        if (!attacker.isAlive()) {
            checkAndHandleDeath(attacker);
        }
    }

    /** Scaffold range bonus: +1 range if player is standing on a scaffold tile. */
    private int getScaffoldRangeBonus(GridPos pos) {
        String effect = tileEffects.get(pos);
        return "scaffold".equals(effect) ? 1 : 0;
    }

    private void applyPlayerKnockback(GridPos attackerPos, int tiles) {
        applyPlayerKnockback(attackerPos, tiles, null);
    }

    /**
     * Wind Burst recoil: the mace's shockwave throws the swinger around as well as the
     * enemies. Grants Airtime at the enchant's level for one turn and shoves the player a
     * single tile in a random direction.
     *
     * <p>This does NOT reuse {@link #applyPlayerKnockback(GridPos, int)}. That routine is
     * for being hit BY something: it lands the player on hazards and applies their
     * consequences, so a recoil through it could drop you in the void or deep water for a
     * guaranteed kill - dying to your own successful swing on a 1-in-4 roll. Your own
     * shockwave shouldn't be able to kill you, so this shove refuses any tile that isn't
     * plainly safe and simply doesn't move you when every side is blocked.
     *
     * <p>Airtime is raised, never lowered: {@code addEffect} overwrites the amplifier, so
     * re-granting a flat level would downgrade a bigger stack built from wind charges or an
     * Elytra launch.
     */
    private void applyWindBurstRecoil(int windBurstLevel) {
        if (windBurstLevel <= 0 || arena == null || player == null) return;

        // Airtime at the enchant's level (level N -> amplifier N-1), one turn, capped.
        // Never downgrade an existing, higher stack.
        int wantAmp = Math.min(windBurstLevel - 1, CombatEffects.AIRTIME_MAX_AMPLIFIER);
        int haveAmp = Math.max(0, combatEffects.getAirtimeLevel() - 1);
        combatEffects.addEffect(CombatEffects.EffectType.AIRTIME, 1, Math.max(wantAmp, haveAmp));

        // Shove one tile to a random side, skipping anything unsafe. Directions are tried in
        // a random order so a blocked roll still moves you when some other side is open.
        GridPos from = gridPosOf(player);
        java.util.List<int[]> dirs = new java.util.ArrayList<>(java.util.List.of(
            new int[]{1, 0}, new int[]{-1, 0}, new int[]{0, 1}, new int[]{0, -1}));
        java.util.Collections.shuffle(dirs, new java.util.Random(player.getRandom().nextLong()));

        boolean moved = false;
        for (int[] d : dirs) {
            GridPos to = new GridPos(from.x() + d[0], from.z() + d[1]);
            if (!arena.isInBounds(to) || arena.isEnemyOccupied(to)) continue;
            var tile = arena.getTile(to);
            if (tile == null || !isSafeRecoilTile(tile)) continue;
            arena.setPlayerGridPos(to);
            BlockPos bp = arena.gridToBlockPos(to);
            player.requestTeleport(bp.getX() + 0.5, arena.getEntityY(to, false), bp.getZ() + 0.5);
            moved = true;
            break;
        }

        sendMessage("§b✦ Wind Burst recoil! §f" + (moved ? "You're blown a tile" : "You brace against the blast")
            + " and land in §bAirtime " + Math.max(windBurstLevel, combatEffects.getAirtimeLevel())
            + "§f (1 turn).");
    }

    /**
     * A tile the Wind Burst recoil may drop the player on: somewhere they'd walk anyway, that
     * won't hurt them. Excludes water and powder snow, which are walkable but carry their own
     * consequences (Soaked / freezing) that a self-inflicted recoil shouldn't impose.
     */
    private static boolean isSafeRecoilTile(GridTile tile) {
        com.crackedgames.craftics.core.TileType t = tile.getType();
        if (!t.walkable || t.requiresBoat || t.damageOnStep > 0) return false;
        return t != com.crackedgames.craftics.core.TileType.WATER
            && t != com.crackedgames.craftics.core.TileType.POWDER_SNOW;
    }

    /**
     * Shove the player off a tile perpendicular to a dash direction (used by the
     * Artifacts mimic dash). Damages the player and tries to push them 1 tile
     * sideways. If both perpendicular tiles are blocked, falls back to a 1-tile
     * shove backwards along the dash direction.
     */
    private void shovePlayerAside(GridPos onTile, int dirX, int dirZ, int damage, CombatEntity source) {
        int actual = damagePlayer(damage, source);
        sendMessage("§c  " + (source != null ? source.getDisplayName() : "Mimic") + " slams into you for " + actual + " damage!");
        // Compute perpendicular direction(s) -for an X dash, perpendicular is Z and vice versa.
        int[][] sidewaysOptions;
        if (dirX != 0) {
            sidewaysOptions = new int[][] { {0, 1}, {0, -1}, {-dirX, 0} };
        } else {
            sidewaysOptions = new int[][] { {1, 0}, {-1, 0}, {0, -dirZ} };
        }
        for (int[] off : sidewaysOptions) {
            GridPos dest = new GridPos(onTile.x() + off[0], onTile.z() + off[1]);
            if (!arena.isInBounds(dest)) continue;
            if (arena.isOccupied(dest)) continue;
            GridTile t = arena.getTile(dest);
            if (t == null) continue;
            if (t.getType() == com.crackedgames.craftics.core.TileType.OBSTACLE) continue;
            if (t.getType() == com.crackedgames.craftics.core.TileType.VOID) continue;
            arena.setPlayerGridPos(dest);
            BlockPos shoveBlock = arena.gridToBlockPos(dest);
            //? if <=1.21.1 {
            player.teleport((ServerWorld) player.getEntityWorld(),
                shoveBlock.getX() + 0.5, shoveBlock.getY(), shoveBlock.getZ() + 0.5,
                java.util.Collections.emptySet(), player.getYaw(), 0f);
            //?} else {
            /*player.teleport((ServerWorld) player.getEntityWorld(),
                shoveBlock.getX() + 0.5, shoveBlock.getY(), shoveBlock.getZ() + 0.5,
                java.util.Collections.emptySet(), player.getYaw(), 0f, true);
            *///?}
            return;
        }
    }

    /**
     * Shove a non-player entity off a tile (mimic dash collision).
     * Tries perpendicular tiles first, then falls back to backwards.
     */
    private void shoveEntityAside(CombatEntity occupant, GridPos onTile, int dirX, int dirZ, int damage) {
        int dealt = occupant.takeDamage(damage);
        sendMessage("§c  Slams into " + occupant.getDisplayName() + " for " + dealt + " damage!");
        int[][] sidewaysOptions;
        if (dirX != 0) {
            sidewaysOptions = new int[][] { {0, 1}, {0, -1}, {-dirX, 0} };
        } else {
            sidewaysOptions = new int[][] { {1, 0}, {-1, 0}, {0, -dirZ} };
        }
        for (int[] off : sidewaysOptions) {
            GridPos dest = new GridPos(onTile.x() + off[0], onTile.z() + off[1]);
            if (!arena.isInBounds(dest)) continue;
            if (arena.isOccupied(dest)) continue;
            GridTile t = arena.getTile(dest);
            if (t == null) continue;
            if (t.getType() == com.crackedgames.craftics.core.TileType.OBSTACLE) continue;
            arena.moveEntity(occupant, dest);
            MobEntity mob = occupant.getMobEntity();
            if (mob != null) {
                BlockPos shoveBlock = arena.gridToBlockPos(dest);
                mob.requestTeleport(shoveBlock.getX() + 0.5,
                    arena.getEntityY(dest, occupant.isFlying()),
                    shoveBlock.getZ() + 0.5);
            }
            return;
        }
        if (!occupant.isAlive()) checkAndHandleDeath(occupant);
    }

    /**
     * Prismarine armor's guardian beam. At the start of the wearer's turn every live
     * enemy standing within {@link ArmorSetEffects#PRISMARINE_RADIUS} tiles takes Water
     * damage and is Soaked. Mob Water resistances still apply, so a drowned shrugs it
     * off the same way it shrugs off a trident.
     */
    private void applyPrismarineDischarge(ServerPlayerEntity wearer) {
        if (arena == null || wearer == null) return;
        GridPos wearerPos = gridPosOf(wearer);
        if (wearerPos == null) return;

        int zapped = 0;
        for (CombatEntity enemy : new java.util.ArrayList<>(enemies)) {
            if (!enemy.isAlive() || enemy.isAlly()) continue;
            if (enemy.minDistanceTo(wearerPos) > ArmorSetEffects.PRISMARINE_RADIUS) continue;

            int dealt = enemy.takeDamage(MobResistances.applyResistance(
                enemy.getEntityTypeId(), DamageType.WATER, ArmorSetEffects.PRISMARINE_DAMAGE));
            if (dealt <= 0) continue;
            enemy.stackSoaked(ArmorSetEffects.PRISMARINE_SOAK_TURNS, 1);
            zapped++;
            achievementTracker.recordPlayerDealtDamage();

            if (wearer.getEntityWorld() instanceof ServerWorld world) {
                ProjectileSpawner.spawnSpellTrail(world,
                    arena.gridToBlockPos(wearerPos), arena.gridToBlockPos(enemy.getGridPos()),
                    net.minecraft.particle.ParticleTypes.BUBBLE,
                    net.minecraft.particle.ParticleTypes.SPLASH, 12, 0.2);
            }
            sendMessage("§3✦ Prismarine beam hits " + enemy.getDisplayName()
                + " for " + dealt + " and soaks it!");
            checkAndHandleDeath(enemy);
        }
        if (zapped > 0 && wearer.getEntityWorld() instanceof ServerWorld world) {
            world.playSound(null, wearer.getBlockPos(),
                net.minecraft.sound.SoundEvents.ENTITY_GUARDIAN_ATTACK,
                net.minecraft.sound.SoundCategory.PLAYERS, 0.8f, 1.2f);
        }
    }

    /**
     * Wooden and Bone armor are brittle: every worn piece of the set independently
     * risks shattering when its wearer is struck. A piece that shatters is destroyed
     * outright, not merely damaged - the set trades durability for its other perks.
     * Luck steadies the gear, shaving the roll down without ever making it safe.
     */
    private void applyFragileArmorBreak() {
        if (player == null) return;
        double breakChance = ArmorSetEffects.fragileBreakChance(
            PlayerCombatStats.getArmorSet(player), luckPointsOf(player));
        if (breakChance <= 0) return;
        for (net.minecraft.entity.EquipmentSlot slot : new net.minecraft.entity.EquipmentSlot[]{
                net.minecraft.entity.EquipmentSlot.HEAD, net.minecraft.entity.EquipmentSlot.CHEST,
                net.minecraft.entity.EquipmentSlot.LEGS, net.minecraft.entity.EquipmentSlot.FEET}) {
            ItemStack piece = player.getEquippedStack(slot);
            if (piece.isEmpty()) continue;
            if (Math.random() >= breakChance) continue;
            String name = piece.getName().getString();
            player.equipStack(slot, ItemStack.EMPTY);
            sendMessage("§c§l✦ SHATTERED! §r§7Your " + name + " breaks apart.");
            player.getWorld().playSound(null, player.getBlockPos(),
                net.minecraft.sound.SoundEvents.BLOCK_GLASS_BREAK,
                net.minecraft.sound.SoundCategory.PLAYERS, 1.0f, 0.8f);
        }
    }

    /** Wither armor: whatever strikes the wearer in melee starts to rot. */
    private void applyWitherRetaliation(CombatEntity attacker) {
        if (player == null || attacker == null || !attacker.isAlive()) return;
        int turns = ArmorSetEffects.witherRetaliationTurns(PlayerCombatStats.getArmorSet(player));
        if (turns <= 0) return;
        // Only a melee attacker touches the armor; an archer across the arena does not.
        if (attacker.minDistanceTo(gridPosOf(player)) > 1) return;
        attacker.stackWither(turns, 0);
        sendMessage("§8✦ Wither armor: §7" + attacker.getDisplayName() + " begins to rot.");
    }

    /** Slime armor: the wearer's own hits bounce their target away. */
    private void applySlimeAttackKnockback(CombatEntity target) {
        if (player == null || target == null || !target.isAlive() || arena == null) return;
        int tiles = ArmorSetEffects.contactKnockbackTiles(PlayerCombatStats.getArmorSet(player));
        if (tiles <= 0) return;
        GridPos pPos = gridPosOf(player);
        GridPos tPos = target.getGridPos();
        int dx = Integer.signum(tPos.x() - pPos.x());
        int dz = Integer.signum(tPos.z() - pPos.z());
        if (dx == 0 && dz == 0) return;
        knockEnemyBack(target, dx, dz, tiles);
        sendMessage("§a✦ Slime armor: §7" + target.getDisplayName() + " bounces away.");
    }

    /** Slime armor: the blow bounces. Both parties are shoved a tile apart. */
    private void applySlimeContactKnockback(CombatEntity attacker) {
        if (player == null || attacker == null || !attacker.isAlive() || arena == null) return;
        int tiles = ArmorSetEffects.contactKnockbackTiles(PlayerCombatStats.getArmorSet(player));
        if (tiles <= 0) return;
        if (attacker.minDistanceTo(gridPosOf(player)) > 1) return; // only contact bounces

        GridPos pPos = gridPosOf(player);
        GridPos aPos = attacker.getGridPos();
        knockEnemyBack(attacker,
            Integer.signum(aPos.x() - pPos.x()), Integer.signum(aPos.z() - pPos.z()), tiles);
        applyPlayerKnockback(aPos, tiles, attacker);
        sendMessage("§a✦ Slime armor: §7the blow bounces you both apart.");
    }

    /**
     * True if the live world has a solid, collidable floor under this tile - an entity placed
     * here would stand, not fall.
     *
     * <p>Used to sanity-check a tile the arena scan typed {@code VOID} before applying an
     * instant-death. A VOID-typed tile with a real block beneath it is a MIS-CLASSIFICATION
     * (the schematic floor sat at a different Y than the sampled level, so the scan saw air and
     * called it a pit), and the player - who sees solid ground - must not be void-killed for
     * standing on it. A genuine pit has air laid at the floor, so this returns false for those
     * and the lethal path still runs.
     */
    private boolean hasSolidFloorAt(GridPos pos) {
        if (arena == null || !(player.getEntityWorld() instanceof ServerWorld sw)) return false;
        BlockPos stand = arena.gridToBlockPos(pos); // feet at origin.getY() + 1
        // Scan from the standing block down to the fall-death threshold (origin.getY() - 2, the
        // same line the movement fall-check uses). The build-time scan types a tile VOID off a
        // single sampled floor level, so it MISSES a walkable surface that sits a step above -
        // the raised temple floor beside a pillar is the classic case. If any block in this
        // window is solid the player lands on it instead of plummeting, so it is not a death pit.
        // A genuine pit is air the whole way down and still returns false, keeping it lethal.
        int bottom = arena.getOrigin().getY() - 2;
        for (int y = stand.getY(); y >= bottom; y--) {
            BlockPos p = new BlockPos(stand.getX(), y, stand.getZ());
            if (!sw.getBlockState(p).getCollisionShape(sw, p).isEmpty()) return true;
        }
        return false;
    }

    /**
     * Move a player who SURVIVED a void/drown knockback (via a totem) off the hazard tile and
     * onto solid ground.
     *
     * <p>A survivor left standing on a genuine void tile - whose floor is air - falls through
     * and trips the per-tick fall-death check on the very next tick, dying for real with the
     * totem already spent. Mirrors the rescue the movement void-fall path performs.
     */
    private void rescueSurvivorToSafeTile() {
        GridPos safeGrid = getSafeArenaGridPos(arena);
        BlockPos safePos = safeGrid != null
            ? arena.gridToBlockPos(safeGrid) : arena.getPlayerStartBlockPos();
        if (safeGrid != null) arena.setPlayerGridPos(safeGrid);
        if (safePos != null) {
            player.requestTeleport(safePos.getX() + 0.5, safePos.getY(), safePos.getZ() + 0.5);
            broadcastPlayerPositionToOthers(player);
        }
        player.setVelocity(0, 0, 0);
        player.velocityModified = true;
        player.fallDistance = 0;
        refreshHighlights();
        sendSync();
    }

    /**
     * Knock the player back N tiles away from the attacker position.
     */
    private void applyPlayerKnockback(GridPos attackerPos, int tiles, CombatEntity source) {
        // Immovable hybrid: the player cannot be knocked back at all.
        if (activeHybridEffect() == HybridEffect.IMMOVABLE) {
            sendMessage("§8⛏ Immovable -you don't budge.");
            return;
        }
        // Heavy armor: too much plate to shift.
        if (ArmorSetEffects.ignoresKnockback(PlayerCombatStats.getArmorSet(player))) {
            sendMessage("§8⛨ Heavy armor -the blow doesn't move you.");
            return;
        }
        // Slow Falling: the player resists knockback (floats in place).
        if (combatEffects.hasSlowFalling()) {
            sendMessage("§f☁ Slow Falling -you drift, unmoved by the blow.");
            return;
        }
        // Addon combat effects: modify knockback distance
        tiles = fireEffectHookChained(tiles, (h, d) -> h.onKnockback(effectContext, source, d));
        if (tiles <= 0) return;

        // Read THIS.PLAYER's actual position, not arena.getPlayerGridPos(). The
        // arena tracker only ever holds one position -whoever took the last
        // player turn -so in MP a mob knocking back the host would compute
        // the "from" tile as player 2's stale spot and teleport the host
        // across the arena to land near player 2. gridPosOf walks the player's
        // real block pos through the arena origin instead.
        GridPos playerGridPos = gridPosOf(player);
        int dx = Integer.signum(playerGridPos.x() - attackerPos.x());
        int dz = Integer.signum(playerGridPos.z() - attackerPos.z());
        if (dx == 0 && dz == 0) dx = 1; // default direction

        GridPos landingPos = playerGridPos;
        boolean hitHazard = false;
        boolean hitCactus = false;
        for (int i = 1; i <= tiles; i++) {
            GridPos candidate = new GridPos(playerGridPos.x() + dx * i, playerGridPos.z() + dz * i);
            if (!arena.isInBounds(candidate) || arena.isEnemyOccupied(candidate)) break;
            var tile = arena.getTile(candidate);
            if (tile == null) break;

            // Solid obstacles block knockback -check for cactus
            if (tile.getType() == com.crackedgames.craftics.core.TileType.OBSTACLE) {
                if (tile.getBlockType() == Blocks.CACTUS) hitCactus = true;
                break;
            }

            // Hazard tiles: land ON them, then take consequences
            if (tile.getType() == com.crackedgames.craftics.core.TileType.VOID
                || tile.getType() == com.crackedgames.craftics.core.TileType.DEEP_WATER
                || tile.getType() == com.crackedgames.craftics.core.TileType.WATER
                || tile.getType() == com.crackedgames.craftics.core.TileType.LAVA) {
                // A tile typed VOID but with a real floor beneath it in the live world is a
                // mis-classified tile, not a pit: the player sees solid ground and would not
                // fall, so treat it as normal footing rather than an instant-death hazard.
                if (tile.getType() == com.crackedgames.craftics.core.TileType.VOID
                        && hasSolidFloorAt(candidate)) {
                    landingPos = candidate;
                    continue;
                }
                landingPos = candidate;
                hitHazard = true;
                break;
            }

            landingPos = candidate;
        }

        // Cactus collision damage -fires even if player didn't move (adjacent slam)
        if (hitCactus) {
            int cactusDmg = damagePlayer(2, source);
            sendMessage("§2  Slammed into a cactus for " + cactusDmg + " damage!");
            if (getPlayerHp() <= 0) {
                sendSync();
                handlePlayerDeathOrGameOver();
                return;
            }
        }

        if (!landingPos.equals(playerGridPos)) {
            arena.setPlayerGridPos(landingPos);
            BlockPos bp = arena.gridToBlockPos(landingPos);
            double kbY = (boatOf(player) != null) ? bp.getY() : arena.getEntityY(landingPos);
            player.requestTeleport(bp.getX() + 0.5, kbY, bp.getZ() + 0.5);
            broadcastPlayerPositionToOthers(player);
            sendMessage("§e  Knocked back " + playerGridPos.manhattanDistance(landingPos) + " tiles!");

            if (hitHazard) {
                var hazardTile = arena.getTile(landingPos);
                if (hazardTile != null) {
                    switch (hazardTile.getType()) {
                        case VOID -> {
                            damagePlayer((int) player.getHealth() + 10, source);
                            sendMessage("§4  Fell into the void!");
                            // Survived (a totem fired inside damagePlayer): don't leave them
                            // standing on the void tile or they fall through and the per-tick
                            // fall-death check kills them for real next tick, totem already spent.
                            if (getPlayerHp() > 0) rescueSurvivorToSafeTile();
                        }
                        case DEEP_WATER -> {
                            if (playerHasBoat()) {
                                consumeBoat();
                                addEffectHooked(CombatEffects.EffectType.SOAKED, 2, 0);
                                sendMessage("§b  Your boat saves you from drowning! Soaked for 2 turns.");
                            } else {
                                damagePlayer((int) player.getHealth() + 10, source);
                                sendMessage("§1  Drowned in deep water!");
                                if (getPlayerHp() > 0) rescueSurvivorToSafeTile();
                            }
                        }
                        case LAVA -> {
                            if (!combatEffects.hasFireResistance()) {
                                int lavaDmg = damagePlayer(10, source);
                                sendMessage("§6  Knocked into lava for " + lavaDmg + " damage!");
                            } else {
                                sendMessage("§6  Knocked into lava, but the heat washes over you!");
                            }
                        }
                        case WATER -> {
                            addEffectHooked(CombatEffects.EffectType.SOAKED, 2, 0);
                            sendMessage("§b  Splashed into water! Soaked for 2 turns.");
                        }
                        default -> {}
                    }
                    if (getPlayerHp() <= 0) {
                        sendSync();
                        handlePlayerDeathOrGameOver();
                    }
                }
            }
        }
    }

    /**
     * Breeze wind charge: punt the player 2 tiles away from the breeze, then
     * blow every entity adjacent to the player's new position 2 tiles further
     * outward. Stops early on walls, obstacles, occupants, or hazards.
     */
    private void applyWindChargeKnockback(CombatEntity breeze) {
        if (breeze == null) return;
        GridPos breezePos = breeze.getGridPos();
        // Read the actual victim's tile, not arena.getPlayerGridPos() -that
        // arena tracker only holds the last-turn-player's pos, so in MP the
        // knockback's "from" tile would point at the wrong player and the
        // landing candidates would compute from there. With gridPosOf the
        // wind charge actually launches the player who got hit by it.
        GridPos playerStart = gridPosOf(player);
        int pdx = Integer.signum(playerStart.x() - breezePos.x());
        int pdz = Integer.signum(playerStart.z() - breezePos.z());
        if (pdx == 0 && pdz == 0) { pdx = 1; }

        GridPos playerLanding = playerStart;
        for (int i = 1; i <= 2; i++) {
            GridPos candidate = new GridPos(playerStart.x() + pdx * i, playerStart.z() + pdz * i);
            if (!arena.isInBounds(candidate) || arena.isOccupied(candidate)) break;
            GridTile tile = arena.getTile(candidate);
            if (tile == null || !tile.isWalkable()) break;
            playerLanding = candidate;
        }
        if (!playerLanding.equals(playerStart)) {
            arena.setPlayerGridPos(playerLanding);
            BlockPos bp = arena.gridToBlockPos(playerLanding);
            player.requestTeleport(bp.getX() + 0.5, bp.getY(), bp.getZ() + 0.5);
            broadcastPlayerPositionToOthers(player);
        }

        // Push every entity adjacent to the player's new position 2 tiles
        // outward (away from the player). Diagonals included so the gust
        // radiates in all 8 directions.
        java.util.List<CombatEntity> nearby = new java.util.ArrayList<>();
        for (CombatEntity e : enemies) {
            if (e == null || !e.isAlive() || e == breeze) continue;
            GridPos epos = e.getGridPos();
            int dx = epos.x() - playerLanding.x();
            int dz = epos.z() - playerLanding.z();
            if (Math.abs(dx) <= 1 && Math.abs(dz) <= 1 && !(dx == 0 && dz == 0)) {
                nearby.add(e);
            }
        }
        for (CombatEntity e : nearby) {
            GridPos epos = e.getGridPos();
            int dx = Integer.signum(epos.x() - playerLanding.x());
            int dz = Integer.signum(epos.z() - playerLanding.z());
            if (dx == 0 && dz == 0) continue;
            knockEnemyBack(e, dx, dz, 2);
        }
    }

    /**
     * Knock an enemy back, allowing them to land on hazard tiles (void/lava/water).
     * Returns the final landing position.
     */
    private GridPos knockEnemyBack(CombatEntity enemy, int dx, int dz, int tiles) {
        GridPos startPos = enemy.getGridPos();
        int sizeX = enemy.getSizeX();
        int sizeZ = enemy.getSizeZ();
        GridPos landingPos = startPos;
        boolean hitHazard = false;
        boolean hitCactus = false;
        boolean hitWall = false;
        String wallLabel = "wall";

        // Iterate the push 1 tile at a time. For multi-tile entities we have
        // to check the FULL footprint at each candidate -the old single-tile
        // check let a 2x2 spider land on a small mob because only the
        // top-left corner of the destination got validated, sharing the other
        // three footprint tiles with whoever was already there.
        for (int i = 1; i <= tiles; i++) {
            GridPos candidate = new GridPos(startPos.x() + dx * i, startPos.z() + dz * i);

            boolean candidateHazard = false;
            boolean candidateWall = false;
            boolean candidateCactus = false;
            for (int fx = 0; fx < sizeX && !candidateWall; fx++) {
                for (int fz = 0; fz < sizeZ; fz++) {
                    GridPos fp = new GridPos(candidate.x() + fx, candidate.z() + fz);

                    if (!arena.isInBounds(fp)) {
                        candidateWall = true;
                        wallLabel = "arena wall";
                        break;
                    }
                    CombatEntity occ = arena.getOccupant(fp);
                    if (occ != null && occ != enemy && !occ.isBackgroundBoss()) {
                        candidateWall = true;
                        wallLabel = "another enemy";
                        break;
                    }
                    if (fp.equals(arena.getPlayerGridPos())) {
                        candidateWall = true;
                        wallLabel = "the player";
                        break;
                    }
                    for (GridPos pp : arena.getAllPlayerGridPositions()) {
                        if (fp.equals(pp)) { candidateWall = true; wallLabel = "the player"; break; }
                    }
                    if (candidateWall) break;
                    var tile = arena.getTile(fp);
                    if (tile == null) { candidateWall = true; break; }

                    if (tile.getType() == com.crackedgames.craftics.core.TileType.OBSTACLE) {
                        if (tile.getBlockType() == Blocks.CACTUS) {
                            candidateCactus = true;
                        } else {
                            candidateWall = true;
                            wallLabel = "obstacle";
                            break;
                        }
                        continue;
                    }

                    if (tile.getType() == com.crackedgames.craftics.core.TileType.VOID
                        || tile.getType() == com.crackedgames.craftics.core.TileType.DEEP_WATER
                        || tile.getType() == com.crackedgames.craftics.core.TileType.WATER
                        || tile.getType() == com.crackedgames.craftics.core.TileType.LAVA) {
                        if (enemy.isHazardImmune()) {
                            candidateWall = true;
                            wallLabel = "hazard edge";
                            break;
                        }
                        candidateHazard = true;
                        continue;
                    }

                    if (!tile.isWalkable()) {
                        candidateWall = true;
                        wallLabel = "terrain";
                        break;
                    }
                }
            }

            if (candidateWall) {
                hitWall = true;
                if (candidateCactus) hitCactus = true;
                break;
            }
            if (candidateCactus) hitCactus = true;
            if (candidateHazard) {
                landingPos = candidate;
                hitHazard = true;
                break;
            }
            landingPos = candidate;
        }

        // Cactus collision damage -cactus has its own fixed-damage effect that fires
        // even if the enemy didn't move at all (adjacent slam).
        if (hitCactus) {
            int cactusDmg = enemy.takeDamage(2);
            sendMessage("§2" + enemy.getDisplayName() + " slammed into a cactus for " + cactusDmg + " damage!");
            if (!enemy.isAlive()) {
                killEnemy(enemy);
                return startPos;
            }
        }

        // Generic wall/obstacle slam -scales with the push strength so strong
        // knockbacks that hit a wall hurt more than weak ones. Mirrors the
        // collision handling in VanillaWeapons' Knockback shockwave.
        if (hitWall && !hitHazard) {
            int slamDamage = Math.max(1, tiles * 2);
            int dealt = enemy.takeDamage(slamDamage);
            sendMessage("§6" + enemy.getDisplayName() + " slammed into " + wallLabel
                + " for " + dealt + " collision damage!");
            if (!enemy.isAlive()) {
                killEnemy(enemy);
                return landingPos;
            }
        }

        if (!landingPos.equals(startPos)) {
            arena.moveEntity(enemy, landingPos);
            if (enemy.getMobEntity() != null) {
                var bp = arena.gridToBlockPos(landingPos);
                enemy.getMobEntity().requestTeleport(bp.getX() + 0.5, arena.getEntityY(landingPos, enemy.isFlying()), bp.getZ() + 0.5);
            }

            if (hitHazard) {
                var hazardTile = arena.getTile(landingPos);
                if (hazardTile != null) {
                    switch (hazardTile.getType()) {
                        case VOID -> {
                            enemy.takeDamage(enemy.getCurrentHp() + 100);
                            sendMessage("§4" + enemy.getDisplayName() + " fell into the void!");
                            killEnemy(enemy);
                        }
                        case DEEP_WATER -> {
                            if (isWaterImmune(enemy.getEntityTypeId())) {
                                // Aquatic mobs survive deep water -just soak them
                                enemy.stackSoaked(2, 1);
                                sendMessage("§b" + enemy.getDisplayName() + " splashes into deep water!");
                            } else {
                                enemy.takeDamage(enemy.getCurrentHp() + 100);
                                sendMessage("§1" + enemy.getDisplayName() + " drowned in deep water!");
                                killEnemy(enemy);
                            }
                        }
                        case LAVA -> {
                            int lavaDmg = enemy.takeDamage(10);
                            sendMessage("§6" + enemy.getDisplayName() + " knocked into lava for " + lavaDmg + " damage!");
                            if (!enemy.isAlive()) {
                                killEnemy(enemy);
                            }
                        }
                        case WATER -> {
                            enemy.stackSoaked(2, 1);
                            sendMessage("§b" + enemy.getDisplayName() + " splashes into water! Soaked!");
                        }
                        default -> {}
                    }
                }
            }
        }
        return landingPos;
    }

    private boolean hasLeatherBoots() {
        if (player == null) return false;
        var boots = player.getEquippedStack(net.minecraft.entity.EquipmentSlot.FEET);
        return boots.getItem() == Items.LEATHER_BOOTS;
    }

    private static boolean isWaterImmune(String entityTypeId) {
        return switch (entityTypeId) {
            case "minecraft:drowned", "minecraft:guardian", "minecraft:elder_guardian",
                 "minecraft:squid", "minecraft:glow_squid", "minecraft:axolotl",
                 "minecraft:turtle", "minecraft:dolphin", "minecraft:cod",
                 "minecraft:salmon", "minecraft:tropical_fish", "minecraft:pufferfish",
                 "minecraft:tadpole", "minecraft:frog" -> true;
            default -> false;
        };
    }

    /** Remove {@code owner}'s water boat (if any) and snap them back onto their
     *  grid tile -vanilla dismount offsets X/Z. */
    private void despawnActiveBoat(ServerPlayerEntity owner) {
        if (owner == null) return;
        net.minecraft.entity.vehicle.BoatEntity boat = activeBoats.remove(owner.getUuid());
        if (boat == null) return;
        owner.stopRiding();
        boat.discard();
        if (arena != null && !owner.isRemoved() && !owner.isDisconnected()) {
            GridPos ownerPos = (player != null && owner.getUuid().equals(player.getUuid()))
                ? arena.getPlayerGridPos() : gridPosOf(owner);
            BlockPos correct = arena.gridToBlockPos(ownerPos);
            double correctY = arena.getEntityY(ownerPos);
            owner.setPosition(correct.getX() + 0.5, correctY, correct.getZ() + 0.5);
            owner.networkHandler.requestTeleport(
                correct.getX() + 0.5, correctY, correct.getZ() + 0.5,
                owner.getYaw(), owner.getPitch());
        }
    }

    /** Combat-end cleanup: remove every player's water boat. */
    private void despawnAllBoats() {
        for (ServerPlayerEntity member : new ArrayList<>(allCombatPlayers())) {
            despawnActiveBoat(member);
        }
        // Boats whose owner already left the roster (disconnects) still need discarding.
        for (var leftover : activeBoats.values()) {
            if (leftover != null) leftover.discard();
        }
        activeBoats.clear();
    }

    /**
     * Apply status effects when certain enemy types hit the player.
     */
    private void applyEnemyHitEffect(String entityTypeId) {
        switch (entityTypeId) {
            case "minecraft:wither_skeleton" -> {
                addEffectHooked(CombatEffects.EffectType.WITHER, 3, 0);
                sendMessage("§8  Withered for 3 turns! (damage ramps up)");
            }
            case "minecraft:wither" -> {
                // The Wither boss applies Wither II on every direct hit -the
                // signature mechanic of the boss. Stronger than its minions.
                addEffectHooked(CombatEffects.EffectType.WITHER, 4, 1);
                sendMessage("§8  Withered II for 4 turns! (damage ramps up)");
            }
            case "minecraft:blaze" -> {
                if (!combatEffects.hasFireResistance()) {
                    addEffectHooked(CombatEffects.EffectType.BURNING, 2, 0);
                    sendMessage("§6  You're burning for 2 turns!");
                }
            }
            case "minecraft:husk" -> {
                addEffectHooked(CombatEffects.EffectType.WEAKNESS, 2, 0);
                sendMessage("§7  Weakness applied! (-2 attack for 2 turns)");
                applyPlayerKnockback(currentEnemy.getGridPos(), 1, currentEnemy);
            }
            case "minecraft:vindicator" -> {
                applyPlayerKnockback(currentEnemy.getGridPos(), 2, currentEnemy);
            }
            case "minecraft:stray" -> {
                addEffectHooked(CombatEffects.EffectType.SLOWNESS, 2, 0);
                sendMessage("§b  Slowness applied! (-1 movement for 2 turns)");
            }
            case "minecraft:witch" -> {
                addEffectHooked(CombatEffects.EffectType.POISON, 3, 0);
                sendMessage("§2  Poisoned for 3 turns!");
            }
            case "minecraft:shulker" -> {
                addEffectHooked(CombatEffects.EffectType.SLOWNESS, 2, 0);
                sendMessage("§d  Levitation slows you! (-1 movement for 2 turns)");
            }
            case "minecraft:ghast" -> {
                // Ghast fireball splash: also damages nearby enemies? No -just applies burning
                if (!combatEffects.hasFireResistance()) {
                    addEffectHooked(CombatEffects.EffectType.BURNING, 2, 0);
                    sendMessage("§6  Fireball burns you for 2 turns!");
                }
            }
            case "minecraft:breeze" -> {
                addEffectHooked(CombatEffects.EffectType.SLOWNESS, 1, 0);
                sendMessage("§b  Wind blast pushes you off balance! (-1 movement next turn)");
                // Wind charge gust: shove the player 2 tiles away from the
                // breeze. The full knockback handler also radiates adjacent
                // enemies outward from the player's new tile (8-direction).
                // This used to only fire from dispatchBossSubAction, which
                // the breeze's ranged-attack flow doesn't go through -
                // applyEnemyHitEffect is the path both ranged + melee hits
                // share, so calling it here actually moves the player.
                applyWindChargeKnockback(currentEnemy);
            }
            case "minecraft:ender_dragon" -> {
                addEffectHooked(CombatEffects.EffectType.WEAKNESS, 2, 0);
                sendMessage("§5  Dragon breath weakens you! (-2 attack for 2 turns)");
            }
            case "minecraft:bee" -> {
                addEffectHooked(CombatEffects.EffectType.POISON, 3, 0);
                sendMessage("§2  Bee sting! Poisoned for 3 turns!");
            }
            case "minecraft:llama" -> {
                sendMessage("§a  Splat! Llama spit!");
            }
            default -> {} // no special effect
        }
        // Bee post-attack recoil: stinging the player costs the bee 25% of its
        // max HP every time it attacks, just like the vanilla bee dying after
        // a sting.
        if ("minecraft:bee".equals(entityTypeId) && currentEnemy != null) {
            applyBeeStingRecoil(currentEnemy);
        }
    }

    /**
     * Bees lose 25% of their max HP every time they attack (rounded up, min 1).
     * Models the vanilla "bees die after stinging" mechanic without one-shotting
     * them, since arena bees have boosted HP. Kills the bee if recoil drops it.
     */
    /**
     * Count live allies that belong to {@code owner}. Used to gate spawn-egg
     * summons against the player's party cap. Unowned arena tames count as
     * belonging to the local active player.
     */
    private int countOwnedAllies(ServerPlayerEntity owner) {
        if (owner == null) return 0;
        java.util.UUID ownerId = owner.getUuid();
        int n = 0;
        for (CombatEntity e : enemies) {
            if (!e.isAlive() || !e.isAlly()) continue;
            // Seekers are spell payloads, not party members - they must not eat the
            // pet-affinity party slots a player summons real allies with.
            if (e.isSeekerProjectile()) continue;
            java.util.UUID eOwner = e.getOwnerUuid();
            if (eOwner == null && owner == player) { n++; continue; }
            if (eOwner != null && eOwner.equals(ownerId)) n++;
        }
        return n;
    }

    private void applyBeeStingRecoil(CombatEntity bee) {
        if (bee == null || !bee.isAlive()) return;
        if (!"minecraft:bee".equals(bee.getEntityTypeId())) return;
        int recoil = Math.max(1, (bee.getMaxHp() + 3) / 4);
        bee.takeDamage(recoil);
        if (bee.getMobEntity() != null && player != null
                && player.getEntityWorld() instanceof ServerWorld bw) {
            bw.spawnParticles(net.minecraft.particle.ParticleTypes.DAMAGE_INDICATOR,
                bee.getMobEntity().getX(), bee.getMobEntity().getY() + 0.5,
                bee.getMobEntity().getZ(), 4, 0.2, 0.2, 0.2, 0.02);
        }
        sendMessage("§e  " + bee.getDisplayName() + " loses " + recoil
            + " HP from stinging. (" + bee.getCurrentHp() + "/" + bee.getMaxHp() + ")");
        if (!bee.isAlive()) {
            checkAndHandleDeath(bee);
        }
    }

    private void tickEnemyDone() {
        // Broodmother: consume pending web rain (Hunting Dive phase 2)
        if (currentEnemy != null && currentEnemy.isBoss()) {
            EnemyAI bossAi = resolveAi(currentEnemy);
            if (bossAi instanceof BroodmotherAI bm) {
                List<GridPos> webRain = bm.consumeWebRain();
                if (webRain != null && !webRain.isEmpty()) {
                    placeWebOverlays(webRain, 2);
                    sendMessage("§e  The Broodmother rains webs from the ceiling!");
                }
            }
        }

        // INFINITE MODE: bosses past biome 10/20/... act multiple times per enemy
        // phase. Re-enter DECIDING for the same enemy (index unchanged) until its
        // per-turn action budget is spent; the counter self-resets at phase start.
        if (currentEnemy != null && currentEnemy.isAlive() && currentEnemy.isBoss()
                && phase == CombatPhase.ENEMY_TURN) {
            int totalActions = currentEnemy.getAiMemory("inf_actions_per_turn", 1);
            if (totalActions > 1) {
                int used = currentEnemy.getAiMemory("inf_actions_used", 0) + 1;
                if (used < totalActions) {
                    currentEnemy.setAiMemory("inf_actions_used", used);
                    sendMessage("§5  " + currentEnemy.getDisplayName() + " strikes again! ("
                        + (used + 1) + "/" + totalActions + ")");
                    enemyTurnState = EnemyTurnState.DECIDING;
                    enemyTurnDelay = Math.max(1, CrafticsMod.CONFIG.enemyTurnDelay() / 2);
                    pendingAction = null;
                    currentEnemy = null;
                    return;
                }
                currentEnemy.setAiMemory("inf_actions_used", 0);
            }
        }

        enemyTurnIndex++;
        enemyTurnState = EnemyTurnState.DECIDING;
        enemyTurnDelay = Math.max(1, CrafticsMod.CONFIG.enemyTurnDelay() / 2);
        pendingAction = null;
        currentEnemy = null;
    }

    /**
     * Locate a Totem of Undying anywhere on the player. Hand slots are checked
     * first to match vanilla totem priority; the rest of the inventory is
     * scanned afterward so a totem placed in the hotbar/main/armor slots still
     * saves the player. Returns the live stack reference (not a copy) so the
     * caller can decrement it directly. {@code null} if no totem is held.
     */
    private net.minecraft.item.ItemStack findTotemStack() {
        net.minecraft.item.ItemStack mainHand = player.getMainHandStack();
        if (!mainHand.isEmpty() && isAnyTotem(mainHand.getItem())) {
            return mainHand;
        }
        net.minecraft.item.ItemStack offHand = player.getOffHandStack();
        if (!offHand.isEmpty() && isAnyTotem(offHand.getItem())) {
            return offHand;
        }
        var inv = player.getInventory();
        for (int i = 0; i < inv.size(); i++) {
            net.minecraft.item.ItemStack stack = inv.getStack(i);
            if (!stack.isEmpty() && isAnyTotem(stack.getItem())) {
                return stack;
            }
        }
        return null;
    }

    /** Vanilla Totem of Undying or any MoreTotems totem. */
    private static boolean isAnyTotem(net.minecraft.item.Item item) {
        return item == Items.TOTEM_OF_UNDYING
            || com.crackedgames.craftics.compat.moretotems.MoreTotemsCompat.isMoreTotem(item);
    }

    /**
     * Consume a Totem of Undying and resurrect the player. Returns {@code true}
     * if a totem was consumed (death should be skipped), {@code false} if the
     * player has no totem.
     *
     * <p>Order is important: the totem is decremented <em>before</em> any other
     * side effects, so an exception in particle/sound rendering can never
     * leave the player half-resurrected with the totem still in hand. Status
     * effects are cleared first (matches vanilla behavior) so lingering
     * Wither/Poison from the killing blow can't chain-kill the resurrected
     * player on the next tick.
     */
    /**
     * Last-resort totem hook for damage Craftics never metered: a vanilla source (an explosion,
     * fire, fall damage, a boss's real-entity attack) that would kill the player outright.
     *
     * <p>{@code damagePlayer} clamps HP to 1 so the turn-based flow can never kill, and every
     * death route it owns checks the totem. But nothing was watching vanilla damage - so a boss
     * one-shot could take the player from full HP to dead without the totem ever being asked.
     * {@code PlayerDeathTotemMixin} calls this from {@code LivingEntity.damage} just before the
     * blow would land lethally, and cancels the damage when a totem is spent.
     *
     * @param deathBlow the player is about to die from a source Craftics didn't route
     * @return true when a totem was consumed and the death must be cancelled
     */
    /**
     * True while the arena is still settling after combat start. Damage taken in this window is
     * an artifact of the arena not being built yet (the player is falling through air that has
     * no floor under it yet), so it must not kill anyone or spend a totem - the mixin swallows
     * it outright instead.
     */
    public boolean isArenaSettling() {
        // Deliberately the TIMER only, not "is the floor missing?". A boss that destroys terrain
        // can legitimately delete the start tile's floor mid-fight, and keying invulnerability on
        // that would make the whole party immortal for the rest of the fight - far worse than the
        // bug this guards. The floor probe is used to EXTEND the grace window (below), never to
        // re-open it once the fight is genuinely underway.
        return active && fallDeathGraceTicks > 0;
    }

    public boolean tryTotemAgainstLethalDamage(ServerPlayerEntity victim) {
        if (!active || victim == null) return false;
        // Retarget onto the victim: `player` is the current TURN holder, and in a party the
        // one taking a vanilla hit may be someone else entirely. Consuming the turn-holder's
        // totem to save a different player would be a real bug.
        ServerPlayerEntity saved = this.player;
        try {
            this.player = victim;
            return tryConsumeTotemAndResurrect();
        } finally {
            this.player = saved;
        }
    }

    private boolean tryConsumeTotemAndResurrect() {
        net.minecraft.item.ItemStack totem = findTotemStack();
        if (totem == null) return false;

        String moddedPath = com.crackedgames.craftics.compat.moretotems.MoreTotemsCompat.totemPath(totem.getItem());
        if (moddedPath != null) {
            return consumeModdedTotem(totem, moddedPath);
        }

        totem.decrement(1);

        // Vanilla parity: clear all status effects, then re-apply totem buffs.
        player.clearStatusEffects();
        player.setAbsorptionAmount(0f);

        float halfMax = Math.max(1.0f, player.getMaxHealth() / 2.0f);
        player.setHealth(halfMax);

        // Combat-only regeneration: the vanilla effect heals in real time, which would let a
        // resurrected player tick their HP back between turns and quietly undo the turn-based
        // damage economy. The combat effect heals a little at the start of each of their turns.
        combatEffects.addEffect(CombatEffects.EffectType.REGENERATION, 5, 1);
        player.addStatusEffect(new net.minecraft.entity.effect.StatusEffectInstance(
            net.minecraft.entity.effect.StatusEffects.ABSORPTION, 100, 1));
        player.addStatusEffect(new net.minecraft.entity.effect.StatusEffectInstance(
            net.minecraft.entity.effect.StatusEffects.FIRE_RESISTANCE, 800, 0));

        // Visual + audio feedback. Wrapped so a particle/sound failure can't
        // block the resurrection -the player must always be saved if a totem
        // was consumed.
        try {
            ServerWorld world = (ServerWorld) player.getEntityWorld();
            world.spawnParticles(net.minecraft.particle.ParticleTypes.TOTEM_OF_UNDYING,
                player.getX(), player.getY() + 1.0, player.getZ(),
                100, 0.6, 1.0, 0.6, 0.5);
            world.playSound(null, player.getBlockPos(),
                net.minecraft.sound.SoundEvents.ITEM_TOTEM_USE,
                net.minecraft.sound.SoundCategory.PLAYERS, 1.0f, 1.0f);
        } catch (Exception ignored) {
        }

        sendMessage("\u00a76\u00a7l\u2726 TOTEM OF UNDYING ACTIVATES! \u2726 \u00a7rResurrected with half health!");
        achievementTracker.recordTotemProc();
        sendSync();
        return true;
    }

    /**
     * Consume a MoreTotems totem and resurrect with a BARE revive (clear effects + 50% HP),
     * then run the totem's unique Craftics effect. Decrement happens first so a render
     * failure can never leave the player un-revived (matches the vanilla method's ordering).
     */
    private boolean consumeModdedTotem(net.minecraft.item.ItemStack totem, String path) {
        totem.decrement(1);

        // Bare revive: clear effects + zero absorption + 50% HP. No vanilla buff baseline.
        player.clearStatusEffects();
        player.setAbsorptionAmount(0f);
        float halfMax = Math.max(1.0f, player.getMaxHealth() / 2.0f);
        player.setHealth(halfMax);

        String label;
        switch (path) {
            case com.crackedgames.craftics.compat.moretotems.MoreTotemsCompat.EXPLOSIVE -> {
                label = "Explosive Totem";
                totemExplosion();
            }
            case com.crackedgames.craftics.compat.moretotems.MoreTotemsCompat.SKELETAL -> {
                label = "Skeletal Totem";
                totemMarkAllEnemies(2);
            }
            case com.crackedgames.craftics.compat.moretotems.MoreTotemsCompat.TELEPORTING -> {
                label = "Teleporting Totem";
                totemTeleportToSafestTile();
            }
            case com.crackedgames.craftics.compat.moretotems.MoreTotemsCompat.GHASTLY -> {
                label = "Ghastly Totem";
                totemBurnAllEnemiesAndFireRes(5);
            }
            case com.crackedgames.craftics.compat.moretotems.MoreTotemsCompat.STINGING -> {
                label = "Stinging Totem";
                totemSummonAllies(net.minecraft.entity.EntityType.BEE, 5);
            }
            case com.crackedgames.craftics.compat.moretotems.MoreTotemsCompat.TENTACLED -> {
                label = "Tentacled Totem";
                totemBlindAllEnemies(2);
            }
            case com.crackedgames.craftics.compat.moretotems.MoreTotemsCompat.ROTTING -> {
                label = "Rotting Totem";
                totemSummonAllies(net.minecraft.entity.EntityType.ZOMBIE, 3);
            }
            default -> label = "Totem";
        }

        try {
            ServerWorld world = (ServerWorld) player.getEntityWorld();
            world.spawnParticles(net.minecraft.particle.ParticleTypes.TOTEM_OF_UNDYING,
                player.getX(), player.getY() + 1.0, player.getZ(),
                100, 0.6, 1.0, 0.6, 0.5);
            world.playSound(null, player.getBlockPos(),
                net.minecraft.sound.SoundEvents.ITEM_TOTEM_USE,
                net.minecraft.sound.SoundCategory.PLAYERS, 1.0f, 1.0f);
        } catch (Exception ignored) {
        }

        sendMessage("\u00a76\u00a7l\u2726 " + label.toUpperCase() + " ACTIVATES! \u2726 \u00a7rResurrected with half health!");
        achievementTracker.recordTotemProc();
        sendSync();
        return true;
    }

    // \u2500\u2500 MoreTotems effect helpers \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500

    /** Explosive totem: 4x4 around the player, each enemy takes 50% max HP + biome ordinal. */
    private void totemExplosion() {
        GridPos center = arena.getPlayerGridPos();
        ServerWorld sw = (ServerWorld) player.getEntityWorld();
        try {
            BlockPos bp = arena.gridToBlockPos(center);
            sw.playSound(null, bp, net.minecraft.sound.SoundEvents.ENTITY_GENERIC_EXPLODE.value(),
                net.minecraft.sound.SoundCategory.PLAYERS, 1.0f, 1.0f);
        } catch (Exception ignored) {}
        // 4x4 block anchored so the player tile is the inner corner: dx,dz in -1..2.
        outer:
        for (int dx = -1; dx <= 2; dx++) {
            for (int dz = -1; dz <= 2; dz++) {
                GridPos pos = new GridPos(center.x() + dx, center.z() + dz);
                if (!arena.isInBounds(pos)) continue;
                CombatEntity target = arena.getOccupant(pos);
                if (target == null || !target.isAlive() || target.isAlly()) continue;
                int dmg = MoreTotemsEffects.explosionDamage(target.getMaxHp(), currentBiomeOrdinal);
                int actual = target.takeDamage(dmg);
                sendMessage("\u00a7c\u2726 Explosion hits " + target.getDisplayName() + " for " + actual + "!");
                checkAndHandleDeath(target);
                if (!active) break outer; // last enemy died \u2014 combat already ended
            }
        }
        refreshHighlights();
    }

    /** Skeletal totem: mark every living enemy for the given turns. */
    private void totemMarkAllEnemies(int turns) {
        int n = 0;
        for (CombatEntity e : enemies) {
            if (!e.isAlive() || e.isAlly()) continue;
            e.setMarkedTurns(Math.max(e.getMarkedTurns(), turns));
            n++;
        }
        sendMessage("\u00a7e\u2726 " + n + " enemies are Marked for " + turns + " turns!");
    }

    /** Tentacled totem: blind every living enemy for the given turns. */
    private void totemBlindAllEnemies(int turns) {
        int n = 0;
        for (CombatEntity e : enemies) {
            if (!e.isAlive() || e.isAlly()) continue;
            e.stackBlinded(turns);
            n++;
        }
        sendMessage("\u00a79\u2726 " + n + " enemies are Blinded for " + turns + " turns!");
    }

    /** Ghastly totem: set every living enemy on fire, grant the player Fire Resistance. */
    private void totemBurnAllEnemiesAndFireRes(int turns) {
        // Burning I. This was a per-turn damage number before the amplifier slot meant a level.
        int burnAmp = 0;
        int n = 0;
        for (CombatEntity e : enemies) {
            if (!e.isAlive() || e.isAlly()) continue;
            e.stackBurning(turns, burnAmp);
            n++;
        }
        addEffectHooked(CombatEffects.EffectType.FIRE_RESISTANCE, turns, 0);
        sendMessage("\u00a76\u2726 " + n + " enemies set ablaze for " + turns + " turns! You gain Fire Resistance.");
    }

    /** Teleporting totem: move the player to the tile farthest from the nearest enemy. */
    private void totemTeleportToSafestTile() {
        java.util.List<GridPos> candidates = new java.util.ArrayList<>();
        GridPos cur = arena.getPlayerGridPos();
        for (int x = 0; x < arena.getWidth(); x++) {
            for (int z = 0; z < arena.getHeight(); z++) {
                GridPos p = new GridPos(x, z);
                if (arena.isOccupied(p) && !p.equals(cur)) continue;
                GridTile t = arena.getTile(p);
                if (t == null || !t.isSafeForSpawn()) continue;
                candidates.add(p);
            }
        }
        java.util.List<GridPos> enemyPositions = new java.util.ArrayList<>();
        for (CombatEntity e : enemies) {
            if (e.isAlive() && !e.isAlly()) enemyPositions.add(e.getGridPos());
        }
        GridPos dest = MoreTotemsEffects.safestTile(candidates, enemyPositions);
        if (dest == null || dest.equals(cur)) return; // no better tile \u2014 stay put
        arena.setPlayerGridPos(dest);
        BlockPos bp = arena.gridToBlockPos(dest);
        //? if <=1.21.1 {
        player.teleport((ServerWorld) player.getEntityWorld(),
            bp.getX() + 0.5, bp.getY(), bp.getZ() + 0.5,
            java.util.Collections.emptySet(), player.getYaw(), 0f);
        //?} else {
        /*player.teleport((ServerWorld) player.getEntityWorld(),
            bp.getX() + 0.5, bp.getY(), bp.getZ() + 0.5,
            java.util.Collections.emptySet(), player.getYaw(), 0f, true);
        *///?}
        sendMessage("\u00a7d\u2726 Teleported to safety!");
    }

    /**
     * Summon {@code count} temporary allied mobs of the given type near the player. Bypasses
     * AP and the party cap (this is a revive bonus, not a player action). Best-effort: any mob
     * that can't be placed is skipped.
     */
    private void totemSummonAllies(net.minecraft.entity.EntityType<?> entityType, int count) {
        ServerWorld world = (ServerWorld) player.getEntityWorld();
        String typeId = net.minecraft.registry.Registries.ENTITY_TYPE.getId(entityType).toString();
        com.crackedgames.craftics.api.registry.AllyEntry entry =
            com.crackedgames.craftics.api.registry.AllyRegistry.getOrNull(typeId);
        int hp, atk, def, range;
        if (entry != null) {
            hp = entry.hp(); atk = entry.attack(); def = entry.defense(); range = entry.range();
        } else {
            hp = 8; atk = 2; def = 0; range = 1;
        }
        hp += computeAllyPetHpBonus(typeId, player.getUuid());

        java.util.Set<GridPos> reserved = new java.util.HashSet<>();
        for (CombatEntity e : enemies) {
            if (e.isAlive()) reserved.add(e.getGridPos());
        }
        reserved.add(arena.getPlayerGridPos());

        int spawned = 0;
        for (int i = 0; i < count; i++) {
            GridPos tile = findNearestWalkableUnreserved(arena, arena.getPlayerGridPos(), reserved);
            if (tile == null) break;
            reserved.add(tile);

            BlockPos blockPos = arena.gridToBlockPos(tile);
            net.minecraft.entity.Entity rawEntity = entityType.create(world, null, blockPos,
                net.minecraft.entity.SpawnReason.MOB_SUMMONED, false, false);
            if (!(rawEntity instanceof net.minecraft.entity.mob.MobEntity mob)) continue;
            mob.refreshPositionAndAngles(
                blockPos.getX() + 0.5, blockPos.getY(), blockPos.getZ() + 0.5, 0, 0);
            mob.setPersistent();
            mob.setAiDisabled(true);
            mob.setInvulnerable(true);
            mob.setNoGravity(true);
            mob.noClip = true;
            mob.setSilent(true);
            mob.addCommandTag("craftics_arena");
            world.spawnEntity(mob);

            CombatEntity ce = new CombatEntity(mob.getId(), typeId, tile, hp, atk, def, range);
            ce.setAlly(true);
            ce.setTemporaryAlly(true);
            ce.setOwnerUuid(player.getUuid());
            ce.setMobEntity(mob);
            ce.setAllyAi(com.crackedgames.craftics.combat.ai.ally.AllyArchetypes.aiFor(typeId));
            enemies.add(ce);
            arena.placeEntity(ce);
            spawned++;
        }
        sendMessage("\u00a7a\u2726 " + spawned + " allies rise to defend you!");
        refreshHighlights();
    }

    /**
     * Called when the active player's HP reaches 0. In a party, the dead player
     * becomes a spectator and combat continues with the next alive member.
     * Only triggers a full game over when ALL party members are dead (or solo play).
     */
    private void handlePlayerDeathOrGameOver() {
        // Totem of Undying: save the player from downing/death entirely.
        if (tryConsumeTotemAndResurrect()) {
            return;
        }

        // Solo play or no party → start death animation before game over
        if (partyPlayers.size() <= 1) {
            startPlayerDeathAnimation();
            return;
        }

        // Mark current player as dead
        deadPartyMembers.add(player.getUuid());
        player.setHealth(1); // keep at clamp threshold (avoids vanilla death screen)

        // --- Downed animation: distinct from death (shorter, different effects) ---
        // Downed sound: player hurt + anvil thud (not wither sounds like death)
        ServerWorld downedWorld = (ServerWorld) player.getEntityWorld();
        player.getWorld().playSound(null, player.getBlockPos(),
            net.minecraft.sound.SoundEvents.ENTITY_PLAYER_HURT,
            net.minecraft.sound.SoundCategory.PLAYERS, 1.0f, 0.7f);
        player.getWorld().playSound(null, player.getBlockPos(),
            net.minecraft.sound.SoundEvents.BLOCK_ANVIL_LAND,
            net.minecraft.sound.SoundCategory.PLAYERS, 0.4f, 0.5f);

        // Downed particles: red dust + damage indicator (NOT soul particles like death)
        downedWorld.spawnParticles(net.minecraft.particle.ParticleTypes.DAMAGE_INDICATOR,
            player.getX(), player.getY() + 1.0, player.getZ(),
            8, 0.3, 0.5, 0.3, 0.02);
        //? if <=1.21.1 {
        downedWorld.spawnParticles(
            new net.minecraft.particle.DustParticleEffect(
                new org.joml.Vector3f(1.0f, 0.2f, 0.2f), 1.5f),
            player.getX(), player.getY() + 0.5, player.getZ(),
            12, 0.4, 0.3, 0.4, 0.01);
        //?} else {
        /*downedWorld.spawnParticles(
            new net.minecraft.particle.DustParticleEffect(0xFF3333, 1.5f),
            player.getX(), player.getY() + 0.5, player.getZ(),
            12, 0.4, 0.3, 0.4, 0.01);
        *///?}

        // Send downed event to client (orange vignette, different from red death vignette)
        sendToAllParty(new CombatEventPayload(
            CombatEventPayload.EVENT_PLAYER_DOWNED, 0, 0, 0, 0, 0));

        player.changeGameMode(net.minecraft.world.GameMode.SPECTATOR);
        sendMessage("§c§l☠ " + player.getName().getString() + " has fallen!");

        // Find next alive party member
        ServerPlayerEntity nextAlive = null;
        for (ServerPlayerEntity member : partyPlayers) {
            if (!deadPartyMembers.contains(member.getUuid())
                    && member != null && !member.isRemoved() && !member.isDisconnected()) {
                nextAlive = member;
                break;
            }
        }

        if (nextAlive == null) {
            // Everyone dead → start death animation before game over
            startPlayerDeathAnimation();
            return;
        }

        // Transfer combat control to next alive member. We deliberately do NOT
        // teleport them to the dying player's spot -they're standing on their
        // own arena tile and the previous "snap to the corpse" behavior was
        // making the survivor jump onto where their teammate just died for no
        // gameplay benefit (it broke positioning in turn-based combat).
        sendMessage("§e" + nextAlive.getName().getString() + " takes over the fight!");
        // Drop the dead player from the positional turn queue so the survivors
        // don't get a free double-turn this round (the queue is rotated by index,
        // and switchToTurnPlayer only skipped removed/disconnected, not dead).
        pruneDeadFromTurnQueue(player.getUuid());
        this.player = nextAlive;
        retargetEffectsToCurrentPlayer();

        // Recalculate stats for the new active player
        PlayerProgression prog = PlayerProgression.get((ServerWorld) player.getEntityWorld());
        PlayerProgression.PlayerStats pStats = prog.getStats(player);
        this.apRemaining = pStats.getEffective(PlayerProgression.Stat.AP)
            + PlayerCombatStats.getSetApBonus(player);
        this.movePointsRemaining = pStats.getEffective(PlayerProgression.Stat.SPEED)
            + PlayerCombatStats.getSetSpeedBonus(player);
        this.activeTrimScan = TrimEffects.scan(player);
        this.activeCombatEffects = activeTrimScan.getCombatEffects();
        if (effectContext != null) effectContext.update(player, arena, combatEffects, activeTrimScan);

        sendSync();
        refreshHighlights();
    }

    /**
     * Begin the player death animation sequence. Freezes combat, plays dramatic
     * effects (sound, particles, camera event) over PLAYER_DEATH_ANIM_TICKS,
     * then transitions to the real handleGameOver().
     */
    private void startPlayerDeathAnimation() {
        phase = CombatPhase.PLAYER_DYING;
        playerDeathAnimTick = 0;

        // Clamp player health so vanilla death screen doesn't trigger
        player.setHealth(1);

        // Death sound -deep bass hit
        player.getWorld().playSound(null, player.getBlockPos(),
            net.minecraft.sound.SoundEvents.ENTITY_PLAYER_DEATH,
            net.minecraft.sound.SoundCategory.PLAYERS, 1.0f, 0.5f);

        // Send death event to client for screen effects (red vignette, camera drop)
        sendToAllParty(new CombatEventPayload(
            CombatEventPayload.EVENT_COMBAT_LOST, 0, PLAYER_DEATH_ANIM_TICKS, 0, 0, 0));

        sendMessage("§c§l☠ You have fallen...");
    }

    private void tickPlayerDying() {
        playerDeathAnimTick++;

        ServerWorld world = (ServerWorld) player.getEntityWorld();

        // Tick 1-15: rising soul particles from player
        if (playerDeathAnimTick <= 15 && playerDeathAnimTick % 3 == 0) {
            world.spawnParticles(net.minecraft.particle.ParticleTypes.SOUL,
                player.getX(), player.getY() + 1.0, player.getZ(),
                5, 0.3, 0.5, 0.3, 0.02);
        }

        // Tick 10: secondary death echo sound
        if (playerDeathAnimTick == 10) {
            player.getWorld().playSound(null, player.getBlockPos(),
                net.minecraft.sound.SoundEvents.ENTITY_WITHER_HURT,
                net.minecraft.sound.SoundCategory.PLAYERS, 0.4f, 0.3f);
        }

        // Tick 20-40: smoke/ash particles (body fading)
        if (playerDeathAnimTick >= 20 && playerDeathAnimTick <= 40 && playerDeathAnimTick % 4 == 0) {
            world.spawnParticles(net.minecraft.particle.ParticleTypes.LARGE_SMOKE,
                player.getX(), player.getY() + 0.5, player.getZ(),
                8, 0.4, 0.3, 0.4, 0.01);
        }

        // Tick 45: defeat sting
        if (playerDeathAnimTick == 45) {
            player.getWorld().playSound(null, player.getBlockPos(),
                net.minecraft.sound.SoundEvents.ENTITY_WITHER_DEATH,
                net.minecraft.sound.SoundCategory.PLAYERS, 0.5f, 0.5f);
        }

        // Animation complete → proceed to actual game over logic
        if (playerDeathAnimTick >= PLAYER_DEATH_ANIM_TICKS) {
            handleGameOver();
        }
    }

    /**
     * Pre-roll the death-loss outcome for every losable item this player carries,
     * WITHOUT mutating the inventory. Returns an empty list (caller falls back to
     * the legacy synchronous path) when the player is death-protected or is not in
     * a biome run past level 1, or when there is nothing losable. Exempt items
     * (Move feather, Guide Book) are skipped entirely.
     */
    /** One slot before grouping: its stack, its per-unit loss chance, and how many
     *  of its units rolled "lost". */
    private record RawSlotRoll(int kind, int index, String accContainer, int accKind, int accSlot,
                               ItemStack stack, int lost) {}

    private java.util.List<PendingItemRoll> rollGameOverLoss(ServerPlayerEntity p,
                                                             CrafticsSavedData.PlayerData ld) {
        java.util.List<PendingItemRoll> rolls = new java.util.ArrayList<>();
        // Protected players keep everything - no flip.
        if (DeathProtectionComponent.hasRecoveryCompass(p)
                && DeathProtectionComponent.protectCombatInventory(p)) {
            return rolls;
        }
        // Any biome-run death uses the per-item coin-flip (level 1 included).
        if (!ld.isInBiomeRun()) return rolls;

        double mainLoss = CrafticsMod.CONFIG.deathMainInventoryLossChance();
        double gearLoss = CrafticsMod.CONFIG.deathGearLossChance();
        int luck = PlayerProgression.get((ServerWorld) p.getEntityWorld())
            .getStats(p).getPoints(PlayerProgression.Stat.LUCK);
        double gearEff = Math.max(MIN_LOSS_CHANCE, gearLoss - LUCK_KEEP_PER_POINT * luck);
        double mainEff = Math.max(MIN_LOSS_CHANCE, mainLoss - LUCK_KEEP_PER_POINT * luck);

        // Roll each physical slot at its own rate, per UNIT in the stack.
        java.util.List<RawSlotRoll> raw = new java.util.ArrayList<>();
        // Main + hotbar 36 slots (hotbar < 9 = gear rate, backpack >= 9 = main rate).
        int mainSlots = Math.min(36, p.getInventory().size());
        for (int slot = 0; slot < mainSlots; slot++) {
            ItemStack stack = p.getInventory().getStack(slot);
            if (stack.isEmpty()) continue;
            Item item = stack.getItem();
            if (item == com.crackedgames.craftics.item.ModItems.MOVE_ITEM
                    || item instanceof com.crackedgames.craftics.item.GuideBookItem) continue;
            int lost = rollUnitsLost(stack.getCount(), slot < 9 ? gearEff : mainEff);
            raw.add(new RawSlotRoll(0, slot, null, 0, 0, stack.copy(), lost));
        }
        // Armor (4 slots) at gear rate.
        //? if <=1.21.4 {
        for (int slot = 0; slot < p.getInventory().armor.size(); slot++) {
            ItemStack stack = p.getInventory().armor.get(slot);
            if (stack.isEmpty()) continue;
            raw.add(new RawSlotRoll(1, slot, null, 0, 0, stack.copy(),
                rollUnitsLost(stack.getCount(), gearEff)));
        }
        //?} else {
        /*net.minecraft.entity.EquipmentSlot[] armorSlots = {
                net.minecraft.entity.EquipmentSlot.HEAD, net.minecraft.entity.EquipmentSlot.CHEST,
                net.minecraft.entity.EquipmentSlot.LEGS, net.minecraft.entity.EquipmentSlot.FEET};
        for (int slot = 0; slot < armorSlots.length; slot++) {
            ItemStack stack = p.getEquippedStack(armorSlots[slot]);
            if (stack.isEmpty()) continue;
            raw.add(new RawSlotRoll(1, slot, null, 0, 0, stack.copy(),
                rollUnitsLost(stack.getCount(), gearEff)));
        }
        *///?}
        // Offhand at gear rate.
        ItemStack off = p.getOffHandStack();
        if (!off.isEmpty()) {
            raw.add(new RawSlotRoll(2, 0, null, 0, 0, off.copy(),
                rollUnitsLost(off.getCount(), gearEff)));
        }
        // Accessories (Artifacts trinkets) at gear rate, enumerated per slot.
        for (com.crackedgames.craftics.compat.artifacts.AccessoriesReflect.AccessorySnapshot snap :
                com.crackedgames.craftics.compat.artifacts.AccessoriesReflect.saveAccessories(p)) {
            raw.add(new RawSlotRoll(3, 0, snap.container(), snap.kind(), snap.slot(),
                snap.stack().copy(), rollUnitsLost(snap.stack().getCount(), gearEff)));
        }

        // Group identical item-types (same item + components) across all slots into
        // one display entry: total quantity, summed lost quantity, and the per-slot
        // removals to apply. Insertion order preserved for a stable grid.
        for (RawSlotRoll rs : raw) {
            PendingItemRoll group = null;
            for (PendingItemRoll g : rolls) {
                if (ItemStack.areItemsAndComponentsEqual(g.repr(), rs.stack())) { group = g; break; }
            }
            SlotLoss sl = new SlotLoss(rs.kind(), rs.index(), rs.accContainer(), rs.accKind(),
                rs.accSlot(), rs.lost());
            if (group == null) {
                java.util.List<SlotLoss> slots = new java.util.ArrayList<>();
                slots.add(sl);
                ItemStack repr = rs.stack().copy();
                repr.setCount(rs.stack().getCount());
                rolls.add(new PendingItemRoll(repr, rs.stack().getCount(), rs.lost(), slots));
            } else {
                group.slots().add(sl);
                // records are immutable; replace with an updated total/lost. The repr
                // stack carries the merged total purely for the client display.
                int idx = rolls.indexOf(group);
                int newTotal = group.totalQ() + rs.stack().getCount();
                ItemStack repr = group.repr().copy();
                repr.setCount(Math.min(9999, newTotal));
                rolls.set(idx, new PendingItemRoll(repr, newTotal, group.lostQ() + rs.lost(), group.slots()));
            }
        }
        return rolls;
    }

    /** Roll {@code count} independent units at {@code lossChance} each; return how
     *  many were lost. */
    private static int rollUnitsLost(int count, double lossChance) {
        int lost = 0;
        for (int i = 0; i < count; i++) if (Math.random() < lossChance) lost++;
        return lost;
    }

    private void handleGameOver() {
        phase = CombatPhase.GAME_OVER;
        lastXpLevelsLost.clear();
        // Sound: defeat
        if (player != null) {
            player.getWorld().playSound(null, player.getBlockPos(),
                net.minecraft.sound.SoundEvents.ENTITY_WITHER_DEATH,
                net.minecraft.sound.SoundCategory.PLAYERS, 0.5f, 0.5f);
        }
        sendMessage("§c§l*** DEFEATED ***");

        ServerWorld world = (ServerWorld) player.getEntityWorld();
        CrafticsSavedData data = CrafticsSavedData.get(world);
        CrafticsSavedData.PlayerData ld = data.getPlayerData(leaderUuid != null ? leaderUuid : player.getUuid());

        // HARDCORE ISLAND: full-party defeat = total wipe. Takes precedence over
        // the infinite-mode and permadeath flows; no emerald/XP penalties and no
        // coin-flip item screen - everything is gone regardless.
        java.util.UUID hcOwner = leaderUuid != null ? leaderUuid : player.getUuid();
        if (com.crackedgames.craftics.world.HardcoreIslands.isHardcore(world.getServer(), hcOwner)) {
            finishHardcoreTeardown(hcOwner, ld);
            return;
        }

        // INFINITE MODE: a wipe just ends the run. No emerald/XP/item death
        // penalties - the run items evaporate with the stash restore, emeralds
        // and the banked best score are kept.
        if (ld.infiniteActive) {
            java.util.UUID infHost = leaderUuid != null ? leaderUuid : player.getUuid();
            finishGameOverTeardown();
            InfiniteRunManager.endRun(world.getServer(), infHost, "the party fell");
            return;
        }

        // Permadeath mode: lose ALL emeralds and reset biome progress
        if (CrafticsMod.CONFIG.permadeathMode()) {
            int allEmeralds = ld.emeralds;
            if (allEmeralds > 0) ld.spendEmeralds(allEmeralds);
            ld.highestBiomeUnlocked = 1;
            sendMessage("§4§lPERMADEATH: All progress lost!");
        }

        // Death penalty: lose 50% emeralds
        int emeraldLoss = CrafticsMod.CONFIG.permadeathMode() ? 0 : ld.emeralds / 2;
        if (emeraldLoss > 0) {
            ld.spendEmeralds(emeraldLoss);
            sendMessage("§cLost " + emeraldLoss + " emeralds!");
        }

        // Death penalty: lose XP levels
        for (ServerPlayerEntity p : getAllParticipants()) {
            int levels = p.experienceLevel;
            if (levels > 0) {
                int lost = Math.max(1, levels / 2);
                p.addExperienceLevels(-lost);
                lastXpLevelsLost.put(p.getUuid(), lost);
                sendMessageTo(p, "§cLost " + lost + " XP level" + (lost != 1 ? "s" : "") + "!");
            }
        }

        // Per-player item loss. Eligible players (biome run past level 1, not
        // death-protected, with losable items) defer to the coin-flip screen; the
        // rest take the legacy synchronous path immediately.
        pendingGameOverLoss.clear();
        gameOverAcks.clear();
        gameOverWaiting.clear();
        boolean anyFlip = false;
        for (ServerPlayerEntity p : getAllParticipants()) {
            java.util.List<PendingItemRoll> rolls = rollGameOverLoss(p, ld);
            if (rolls.isEmpty()) {
                applyLegacyGameOverLoss(p, ld); // protected / level-1 / nothing losable
                continue;
            }
            pendingGameOverLoss.put(p.getUuid(), rolls);
            gameOverWaiting.add(p.getUuid());
            anyFlip = true;
            // Build the parallel lists for the payload: one entry per grouped item,
            // its representative stack (count = total owned) and how many units of
            // it are lost.
            java.util.List<ItemStack> items = new java.util.ArrayList<>();
            java.util.List<Integer> lostCounts = new java.util.ArrayList<>();
            for (PendingItemRoll r : rolls) {
                items.add(r.repr());
                lostCounts.add(r.lostQ());
            }
            int pXpLost = lastXpLevelsLost.getOrDefault(p.getUuid(), 0);
            ServerPlayNetworking.send(p, new com.crackedgames.craftics.network.GameOverItemsPayload(
                items, lostCounts, emeraldLoss, pXpLost));
        }

        if (anyFlip) {
            // Hold here; clients animate, then ack. tickGameOverFlip applies the
            // loss + teardown on all-acked or on timeout.
            phase = CombatPhase.GAME_OVER_FLIP;
            gameOverFlipTimer = GAME_OVER_FLIP_TIMEOUT;
            return;
        }
        // Nobody flips - fall through to the existing heal/teleport/endCombat teardown below.
        finishGameOverTeardown();
    }

    /** The original synchronous death-loss for one player: recovery-compass save,
     *  past-level-1 probabilistic per-slot loss, or level-1 single-item loss.
     *  Used for players who do not get the coin-flip screen. */
    private void applyLegacyGameOverLoss(ServerPlayerEntity p, CrafticsSavedData.PlayerData ld) {
            if (DeathProtectionComponent.hasRecoveryCompass(p)
                && DeathProtectionComponent.protectCombatInventory(p)) {
                // Particles + sound for recovery compass activation
                ServerWorld compassWorld = (ServerWorld) p.getEntityWorld();
                compassWorld.spawnParticles(net.minecraft.particle.ParticleTypes.SOUL,
                    p.getX(), p.getY() + 1.0, p.getZ(),
                    40, 0.5, 0.8, 0.5, 0.02);
                compassWorld.spawnParticles(net.minecraft.particle.ParticleTypes.END_ROD,
                    p.getX(), p.getY() + 1.5, p.getZ(),
                    25, 0.4, 0.6, 0.4, 0.05);
                p.getWorld().playSound(null, p.getBlockPos(),
                    net.minecraft.sound.SoundEvents.BLOCK_RESPAWN_ANCHOR_CHARGE,
                    net.minecraft.sound.SoundCategory.PLAYERS, 1.0f, 1.2f);
                sendMessageTo(p, "\u00a76\u00a7l\u2728 Recovery Compass activated! \u00a7rYour inventory was saved.");
                return;
            }
            if (ld.isInBiomeRun() && ld.activeBiomeLevelIndex > 0) {
                // Past level 1: probabilistic loss. Backpack (main inventory) items are very
                // likely to be lost; hotbar, armor, offhand and accessories are far more likely
                // to survive. Both rates are config-tunable.
                double mainLoss = CrafticsMod.CONFIG.deathMainInventoryLossChance();
                double gearLoss = CrafticsMod.CONFIG.deathGearLossChance();
                int itemsLost = 0;
                // Iterate only the 36 main+hotbar slots (0-8 hotbar, 9-35 backpack); armor and
                // offhand are handled separately below so they never get rolled twice.
                int mainSlots = Math.min(36, p.getInventory().size());
                for (int slot = 0; slot < mainSlots; slot++) {
                    ItemStack stack = p.getInventory().getStack(slot);
                    if (stack.isEmpty()) continue;
                    Item item = stack.getItem();
                    if (item == com.crackedgames.craftics.item.ModItems.MOVE_ITEM || item instanceof com.crackedgames.craftics.item.GuideBookItem) continue;
                    double loss = slot < 9 ? gearLoss : mainLoss; // hotbar vs backpack
                    if (Math.random() < loss) {
                        p.getInventory().setStack(slot, ItemStack.EMPTY);
                        itemsLost++;
                    }
                }
                //? if <=1.21.4 {
                for (int slot = 0; slot < p.getInventory().armor.size(); slot++) {
                    if (!p.getInventory().armor.get(slot).isEmpty() && Math.random() < gearLoss) {
                        p.getInventory().armor.set(slot, ItemStack.EMPTY);
                        itemsLost++;
                    }
                }
                //?} else {
                /*for (net.minecraft.entity.EquipmentSlot armorSlot : new net.minecraft.entity.EquipmentSlot[]{
                        net.minecraft.entity.EquipmentSlot.HEAD, net.minecraft.entity.EquipmentSlot.CHEST,
                        net.minecraft.entity.EquipmentSlot.LEGS, net.minecraft.entity.EquipmentSlot.FEET}) {
                    if (!p.getEquippedStack(armorSlot).isEmpty() && Math.random() < gearLoss) {
                        p.equipStack(armorSlot, ItemStack.EMPTY);
                        itemsLost++;
                    }
                }
                *///?}
                if (!p.getOffHandStack().isEmpty() && Math.random() < gearLoss) {
                    p.setStackInHand(net.minecraft.util.Hand.OFF_HAND, ItemStack.EMPTY);
                    itemsLost++;
                }
                // Accessories (Artifacts trinkets, shields in accessory slots, etc.) roll at the gear rate.
                itemsLost += com.crackedgames.craftics.compat.artifacts.AccessoriesReflect
                    .clearAccessoriesChance(p, gearLoss);
                if (itemsLost > 0) {
                    sendMessageTo(p, "§c§lLost " + itemsLost + " item" + (itemsLost != 1 ? "s" : "") + "!");
                }
            } else {
                // First level or no run: remove one non-exempt item.
                // Prefer main hand, but fall back to hotbar/offhand/inventory so
                // holding the Move feather can't bypass the death penalty.
                ItemStack dropped = ItemStack.EMPTY;

                var mainHand = p.getMainHandStack();
                if (!mainHand.isEmpty()
                    && mainHand.getItem() != com.crackedgames.craftics.item.ModItems.MOVE_ITEM
                    && !(mainHand.getItem() instanceof com.crackedgames.craftics.item.GuideBookItem)) {
                    dropped = mainHand.copy();
                    //? if <=1.21.4 {
                    p.getInventory().setStack(p.getInventory().selectedSlot, ItemStack.EMPTY);
                    //?} else
                    /*p.getInventory().setStack(p.getInventory().getSelectedSlot(), ItemStack.EMPTY);*/
                }

                if (dropped.isEmpty()) {
                    for (int slot = 0; slot < 9; slot++) {
                        ItemStack stack = p.getInventory().getStack(slot);
                        if (stack.isEmpty()) continue;
                        Item item = stack.getItem();
                        if (item == com.crackedgames.craftics.item.ModItems.MOVE_ITEM || item instanceof com.crackedgames.craftics.item.GuideBookItem) continue;
                        dropped = stack.copy();
                        p.getInventory().setStack(slot, ItemStack.EMPTY);
                        break;
                    }
                }

                if (dropped.isEmpty()) {
                    ItemStack offhand = p.getOffHandStack();
                    if (!offhand.isEmpty()
                        && offhand.getItem() != com.crackedgames.craftics.item.ModItems.MOVE_ITEM
                        && !(offhand.getItem() instanceof com.crackedgames.craftics.item.GuideBookItem)) {
                        dropped = offhand.copy();
                        p.setStackInHand(net.minecraft.util.Hand.OFF_HAND, ItemStack.EMPTY);
                    }
                }

                if (dropped.isEmpty()) {
                    for (int slot = 9; slot < p.getInventory().size(); slot++) {
                        ItemStack stack = p.getInventory().getStack(slot);
                        if (stack.isEmpty()) continue;
                        Item item = stack.getItem();
                        if (item == com.crackedgames.craftics.item.ModItems.MOVE_ITEM || item instanceof com.crackedgames.craftics.item.GuideBookItem) continue;
                        dropped = stack.copy();
                        p.getInventory().setStack(slot, ItemStack.EMPTY);
                        break;
                    }
                }

                if (!dropped.isEmpty()) {
                    sendMessageTo(p, "§cDropped: " + dropped.getName().getString());
                }
            }
    }

    /** Shared game-over teardown tail: heal/clear participants, end the biome run,
     *  clear lost party mobs, teleport everyone home, and end combat. Runs exactly
     *  once per wipe - from the no-flip fall-through or from applyGameOverLossAndTeardown. */
    private void finishGameOverTeardown() {
        ServerWorld world = (ServerWorld) player.getEntityWorld();
        CrafticsSavedData data = CrafticsSavedData.get(world);
        CrafticsSavedData.PlayerData ld = data.getPlayerData(leaderUuid != null ? leaderUuid : player.getUuid());

        // Heal all participants (including dead spectators returning home)
        for (ServerPlayerEntity p : getAllParticipants()) {
            if (CrafticsMod.CONFIG.healBetweenLevels()) {
                p.setHealth(p.getMaxHealth());
            }
            p.clearStatusEffects();
        }

        // Reset biome run
        ld.endBiomeRun();
        ld.inCombat = false;
        data.markDirty();

        sendMessage("§7Returning to hub... Your biome run has ended.");
        sendMessage("§7Remaining emeralds: " + ld.emeralds);

        // Death = the run failed; the party mobs (and the mount) brought into it are
        // lost along with the dropped items -they do NOT return to the hub. Mark
        // petsRescued so endCombat()'s safety-net doesn't "rescue" the survivors back
        // home (the reported bug: "when you die in battle, the mounts come home when
        // they shouldn't"). endCombat() then discards the transient combat mobs.
        petsRescued = true;
        // Clear the lost party so the party HUD / next run don't reference ghost mobs.
        // Party-add enforces partyCap (PartyMobs), so the whole party is always brought
        // into the run -every entry here was just lost. (We clear rather than probe
        // world.getEntity(): at death the player is in the arena with the hub chunks
        // unloaded, so a lookup would false-null and is the wrong tool anyway.)
        try {
            java.util.UUID partyOwner = leaderUuid != null ? leaderUuid : player.getUuid();
            CrafticsSavedData.PlayerData ownerPd = data.getPlayerData(partyOwner);
            if (!ownerPd.getPartyMobs().isEmpty()) {
                ownerPd.getPartyMobs().clear();
                data.markDirty();
                ServerPlayerEntity ownerPlayer = world.getServer().getPlayerManager().getPlayer(partyOwner);
                if (ownerPlayer != null) com.crackedgames.craftics.network.PartyMobSync.sync(ownerPlayer);
            }
        } catch (Exception e) {
            CrafticsMod.LOGGER.warn("handleGameOver: party-mob clear failed: {}", e.getMessage());
        }

        // Teleport all party members home, restore daytime
        world.setTimeOfDay(6000);
        for (ServerPlayerEntity p : getAllParticipants()) {
            teleportToHub(p);
        }
        sendToAllParty(new ExitCombatPayload(false));
        endCombat();
    }

    /**
     * Hardcore variant of the game-over teardown: no penalties, no coin flip.
     * Resolves an active infinite run first (its stash restore is wiped anyway),
     * does the normal run-failure bookkeeping, ends combat, then hands off to
     * HardcoreIslands.wipe which empties + deletes the island dimension.
     */
    private void finishHardcoreTeardown(java.util.UUID owner, CrafticsSavedData.PlayerData ld) {
        ServerWorld world = (ServerWorld) player.getEntityWorld();
        net.minecraft.server.MinecraftServer srv = world.getServer();
        CrafticsSavedData data = CrafticsSavedData.get(world);

        sendMessage("§4§l☠ HARDCORE DEFEAT §r§4- the island is lost.");

        // Infinite run on a hardcore island: resolve stash flags before the wipe
        // (restoreParticipant refills inventories, but the wipe below clears them
        // again; offline members are caught by the pending-wipe join hook, which
        // runs AFTER the join-time stash restore).
        if (ld.infiniteActive) {
            InfiniteRunManager.endRun(srv, owner, "hardcore defeat");
        }

        // Same run-failure bookkeeping as finishGameOverTeardown.
        ld.endBiomeRun();
        ld.inCombat = false;
        data.markDirty();
        // Dead run: pets are lost with it; block endCombat's rescue safety-net
        // (same reasoning as finishGameOverTeardown). The owner record reset in
        // HardcoreIslands.wipe clears the party-mob list itself.
        petsRescued = true;

        // Snapshot participants BEFORE endCombat clears party state.
        java.util.List<ServerPlayerEntity> participants =
            new java.util.ArrayList<>(getAllParticipants());

        // Downed party members sit in SPECTATOR; restore before the lobby move.
        for (ServerPlayerEntity p : participants) {
            if (p != null && !p.isRemoved() && !p.isDisconnected()) {
                p.changeGameMode(net.minecraft.world.GameMode.SURVIVAL);
            }
        }

        world.setTimeOfDay(6000);
        sendToAllParty(new ExitCombatPayload(false));
        endCombat();

        com.crackedgames.craftics.world.HardcoreIslands.wipe(srv, owner, participants);
    }

    /** Apply every pending player's pre-decided losses, then run the shared teardown. */
    private void applyGameOverLossAndTeardown() {
        if (phase != CombatPhase.GAME_OVER_FLIP) return; // already applied (late ack vs timeout race)
        phase = CombatPhase.GAME_OVER;                   // close the window for any further ack/tick
        for (var entry : pendingGameOverLoss.entrySet()) {
            ServerPlayerEntity p = server != null ? server.getPlayerManager().getPlayer(entry.getKey()) : null;
            int lost = 0;
            for (PendingItemRoll r : entry.getValue()) {
                lost += r.lostQ();
                if (p == null) continue; // disconnected - their items still count as lost server-side
                // Remove exactly `lose` units from each slot in this group.
                for (SlotLoss sl : r.slots()) {
                    if (sl.lose() <= 0) continue;
                    removeUnitsFromSlot(p, sl);
                }
            }
            if (p != null && lost > 0) {
                sendMessageTo(p, "§c§lLost " + lost + " item" + (lost != 1 ? "s" : "") + "!");
            }
        }
        pendingGameOverLoss.clear();
        gameOverAcks.clear();
        gameOverWaiting.clear();
        finishGameOverTeardown();
    }

    /** Remove {@code sl.lose()} units from the physical slot {@code sl} refers to.
     *  Armor/offhand/accessory stacks are size 1 so any loss clears them; main slots
     *  decrement by the lost count (clearing the slot if it empties). */
    private void removeUnitsFromSlot(ServerPlayerEntity p, SlotLoss sl) {
        int lose = sl.lose();
        switch (sl.kind()) {
            case 0 -> {
                ItemStack s = p.getInventory().getStack(sl.index());
                if (s.isEmpty()) return;
                if (lose >= s.getCount()) p.getInventory().setStack(sl.index(), ItemStack.EMPTY);
                else s.decrement(lose);
            }
            case 1 -> {
                //? if <=1.21.4 {
                p.getInventory().armor.set(sl.index(), ItemStack.EMPTY);
                //?} else {
                /*net.minecraft.entity.EquipmentSlot[] as = {
                        net.minecraft.entity.EquipmentSlot.HEAD, net.minecraft.entity.EquipmentSlot.CHEST,
                        net.minecraft.entity.EquipmentSlot.LEGS, net.minecraft.entity.EquipmentSlot.FEET};
                if (sl.index() >= 0 && sl.index() < as.length) p.equipStack(as[sl.index()], ItemStack.EMPTY);
                *///?}
            }
            case 2 -> p.setStackInHand(net.minecraft.util.Hand.OFF_HAND, ItemStack.EMPTY);
            case 3 -> com.crackedgames.craftics.compat.artifacts.AccessoriesReflect
                .clearAccessoryAt(p, sl.accContainer(), sl.accKind(), sl.accSlot());
        }
    }

    /** Tick the GAME_OVER_FLIP hold; apply outcomes when the client timeout expires. */
    private void tickGameOverFlip() {
        if (gameOverFlipTimer > 0) gameOverFlipTimer--;
        if (gameOverFlipTimer <= 0) {
            applyGameOverLossAndTeardown();
        }
    }

    /** A player's client finished the coin-flip animation. Apply once all ack or on timeout. */
    public void handleGameOverAck(ServerPlayerEntity p) {
        if (phase != CombatPhase.GAME_OVER_FLIP) return;
        gameOverAcks.add(p.getUuid());
        if (gameOverAcks.containsAll(gameOverWaiting)) {
            applyGameOverLossAndTeardown();
        }
    }

    private void killEnemy(CombatEntity enemy) {
        enemy.takeDamage(9999);
        // Roll equipment drops on direct kills too (DOTs are handled by checkAndHandleDeath).
        // Mirror clones (Void Walker decoys) never drop loot -they now have real HP, so a
        // hazard-knockback kill routes through killEnemy instead of the dispel path; mirror
        // checkAndHandleDeath's clone guard here so they grant no loot/XP/streak.
        if (!enemy.isAlly() && !enemy.isMirrorClone() && !enemy.isDeathProcessed()
                && enemy.getMobEntity() != null) {
            rollMobEquipmentDrops(enemy);
        }
        // Ally died: drop from the persistent battle-party list right now so
        // the cap-aware spawn-egg gate, party HUD, and post-fight pet collector
        // all see the slot freed without waiting for combat to end.
        if (enemy.isAlly() && enemy.getMobEntity() != null && player != null
                && enemy.getMobEntity().getEntityWorld() instanceof ServerWorld dw) {
            java.util.UUID mobUuid = enemy.getMobEntity().getUuid();
            java.util.UUID ownerId = enemy.getOwnerUuid() != null
                ? enemy.getOwnerUuid() : player.getUuid();
            com.crackedgames.craftics.world.CrafticsSavedData savedData =
                com.crackedgames.craftics.world.CrafticsSavedData.get(dw);
            com.crackedgames.craftics.world.CrafticsSavedData.PlayerData pd =
                savedData.getPlayerData(ownerId);
            if (pd.getPartyMobs().remove(mobUuid)) {
                savedData.markDirty();
            }
        }
        // Background bosses occupy many manually-registered tiles -clear them all
        if (enemy.isBackgroundBoss()) {
            arena.getOccupants().values().removeIf(e -> e == enemy);
        } else {
            arena.removeEntity(enemy);
        }
        // Only real enemy kills count toward streaks / rewards. A dying ally
        // (killed by an enemy) routes through here too, but it must not award
        // kill-streak emeralds, Symbiote heals, AP refunds, or loot procs.
        // Mirror clones are excluded for the same reason -they are decoys, not kills.
        if (!enemy.isAlly() && !enemy.isMirrorClone()) {
            onEnemyKilled(enemy); // track kill streak
        }
        // Clean up visual projectile entity
        if (enemy.isProjectile()) {
            killVisualProjectileNear(enemy);
        }
        MobEntity mob = enemy.getMobEntity();
        if (mob == null && player != null) {
            // Non-mob entity (e.g., end crystal) -discard the world entity by ID
            ServerWorld deathWorld = (ServerWorld) player.getEntityWorld();
            net.minecraft.entity.Entity rawEnt = deathWorld.getEntityById(enemy.getEntityId());
            if (rawEnt != null) rawEnt.discard();
        }
        if (mob != null && mob.isAlive()) {
            // Background boss death: big explosion + scream, then discard
            if (enemy.isBackgroundBoss() && mob instanceof net.minecraft.entity.mob.GhastEntity ghast) {
                ghast.setShooting(true); // scream face
                ServerWorld world = (ServerWorld) player.getEntityWorld();
                world.playSound(null, mob.getBlockPos(),
                    net.minecraft.sound.SoundEvents.ENTITY_GHAST_DEATH,
                    net.minecraft.sound.SoundCategory.HOSTILE, 2.0f, 0.8f);
                world.spawnParticles(net.minecraft.particle.ParticleTypes.EXPLOSION_EMITTER,
                    mob.getX(), mob.getY() + 2.0, mob.getZ(), 3, 1.0, 1.0, 1.0, 0.0);
                world.spawnParticles(net.minecraft.particle.ParticleTypes.SOUL,
                    mob.getX(), mob.getY() + 2.0, mob.getZ(), 30, 2.0, 2.0, 2.0, 0.05);
                world.spawnParticles(net.minecraft.particle.ParticleTypes.LARGE_SMOKE,
                    mob.getX(), mob.getY() + 1.0, mob.getZ(), 20, 2.0, 1.5, 2.0, 0.03);
            }
            // Stack passenger cleanup: a force-kill on the base of a stack
            // mob (counterattack, smite, sweep, etc.) bypasses
            // transformStackLayer, so the cosmetic baby zombie / skeleton /
            // slime riding on top would otherwise stay in the world as a
            // ghost mob -visible but not in the combat entity list.
            clearStackPassengers(mob);
            // Death shrink -mob shrinks to 0 then gets discarded after delay
            float scale = startDeathShrink(mob);
            dyingMobs.add(new DyingMob(mob, 20, scale));
        }
        // Check if all enemies are dead or allied
        boolean allDead = enemies.stream().noneMatch(e -> e.isAlive() && !e.isAlly());
        if (allDead) {
            handleVictory();
        }
    }

    /**
     * Delivers a loot stack to a recipient; any portion that did not fit is
     * recorded in {@code overflow} keyed by the recipient's UUID.
     */
    private static void deliverLoot(ServerPlayerEntity recipient, ItemStack stack,
                                    java.util.Map<java.util.UUID, List<ItemStack>> overflow) {
        ItemStack leftover = LootDelivery.deliver(recipient, stack);
        if (leftover != null && !leftover.isEmpty()) {
            overflow.computeIfAbsent(recipient.getUuid(), k -> new ArrayList<>()).add(leftover);
        }
    }

    /**
     * Opens the post-victory loot screen for one player, pre-filled with their overflow.
     * Returns whether the screen actually opened (false if the player already had a screen open).
     */
    private boolean openLootScreen(ServerPlayerEntity p, List<ItemStack> overflowItems) {
        net.minecraft.inventory.SimpleInventory lootInv = new net.minecraft.inventory.SimpleInventory(
            com.crackedgames.craftics.screen.LootManagementScreenHandler.LOOT_SLOTS);
        int placed = 0;
        for (ItemStack item : overflowItems) {
            if (placed >= com.crackedgames.craftics.screen.LootManagementScreenHandler.LOOT_SLOTS) {
                CrafticsMod.LOGGER.warn(
                    "[Craftics] Loot overflow exceeded {} slots for {} -{} item(s) discarded",
                    com.crackedgames.craftics.screen.LootManagementScreenHandler.LOOT_SLOTS,
                    p.getName().getString(), overflowItems.size() - placed);
                break;
            }
            lootInv.setStack(placed++, item);
        }
        return p.openHandledScreen(new net.minecraft.screen.SimpleNamedScreenHandlerFactory(
            (syncId, playerInv, viewer) ->
                new com.crackedgames.craftics.screen.LootManagementScreenHandler(syncId, playerInv, lootInv),
            net.minecraft.text.Text.literal("Battle Loot"))).isPresent();
    }

    /** Called by the loot screen handler when a player closes their loot screen. */
    public void handleLootScreenClosed(ServerPlayerEntity p) {
        if (lootPendingPlayers.remove(p.getUuid()) && lootPendingPlayers.isEmpty()) {
            continueVictoryAfterLoot();
        }
    }

    private void handleVictory() {
        // Re-entrancy gate. Twenty-odd call sites all ask "is every enemy dead?" from
        // different places - DOT ticks, death handling, item use, turn end - and several can
        // run in the SAME tick off one killing blow. Each entry minted a fresh pendingVictory,
        // and each pendingVictory bought its own advanceBiomeRun(): two paths meant +2 levels,
        // three meant +3. That is the "Deep Dark level 3 -> 6, landed in Nether Wastes I"
        // report - the run skipped its own boss and walked into the next biome.
        //
        // The downstream consume-once token in continueVictoryAfterLoot() cannot help here:
        // it stops that method being re-entered, but a second handleVictory() just hands it a
        // brand new token. The duplicate has to be rejected at the entry point, and phase is
        // the state that says the level is already won.
        if (phase == CombatPhase.LEVEL_COMPLETE) return;

        // Raid gate: clearing the field is NOT winning while waves remain. Reward the
        // early clear by bringing the next wave in immediately (no telegraph wait) rather
        // than making the party stand around for the timer.
        if (raidActive && (raidRemainingPillagers > 0 || !raidFinaleSpawned)) {
            sendMessage("§cNo time to rest - the next wave pours in!");
            spawnRaidWave();
            raidRoundsUntilWave = RAID_WAVE_INTERVAL;
            return;
        }
        if (raidActive) {
            markRaidDefeated();
        }

        // If a thrown trident was lying on the arena when the final blow landed,
        // auto-recover it -otherwise the player loses it permanently on level end.
        if (droppedTridentStack != null) {
            String tridentName = droppedTridentStack.getName().getString();
            returnDroppedTrident();
            sendMessage("§3\u21BA Recovered your " + tridentName + "!");
        }

        // Diagnostic: in party combat, this.player is the current turn player
        // (whoever landed the killing blow), NOT the combat leader. Flag the
        // divergence so any downstream code that still uses this.player as a
        // proxy for "the leader" leaves a trail in the log.
        if (isTurnPlayerDivergentFromLeader()) {
            ServerPlayerEntity realLeader = getCombatLeader();
            CrafticsMod.LOGGER.info(
                "handleVictory: turn player '{}' ≠ combat leader '{}' -any leader-specific logic below must use getCombatLeader()",
                player.getName().getString(),
                realLeader != null ? realLeader.getName().getString() : leaderUuid);
        }

        // Sound: victory
        if (player != null) {
            player.getWorld().playSound(null, player.getBlockPos(),
                net.minecraft.sound.SoundEvents.UI_TOAST_CHALLENGE_COMPLETE,
                net.minecraft.sound.SoundCategory.PLAYERS, 1.0f, 1.0f);
        }
        phase = CombatPhase.LEVEL_COMPLETE;
        sendMessage("§a§l*** VICTORY! ***");
        fireEffectHook(h -> h.onCombatEnd(effectContext));

        // Revive fallen party members with 2 hearts (4 HP)
        if (!deadPartyMembers.isEmpty()) {
            for (ServerPlayerEntity p : getAllParticipants()) {
                if (deadPartyMembers.contains(p.getUuid())) {
                    p.setHealth(4); // 2 hearts
                    p.clearStatusEffects();
                    p.changeGameMode(net.minecraft.world.GameMode.ADVENTURE);
                    sendMessageTo(p, "§a§l\u2726 REVIVED! §rYour party won -you're back with 2 hearts!");
                }
            }
            sendMessage("§aFallen allies have been revived!");
            deadPartyMembers.clear();
        }

        // Per-mob loot now routes to the killer only, not every party member.
        // Arena/level-completion bonuses below still go to everyone -that's
        // the shared "you beat the wave" reward and shouldn't be one-player.
        java.util.Map<java.util.UUID, List<ItemStack>> lootOverflow = new java.util.HashMap<>();
        int luckBonusItems = PlayerProgression.get((ServerWorld) player.getEntityWorld())
            .getStats(player).getPoints(PlayerProgression.Stat.LUCK);
        for (CombatEntity enemy : enemies) {
            // The enemies list also holds the player's allies. A *surviving*
            // ally is not loot (a bee ally that lives must not award honey).
            // A *fallen* ally does drop its mob loot, same as any defeated mob.
            if (enemy.isAlly() && enemy.isAlive()) continue;
            // Skip drops for creepers that self-exploded (rewards killing them properly)
            if (enemy.isSelfExploded()) continue;
            List<ServerPlayerEntity> killerOnly = resolveKillerRecipients(enemy);
            for (ServerPlayerEntity recipient : killerOnly) {
                List<ItemStack> drops = getMobDrops(enemy.getEntityTypeId());
                for (ItemStack drop : drops) {
                    if (drop.isEmpty() || drop.getCount() <= 0) continue;
                    if (luckBonusItems > 0 && Math.random() < (luckBonusItems * 0.20)) {
                        drop.setCount(drop.getCount() + 1);
                    }
                    deliverLoot(recipient, drop, lootOverflow);
                }
            }
            // Broadcast a representative message (leader's perspective)
            List<ItemStack> displayDrops = getMobDrops(enemy.getEntityTypeId());
            for (ItemStack drop : displayDrops) {
                if (drop.isEmpty() || drop.getCount() <= 0) continue;
                sendMessage("§e+ " + drop.getCount() + "x " + drop.getName().getString());
            }
            // Rare goat horn drop -per-mob, killer-only.
            if ("minecraft:goat".equals(enemy.getEntityTypeId())) {
                for (ServerPlayerEntity recipient : killerOnly) {
                    if (Math.random() < CrafticsMod.CONFIG.goatHornDropChance() + luckBonusItems * 0.02) {
                        ItemStack horn = GoatHornEffects.createRandomHorn(player.getRegistryManager());
                        if (horn != null) {
                            deliverLoot(recipient, horn, lootOverflow);
                            sendMessageTo(recipient, "§6§l+ Goat Horn! " + horn.getName().getString());
                        }
                    }
                }
            }
        }
        // Shared list used by arena/completion loot below -that stays party-wide.
        List<ServerPlayerEntity> rewardRecipients = getAllParticipants();

        // Give level completion loot to each party participant individually
        if (levelDef != null) {
            ServerWorld lootWorld = (ServerWorld) player.getEntityWorld();
            com.crackedgames.craftics.level.BiomeTemplate lootBiome = null;
            if (levelDef instanceof com.crackedgames.craftics.level.GeneratedLevelDefinition gld) {
                lootBiome = gld.getBiomeTemplate();
            }
            final com.crackedgames.craftics.level.BiomeTemplate finalLootBiome = lootBiome;
            // Each player rolls their own completion loot (Luck boosts item counts)
            for (ServerPlayerEntity recipient : rewardRecipients) {
                java.util.List<ItemStack> lootItems = new java.util.ArrayList<>(levelDef.rollCompletionLoot(lootWorld));
                fireEffectHook(h -> h.onLootRoll(effectContext, lootItems));
                List<ItemStack> loot = new ArrayList<>();
                for (ItemStack stack : lootItems) {
                    loot.add(stack.isOf(Items.ENCHANTED_BOOK) ? randomEnchantedBook(lootWorld, stack.getCount(), finalLootBiome) : stack);
                }
                for (ItemStack item : loot) {
                    if (item.isEmpty() || item.getCount() <= 0) continue; // skip empty/air rolls
                    if (luckBonusItems > 0 && Math.random() < (luckBonusItems * 0.20)) {
                        item.setCount(item.getCount() + 1);
                    }
                    deliverLoot(recipient, item, lootOverflow);
                }
            }
            // Show a representative loot message
            List<ItemStack> displayLoot = levelDef.rollCompletionLoot(lootWorld);
            for (ItemStack item : displayLoot) {
                if (item.isEmpty() || item.getCount() <= 0) continue; // never show "0x Air"
                sendMessage("§e+ " + item.getCount() + "x " + item.getName().getString());
            }
        }

        // Rare pottery sherd drop (Luck boosts chance)
        float sherdChance = CrafticsMod.CONFIG.potterySherdDropChance() + luckBonusItems * 0.01f;
        if (sherdChance > 0 && Math.random() < sherdChance) {
            var sherdList = new ArrayList<>(PotterySherdSpells.POTTERY_SHERDS);
            Item sherdItem = sherdList.get(new java.util.Random().nextInt(sherdList.size()));
            ItemStack sherdStack = new ItemStack(sherdItem);
            for (ServerPlayerEntity recipient : rewardRecipients) {
                deliverLoot(recipient, sherdStack.copy(), lootOverflow);
            }
            sendMessage("§d§l✦ RARE DROP: " + sherdStack.getName().getString() + "!");
        }

        // Rare spawn egg drop (Luck boosts chance) -summons a temporary ally in combat.
        float eggChance = 0.04f + luckBonusItems * 0.01f;
        if (eggChance > 0 && Math.random() < eggChance) {
            Item eggItem = SPAWN_EGG_DROP_POOL[new java.util.Random().nextInt(SPAWN_EGG_DROP_POOL.length)];
            ItemStack eggStack = new ItemStack(eggItem);
            for (ServerPlayerEntity recipient : rewardRecipients) {
                deliverLoot(recipient, eggStack.copy(), lootOverflow);
            }
            sendMessage("§e§l✦ RARE DROP: " + eggStack.getName().getString() + "!");
        }

        // Award emeralds (scales with biome progression)
        ServerWorld world = (ServerWorld) player.getEntityWorld();
        CrafticsSavedData data = CrafticsSavedData.get(world);
        java.util.UUID dataOwner = leaderUuid != null ? leaderUuid : player.getUuid();
        CrafticsSavedData.PlayerData ld = data.getPlayerData(dataOwner);
        int biomeIndex = ld.activeBiomeLevelIndex;
        com.crackedgames.craftics.level.BiomeTemplate biomeTemplate = null;
        if (levelDef instanceof com.crackedgames.craftics.level.GeneratedLevelDefinition gld) {
            biomeTemplate = gld.getBiomeTemplate();
        }
        // Fallback: look up biome from active biome run (covers event levels like treasure vault)
        if (biomeTemplate == null && ld.isInBiomeRun()) {
            for (var b : com.crackedgames.craftics.level.BiomeRegistry.getAllBiomes()) {
                if (b.biomeId.equals(ld.activeBiomeId)) { biomeTemplate = b; break; }
            }
        }
        // Use active-campaign order for biome progression (not registry order)
        ld.initBranchIfNeeded();
        int biomeOrdinal = biomeTemplate != null
            ? com.crackedgames.craftics.level.campaign.CampaignManager
                .ordinalOf(biomeTemplate.biomeId, Math.max(0, ld.branchChoice))
            : 0;
        if (biomeOrdinal < 0) biomeOrdinal = 0;
        boolean isBoss = biomeTemplate != null && biomeTemplate.isBossLevel(arena.getLevelNumber());
        // Rare MoreTotems totem drop -boss kills only (Luck boosts chance). No-op when the
        // mod is absent (rollOne returns EMPTY).
        if (isBoss) {
            float totemChance = (float) CrafticsMod.CONFIG.totemDropChance() + luckBonusItems * 0.01f;
            if (Math.random() < totemChance) {
                ItemStack totemDrop = com.crackedgames.craftics.compat.moretotems.MoreTotemsLootRoller.rollOne();
                if (!totemDrop.isEmpty()) {
                    for (ServerPlayerEntity recipient : rewardRecipients) {
                        deliverLoot(recipient, totemDrop.copy(), lootOverflow);
                    }
                    sendMessage("§d§l✦ RARE DROP: " + totemDrop.getName().getString() + "!");
                }
            }
        }
        // Rare unique weapon drop -boss kills only (Luck boosts chance). Each recipient
        // rolls independently, preferring uniques they don't already carry. Simply Swords
        // and Simply Bows share ONE drop chance and one coin-flip between them, so having
        // both mods installed widens the pool without doubling how often it pays out.
        // No-op when neither mod is present (each roller returns EMPTY).
        if (isBoss) {
            float uniqueChance = (float) CrafticsMod.CONFIG.uniqueWeaponDropChance() + luckBonusItems * 0.01f;
            if (Math.random() < uniqueChance) {
                for (ServerPlayerEntity recipient : rewardRecipients) {
                    ItemStack uniqueDrop = rollUniqueWeapon(recipient);
                    if (!uniqueDrop.isEmpty()) {
                        deliverLoot(recipient, uniqueDrop.copy(), lootOverflow);
                        sendMessage("§6§l⚔ LEGENDARY DROP: " + uniqueDrop.getName().getString() + "!");
                    }
                }
            }
        }
        // Resourceful stat: +1 emerald per point (uses leader's stat)
        PlayerProgression victoryProg = PlayerProgression.get(world);
        int resourcefulBonus = victoryProg.getStats(player).getPoints(PlayerProgression.Stat.RESOURCEFUL) * PROG_RESOURCEFUL_PER_POINT;
        // The base emerald reward scales with how many enemies this level had, so a few-enemy
        // early level pays less than a full late one. Boss levels keep their flat reward (their
        // small add-crew shouldn't shrink the payout). Resourceful is a flat player bonus on top.
        int baseEmeralds = com.crackedgames.craftics.CrafticsMod.CONFIG.emeraldBaseReward() + biomeOrdinal / 3;
        if (!isBoss && levelDef != null) {
            double emeraldMult = com.crackedgames.craftics.level.BiomeDifficulty.rewardMultiplier(
                levelDef.getEnemySpawns().length);
            baseEmeralds = Math.max(1, (int) Math.round(baseEmeralds * emeraldMult));
        }
        int emeraldsEarned = baseEmeralds + (isBoss ? 3 : 0) + resourcefulBonus;
        // FORTUNE_PEAK set bonus: double emerald rewards
        if (activeTrimScan != null && activeTrimScan.setBonus() == TrimEffects.SetBonus.FORTUNE_PEAK) {
            emeraldsEarned *= 2;
            sendMessage("§6§l✦ Fortune's Peak! §r§6Emerald rewards doubled!");
        }
        // Addon combat effects: modify emerald gain
        emeraldsEarned = fireEffectHookChained(emeraldsEarned, (h, amt) -> h.onEmeraldGain(effectContext, amt));
        // Award emeralds to all party members via per-player data
        for (ServerPlayerEntity recipient : rewardRecipients) {
            CrafticsSavedData.PlayerData pd = data.getPlayerData(recipient.getUuid());
            pd.addEmeralds(emeraldsEarned);
        }
        data.markDirty();
        sendMessage("§a+ " + emeraldsEarned + " Emeralds");

        // Per-island boss-kill scaling: record this defeat so the NEXT encounter
        // with the same boss on this island spawns with +bossKillHpScale HP.
        // Infinite-run kills are excluded - their bosses are randomized stand-ins
        // and must never inflate the campaign's per-boss HP ramp.
        if (isBoss && biomeTemplate != null && biomeTemplate.biomeId != null
                && currentInfiniteSpec() == null) {
            java.util.UUID owner = worldOwnerUuid;
            if (owner != null) {
                CrafticsSavedData killData = CrafticsSavedData.get((net.minecraft.server.world.ServerWorld) player.getEntityWorld());
                killData.getPlayerData(owner).incrementBossKills(biomeTemplate.biomeId);
                killData.markDirty();
            }
        }

        // Boss trim template drops (semi-rare: ~35% chance, Luck boosts)
        if (isBoss && Math.random() < CrafticsMod.CONFIG.trimDropChance() + luckBonusItems * 0.02) {
            // Determine dimension from the active campaign's region for this biome
            String dimension = "overworld"; // sensible default if region is unknown/null
            if (biomeTemplate != null) {
                com.crackedgames.craftics.level.campaign.CampaignRegion region =
                    com.crackedgames.craftics.level.campaign.CampaignManager.regionOf(biomeTemplate.biomeId);
                if (region != null) dimension = region.id();
            }

            net.minecraft.item.Item[] trimPool = TrimEffects.getBossDropTrims(dimension);
            if (trimPool.length > 0) {
                // Avoid giving the same trim back-to-back
                java.util.List<net.minecraft.item.Item> candidates = new java.util.ArrayList<>();
                for (net.minecraft.item.Item t : trimPool) {
                    if (t != lastDroppedTrim) candidates.add(t);
                }
                if (candidates.isEmpty()) {
                    for (net.minecraft.item.Item t : trimPool) candidates.add(t);
                }
                java.util.Random trimRng = new java.util.Random();
                String lastName = null;
                for (ServerPlayerEntity recipient : rewardRecipients) {
                    net.minecraft.item.Item trimItem =
                        candidates.get(trimRng.nextInt(candidates.size()));
                    lastDroppedTrim = trimItem; // best-effort anti-repeat across drops
                    ItemStack trimStack = new ItemStack(trimItem);
                    deliverLoot(recipient, trimStack.copy(), lootOverflow);
                    lastName = trimStack.getName().getString();
                }
                if (lastName != null) {
                    sendMessage("\u00a7b\u00a7l\u2726 RARE DROP: " + lastName + "!");
                }

                // Unlock "How Trims Work" guide entry for all recipients
                ServerWorld trimWorld = (ServerWorld) player.getEntityWorld();
                CrafticsSavedData trimData = CrafticsSavedData.get(trimWorld);
                for (ServerPlayerEntity recipient : rewardRecipients) {
                    CrafticsSavedData.PlayerData rpd = trimData.getPlayerData(recipient.getUuid());
                    if (rpd.unlockGuideEntry("How Trims Work")) {
                        trimData.markDirty();
                        sendGuideBookSync(recipient, rpd);
                    }
                }
            }
        }

        // Stash the victory context, then route through the loot screen for any
        // player whose rewards overflowed a full inventory. continueVictoryAfterLoot()
        // runs the boss / non-boss branch -immediately, or once every loot screen closes.
        this.pendingVictory = new PendingVictory(isBoss, biomeOrdinal, biomeTemplate, emeraldsEarned);
        if (lootOverflow.isEmpty()) {
            continueVictoryAfterLoot();
        } else {
            lootPendingPlayers.clear();
            lootPendingPlayers.addAll(lootOverflow.keySet());
            for (java.util.Map.Entry<java.util.UUID, List<ItemStack>> entry : lootOverflow.entrySet()) {
                ServerPlayerEntity p = world.getServer().getPlayerManager().getPlayer(entry.getKey());
                if (p == null || !openLootScreen(p, entry.getValue())) {
                    lootPendingPlayers.remove(entry.getKey());
                }
            }
            // Every player with overflow has since disconnected -continue anyway.
            if (lootPendingPlayers.isEmpty()) {
                continueVictoryAfterLoot();
            }
        }
    }

    /**
     * INFINITE MODE boss clear: score +1 (banked immediately, so a crash can't
     * lose it), a guaranteed level-up on the run-scoped stats (alternating stat
     * point / affinity pick via grantLevelUp), then the party is moved to the
     * rest room where the bell continues into a random biome. The campaign's
     * unlock/NG+/boss-kill bookkeeping is deliberately absent here.
     */
    private void handleInfiniteBossVictory(ServerWorld world, CrafticsSavedData data,
                                           java.util.UUID hostUuid,
                                           List<ServerPlayerEntity> rewardRecipients) {
        CrafticsSavedData.PlayerData ld = data.getPlayerData(hostUuid);
        // Capture player turns taken THIS boss fight before endCombat resets it -
        // drives the "fewer turns = more points" boss score.
        int bossTurns = turnNumber;
        savePets();
        sendToAllParty(new ExitCombatPayload(true));
        sendMessage("§5§l*** ∞ BIOME " + (ld.infiniteBiomesCleared + 1) + " CLEARED! ∞ ***");
        ld.inCombat = false;
        data.markDirty();
        world.setTimeOfDay(6000);

        // Surviving pets return to the hub - the rest room is people-only.
        if (!savedPets.isEmpty()) {
            HubPetCollector.restorePetsToHub(world, player, savedPets, data);
            savedPets.clear();
        }
        petsRescued = true;

        List<ServerPlayerEntity> savedParty = new ArrayList<>(rewardRecipients);
        endCombat();

        // Every infinite boss grants a level-up on the run-scoped profile; the
        // reward alternates automatically (even level = stat point, odd level =
        // affinity pick) - same cadence as the campaign, one per boss.
        PlayerProgression progression = PlayerProgression.get(world);
        for (ServerPlayerEntity member : savedParty) {
            PlayerProgression.PlayerStats stats = progression.getStats(member);
            stats.grantLevelUp();
            stats.pendingAffinityChoice = stats.isAffinityLevel();
            progression.saveStats(member);
            StringBuilder statData = new StringBuilder();
            for (PlayerProgression.Stat s : PlayerProgression.Stat.values()) {
                if (statData.length() > 0) statData.append(":");
                statData.append(stats.getPoints(s));
            }
            ServerPlayNetworking.send(member, new com.crackedgames.craftics.network.LevelUpPayload(
                stats.level, stats.unspentPoints, statData.toString()));
            StringBuilder affData = new StringBuilder();
            for (PlayerProgression.Affinity a : PlayerProgression.Affinity.values()) {
                if (affData.length() > 0) affData.append(":");
                affData.append(stats.getAffinityPoints(a));
            }
            CrafticsSavedData.PlayerData memberPd = data.getPlayerData(member.getUuid());
            ServerPlayNetworking.send(member, new com.crackedgames.craftics.network.PlayerStatsSyncPayload(
                stats.level, stats.unspentPoints, statData.toString(),
                memberPd.emeralds, affData.toString()));
        }

        // Bank the score, roll the next realm, rebuild the rest room, move the party.
        InfiniteRunManager.onBossDefeated(world, hostUuid, savedParty, bossTurns);
    }

    /**
     * Runs the boss / non-boss victory branch -either straight after loot
     * delivery (no overflow) or once every player's loot screen has closed.
     */
    private void continueVictoryAfterLoot() {
        PendingVictory pv = this.pendingVictory;
        this.pendingVictory = null;
        if (pv == null) return;
        boolean isBoss = pv.isBoss();
        int biomeOrdinal = pv.biomeOrdinal();
        com.crackedgames.craftics.level.BiomeTemplate biomeTemplate = pv.biomeTemplate();
        int emeraldsEarned = pv.emeraldsEarned();

        ServerWorld world = (ServerWorld) player.getEntityWorld();
        CrafticsSavedData data = CrafticsSavedData.get(world);
        java.util.UUID dataOwner = leaderUuid != null ? leaderUuid : player.getUuid();
        // Resolve the ACTUAL infinite-run host, not just the party leader. The run's
        // host state lives on the host's own record (infiniteActive), which in co-op
        // is not necessarily the party leader / island owner. resolveActiveHost checks
        // the leader, then this player's infiniteRunHost pointer, and returns whoever's
        // record is actually active - so the boss-victory rest-room flow fires in co-op,
        // not just solo. null when there's no active run (campaign boss).
        java.util.UUID infiniteHostOwner = InfiniteRunManager.resolveActiveHost(
            data, dataOwner, player.getUuid());
        CrafticsSavedData.PlayerData ld = data.getPlayerData(dataOwner);
        List<ServerPlayerEntity> rewardRecipients = getAllParticipants();

        // ===== begin block moved verbatim from handleVictory =====
        // Check combat feat achievements for ALL victories (boss and non-boss)
        if (!isBoss) {
            for (ServerPlayerEntity recipient : rewardRecipients) {
                AchievementManager.checkCombatFeats(recipient, achievementTracker);
                AchievementManager.checkCollections(recipient, data.getPlayerData(recipient.getUuid()).emeralds);
            }
        }

        if (isBoss) {
            // INFINITE MODE: a boss clear banks score and parks the party in the
            // rest room instead of unlocking biomes / going home. No campaign
            // side-effects (unlocks, NG+, boss-kill HP ramp) are touched.
            if (InfiniteRunManager.isHostOfActiveRun(data, infiniteHostOwner)) {
                handleInfiniteBossVictory(world, data, infiniteHostOwner, rewardRecipients);
                return;
            }

            // Boss fights end the run immediately, so capture surviving allied pets now.
            savePets();

            // Boss fights end the biome run immediately.
            sendToAllParty(new ExitCombatPayload(true));

            // Boss defeated -biome complete! Unlock next biome, go home
            sendMessage("§6§l*** BIOME COMPLETE! ***");
            int currentBiomeOrder = biomeOrdinal + 1;
            if (ld.highestBiomeUnlocked <= currentBiomeOrder) {
                ld.highestBiomeUnlocked = currentBiomeOrder + 1;
                data.markDirty();
                com.crackedgames.craftics.CrafticsMod.updateWorldIcon(player.getServer(), ld);
                // Unlock biome for all party members
                for (ServerPlayerEntity recipient : rewardRecipients) {
                    CrafticsSavedData.PlayerData pd = data.getPlayerData(recipient.getUuid());
                    if (pd.highestBiomeUnlocked <= currentBiomeOrder) {
                        pd.highestBiomeUnlocked = currentBiomeOrder + 1;
                    }
                }
                // Region-boundary "unlocked" banner -campaign-driven. Resolve the
                // just-cleared biome id, then announce the NEXT region (if any) when the
                // next biome in flattened campaign order belongs to a different region.
                int branch = Math.max(0, ld.branchChoice);
                java.util.List<String> campaignOrder = com.crackedgames.craftics.level.campaign.CampaignManager
                    .orderedBiomeIds(branch);
                String justClearedBiomeId = biomeTemplate != null ? biomeTemplate.biomeId : ld.activeBiomeId;
                if (justClearedBiomeId == null
                        && biomeOrdinal >= 0 && biomeOrdinal < campaignOrder.size()) {
                    justClearedBiomeId = campaignOrder.get(biomeOrdinal);
                }
                String nextBiomeId = (biomeOrdinal + 1 < campaignOrder.size())
                    ? campaignOrder.get(biomeOrdinal + 1) : null;
                if (nextBiomeId != null) {
                    com.crackedgames.craftics.level.campaign.CampaignRegion clearedRegion =
                        com.crackedgames.craftics.level.campaign.CampaignManager.regionOf(justClearedBiomeId);
                    com.crackedgames.craftics.level.campaign.CampaignRegion nextRegion =
                        com.crackedgames.craftics.level.campaign.CampaignManager.regionOf(nextBiomeId);
                    if (nextRegion != null && nextRegion != clearedRegion) {
                        sendMessage(nextRegion.color() + "§l" + nextRegion.icon() + " "
                            + nextRegion.displayName().toUpperCase() + " HAS BEEN UNLOCKED! "
                            + nextRegion.icon());
                    }
                }
                // Final node of the final region (any campaign, any size) - trigger NG+.
                if (com.crackedgames.craftics.level.campaign.CampaignManager
                        .isFinalBiome(justClearedBiomeId, branch)) {
                    ld.startNewGamePlus();
                    sendMessage("§6§l★ NEW GAME+ " + ld.ngPlusLevel + " UNLOCKED! ★");
                    sendMessage("§eAll biomes reset. Enemies are now stronger. Your stats carry over.");
                }
            }
            ld.endBiomeRun();
            ld.inCombat = false;
            data.markDirty();
            world.setTimeOfDay(6000);
            // Teleport all party members home
            for (ServerPlayerEntity p : rewardRecipients) {
                teleportToHub(p);
            }

            // Restore surviving pets to the hub for the run owner.
            if (!savedPets.isEmpty()) {
                HubPetCollector.restorePetsToHub(world, player, savedPets, data);
                savedPets.clear();
            }
            // Pets handled -endCombat() must not restore them a second time.
            petsRescued = true;

            // Check achievements before endCombat() clears state
            String achievBiomeId = biomeTemplate != null ? biomeTemplate.biomeId : "";
            String achievArmorSet = PlayerCombatStats.getArmorSet(player);
            CombatAchievementTracker savedTracker = achievementTracker;
            for (ServerPlayerEntity recipient : rewardRecipients) {
                AchievementManager.checkBossVictory(recipient, achievBiomeId, achievArmorSet, savedTracker);
            }
            // Check NG+ achievements
            if (ld.ngPlusLevel > 0) {
                for (ServerPlayerEntity recipient : rewardRecipients) {
                    AchievementManager.checkNewGamePlus(recipient, ld.ngPlusLevel);
                }
            }
            // Check emerald collection achievement
            for (ServerPlayerEntity recipient : rewardRecipients) {
                CrafticsSavedData.PlayerData rpd = data.getPlayerData(recipient.getUuid());
                AchievementManager.checkCollections(recipient, rpd.emeralds);
            }

            // Save party list before endCombat() clears it.
            // savedPlayer must be the stable combat leader (not this.player,
            // which rotates per turn and points at the boss-killer by now).
            List<ServerPlayerEntity> savedParty = new ArrayList<>(rewardRecipients);
            ServerPlayerEntity resolvedLeader = getCombatLeader();
            ServerPlayerEntity savedPlayer = resolvedLeader != null ? resolvedLeader : player;
            endCombat();

            // Grant level-up with diminishing returns per boss
            String bossbiomeId = biomeTemplate != null ? biomeTemplate.biomeId : "unknown";
            PlayerProgression progression = PlayerProgression.get(world);
            for (ServerPlayerEntity member : savedParty) {
                PlayerProgression.PlayerStats stats = progression.getStats(member);
                boolean earned = stats.recordBossKillAndCheckLevelUp(bossbiomeId);
                progression.saveStats(member);
                if (earned) {
                    stats.grantLevelUp();
                    stats.pendingAffinityChoice = stats.isAffinityLevel();
                    progression.saveStats(member);
                    AchievementManager.checkProgression(member);
                } else {
                    int remaining = stats.getKillsUntilNextLevel(bossbiomeId);
                    sendMessageTo(member, "§7Defeat this boss §e" + remaining + "§7 more time" + (remaining != 1 ? "s" : "") + " for a level up.");
                }
                StringBuilder statData = new StringBuilder();
                for (PlayerProgression.Stat s : PlayerProgression.Stat.values()) {
                    if (statData.length() > 0) statData.append(":");
                    statData.append(stats.getPoints(s));
                }
                // Only show level-up screen if this kill earned a level
                if (earned) {
                    ServerPlayNetworking.send(member, new com.crackedgames.craftics.network.LevelUpPayload(
                        stats.level, stats.unspentPoints, statData.toString()
                    ));
                }
                StringBuilder affData = new StringBuilder();
                for (PlayerProgression.Affinity a : PlayerProgression.Affinity.values()) {
                    if (affData.length() > 0) affData.append(":");
                    affData.append(stats.getAffinityPoints(a));
                }
                CrafticsSavedData.PlayerData pd = data.getPlayerData(member.getUuid());
                ServerPlayNetworking.send(member, new com.crackedgames.craftics.network.PlayerStatsSyncPayload(
                    stats.level, stats.unspentPoints, statData.toString(), pd.emeralds, affData.toString()
                ));
            }
        } else {
            // Non-boss: show Go Home / Continue choice
            // Don't advance if this was a trial/ambush -those are bonus fights, not real levels
            if (!lastFightWasTrial) {
                ld.advanceBiomeRun();
                data.markDirty();
                // INFINITE MODE: clearing a normal level banks +5 points minus 1 per
                // 2 player-turns (floored at 1) - rewards finishing levels quickly.
                // Trials/ambushes are excluded (guarded above). Boss levels score via
                // onBossDefeated, not here.
                if (InfiniteRunManager.isHostOfActiveRun(data, infiniteHostOwner)) {
                    int earned = InfiniteRunManager.clearPoints(
                        InfiniteRunManager.LEVEL_POINTS, turnNumber);
                    int total = InfiniteRunManager.awardScore(
                        data, infiniteHostOwner, earned, rewardRecipients);
                    for (ServerPlayerEntity member : rewardRecipients) {
                        sendMessageTo(member, "§5∞ Level cleared! §d+" + earned
                            + " points §7(fewer turns = more). Score: §f" + total);
                    }
                }
            }
            String biomeName = biomeTemplate != null ? biomeTemplate.displayName : "Unknown";
            int displayIndex = ld.activeBiomeLevelIndex;
            // Check if the next level in this biome is a boss fight
            int nextGlobalLevel = levelDef instanceof com.crackedgames.craftics.level.GeneratedLevelDefinition gld2
                ? gld2.getLevelNumber() + 1 : -1;
            boolean nextIsBoss = biomeTemplate != null && nextGlobalLevel >= 0
                && biomeTemplate.isBossLevel(nextGlobalLevel);

            // Send choice screen to the STABLE combat leader (resolved via
            // leaderUuid), not `this.player` -in party combat `this.player`
            // is the current turn player and has likely rotated to whoever
            // killed the last enemy by the time we reach this code.
            ServerPlayerEntity decisionPlayer = getCombatLeader();
            if (decisionPlayer == null) {
                decisionPlayer = partyPlayers.isEmpty() ? player : partyPlayers.get(0);
            }
            if (decisionPlayer == null) {
                CrafticsMod.LOGGER.error("handleVictoryNonBoss: no leader found to send victory screen -aborting");
                return;
            }
            ServerPlayNetworking.send(decisionPlayer, new VictoryChoicePayload(
                emeraldsEarned, ld.emeralds, false, biomeName, displayIndex, nextIsBoss,
                true, LootRecorder.drain(decisionPlayer.getUuid())
            ));
            // Non-leaders get a persistent "waiting" loading screen. It fades out
            // automatically when their next EnterCombatPayload arrives from the
            // subsequent transitionPartyToArena call.
            String leaderName = decisionPlayer.getName().getString();
            for (ServerPlayerEntity member : getAllParticipants()) {
                if (!member.getUuid().equals(decisionPlayer.getUuid())) {
                    sendMessageTo(member, "§7Waiting for " + leaderName + " to decide...");
                    // Non-leaders see their OWN collected rewards; isLeader=false makes
                    // the screen show a "waiting for the leader" note instead of buttons.
                    ServerPlayNetworking.send(member, new VictoryChoicePayload(
                        emeraldsEarned, ld.emeralds, false, biomeName, displayIndex, nextIsBoss,
                        false, LootRecorder.drain(member.getUuid())
                    ));
                }
            }
            LootRecorder.clear();
            // Don't endCombat yet -wait for player choice
            // But do clear the arena
            clearHighlights();
        }
        // ===== end moved block =====
    }

    /**
     * Handle the player's choice after winning a non-boss level.
     * goHome = true: teleport home, reset biome run
     * goHome = false: continue to next level (with possible trader encounter)
     */
    public void handlePostLevelChoice(ServerPlayerEntity choicePlayer, boolean goHome) {
        // Reject if combat is mid-fight (not in a post-level state)
        if (active && phase != CombatPhase.LEVEL_COMPLETE) return;

        // Handle addon event choice (accept/decline from VictoryChoicePayload)
        if (pendingAddonEventId != null) {
            String eventId = pendingAddonEventId;
            List<ServerPlayerEntity> members = pendingAddonEventMembers;
            EventManager evtMgr = pendingAddonEventManager;
            pendingAddonEventId = null;
            pendingAddonEventMembers = null;
            pendingAddonEventManager = null;

            if (goHome) {
                // Declined -skip event, continue to pending next level
                for (ServerPlayerEntity p : getOnlinePartyMembers(choicePlayer)) {
                    sendMessageTo(p, "§7You decide to move on...");
                }
                if (pendingNextLevelDef != null) {
                    ServerWorld w = (ServerWorld) choicePlayer.getEntityWorld();
                    spawnSavedPets();
                    GridArena nextArena = buildArena(w, pendingNextLevelDef);
                    transitionPartyToArena(choicePlayer, members, nextArena, pendingNextLevelDef);
                    pendingNextLevelDef = null;
                    pendingBiome = null;
                }
            } else {
                // Accepted -execute the addon event handler
                var addonEvent = com.crackedgames.craftics.api.registry.EventRegistry.getById(eventId);
                if (addonEvent != null && addonEvent.handler() != null) {
                    ServerWorld w = (ServerWorld) choicePlayer.getEntityWorld();
                    try {
                        addonEvent.handler().execute(
                            members != null ? members : getOnlinePartyMembers(choicePlayer),
                            w, evtMgr);
                    } catch (Exception addonEx) {
                        CrafticsMod.LOGGER.error("Addon event '{}' handler threw exception", eventId, addonEx);
                    }
                    // After handler: if no combat was started, auto-continue
                    if (!active && !trialChamberPending && !digSitePending) {
                        if (pendingNextLevelDef != null) {
                            spawnSavedPets();
                            GridArena nextArena = buildArena(w, pendingNextLevelDef);
                            transitionPartyToArena(choicePlayer, members, nextArena, pendingNextLevelDef);
                            pendingNextLevelDef = null;
                            pendingBiome = null;
                        }
                    }
                }
            }
            return;
        }

        // Trial chamber choice used to live here, but it's now a party-vote
        // dialogue (see offerTrialVote / handleTrialDialogueChoice). The
        // trialChamberPending branch is unreachable from the post-battle screen
        // and has been removed; trial accept/skip transitions happen directly
        // from finalizeTrialEvent.
        if (false) { // dead -trial choice moved to dialogue vote, see offerTrialVote
            trialChamberPending = false;
            lastFightWasTrial = false;
            com.crackedgames.craftics.level.LevelDefinition savedTrialDef = trialChamberLevelDef;
            trialChamberLevelDef = null;
            ServerWorld tcWorld = (ServerWorld) choicePlayer.getEntityWorld();
            if (goHome) {
                // Skip trial -continue to pending next level
                for (ServerPlayerEntity p : getOnlinePartyMembers(choicePlayer)) {
                    sendMessageTo(p, "§7You pass by the trial chamber...");
                }
                if (pendingNextLevelDef != null && pendingBiome != null) {
                    // Restore allies and pets before continuing
                    spawnSavedPets();
                    GridArena nextArena = buildArena(tcWorld, pendingNextLevelDef);
                    transitionPartyToArena(choicePlayer, nextArena, pendingNextLevelDef);
                    pendingNextLevelDef = null;
                    pendingBiome = null;
                    pendingEventBiomeOrdinal = 0;
                }
            } else {
                // Accept trial!
                for (ServerPlayerEntity p : getOnlinePartyMembers(choicePlayer)) {
                    sendMessageTo(p, "§6§l\u2694 Entering the Trial Chamber! \u2694");
                    sendMessageTo(p, "§cWarning: Enemies are stronger here!");
                }
                if (savedTrialDef != null) {
                    // Restore allies and pets before entering trial
                    spawnSavedPets();
                    GridArena trialArena = buildArena(tcWorld, savedTrialDef);
                    transitionPartyToArena(choicePlayer, trialArena, savedTrialDef);
                    lastFightWasTrial = true;
                }
            }
            return;
        }

        // After a trial chamber or ambush victory, go directly to the pending next level (no more events)
        if (lastFightWasTrial && pendingNextLevelDef != null && !goHome) {
            lastFightWasTrial = false;
            ServerWorld world2 = (ServerWorld) choicePlayer.getEntityWorld();
            // Capture allies that survived the trial/ambush (including the player's
            // mount) BEFORE endCombat(). The old code called spawnSavedPets() here,
            // but savedPets was already drained when the trial was entered (see
            // finalizeTrialEvent), so it was a no-op -and because savePets()/
            // petsRescued were never set, endCombat()'s safety-net "rescued" the live
            // trial allies straight back to the hub, making mounts and pets vanish
            // from the run after every trial/ambush ("they never return").
            savePets();
            petsRescued = true;
            endCombat();
            GridArena nextArena = buildArena(world2, pendingNextLevelDef);
            // transitionPartyToArena -> startCombat -> spawnSavedPets re-spawns and
            // re-mounts the carried-over allies in the new arena.
            transitionPartyToArena(choicePlayer, nextArena, pendingNextLevelDef);
            pendingNextLevelDef = null;
            pendingBiome = null;
            pendingEventBiomeOrdinal = 0;
            return;
        }
        lastFightWasTrial = false;

        // Only accept choice from the party leader.
        // CRITICAL: resolve the leader via getCombatLeader() (by stable
        // leaderUuid), NOT via `this.player` -in party combat this.player is
        // reassigned per turn by switchToTurnPlayer() and at victory points at
        // whoever dealt the killing blow. Before this was fixed,
        // `savedPlayer = player` caused transitionPartyToArena to treat the
        // killer as the "leader" and teleport only them to the next level.
        ServerPlayerEntity leader = getCombatLeader();
        if (leader == null) {
            // Fall back to partyPlayers[0] / this.player for pre-startCombat
            // edge cases where leaderUuid is null.
            leader = partyPlayers.isEmpty() ? player : partyPlayers.get(0);
        }
        if (leader == null || !choicePlayer.getUuid().equals(leader.getUuid())) {
            CrafticsMod.LOGGER.debug(
                "handlePostLevelChoice: rejecting click from {} (combat leader: {})",
                choicePlayer.getName().getString(),
                leader != null ? leader.getName().getString() : "none");
            return;
        }

        // Save references before endCombat() nulls them. snapshotParticipants
        // prefers partyPlayers (still populated here) and falls back through
        // eventManager so downstream code never has to worry about ordering.
        ServerPlayerEntity savedPlayer = leader;
        List<ServerPlayerEntity> savedMembers = snapshotParticipants();
        ServerWorld world = (ServerWorld) savedPlayer.getEntityWorld();
        CrafticsSavedData data = CrafticsSavedData.get(world);
        java.util.UUID dataOwner = leaderUuid != null ? leaderUuid : savedPlayer.getUuid();
        CrafticsSavedData.PlayerData ld = data.getPlayerData(dataOwner);

        // Snapshot biome state BEFORE endCombat can interfere
        String biomeId = ld.activeBiomeId;
        int levelIndex = ld.activeBiomeLevelIndex;
        int branchChoice = ld.branchChoice;
        int ngPlusLevel = ld.ngPlusLevel;

        // Persist tamed pets so they carry over to the next level (continue) or
        // get restored to the hub just below (go home). Either branch disposes of
        // the survivors explicitly, so endCombat() must not touch them.
        savePets();
        petsRescued = true;

        if (goHome) {
            sendMessage("§7Returning to hub...");
            // Restore surviving pets back into the hub world using their original NBT snapshots.
            if (!savedPets.isEmpty()) {
                HubPetCollector.restorePetsToHub(world, savedPlayer, savedPets, data);
                sendMessage("§aYour surviving pets returned to the hub.");
                savedPets.clear();
            }
            boolean wasInfinite = ld.infiniteActive;
            // An infinite run keeps its biome/level cursor - that IS the save point.
            if (!wasInfinite) {
                ld.endBiomeRun();
            }
            ld.inCombat = false;
            data.markDirty();
            world.setTimeOfDay(6000);
            // Teleport all party members home
            for (ServerPlayerEntity member : savedMembers) {
                teleportToHub(member);
            }
            sendToAllParty(new ExitCombatPayload(true));
            endCombat();
            // INFINITE MODE: going home parks the run at a save point - the stash comes
            // back now, and Infinite Mode resumes here later. Score stays banked either way.
            if (wasInfinite) {
                InfiniteRunManager.suspendRun(world.getServer(), dataOwner, "went home");
            }
        } else {
            // Continue to next level
            // Broadcast to all BEFORE endCombat clears party state
            for (ServerPlayerEntity m : savedMembers) {
                sendMessageTo(m, "§aOnward!");
            }
            // Save eventManager before endCombat nulls it -addon event handlers need it
            EventManager savedEventManager = this.eventManager;
            endCombat();

            try {
            // Start next level -use snapshotted biome state (safe from endCombat clobbering)
            com.crackedgames.craftics.level.BiomeTemplate biome = null;
            for (var b : com.crackedgames.craftics.level.BiomeRegistry.getAllBiomes()) {
                if (b.biomeId.equals(biomeId)) { biome = b; break; }
            }
            if (biome != null) {
                int globalLevel = biome.startLevel + levelIndex;
                // Island owner's per-level HP scaling preference. For party fights
                // this is whoever owns the world slot (the leader); for solo it's
                // the player themselves. worldOwnerUuid is set when combat starts.
                java.util.UUID hpScaleOwnerId = worldOwnerUuid != null
                    ? worldOwnerUuid
                    : (leaderUuid != null ? leaderUuid : savedPlayer.getUuid());
                boolean islandHpScale = data.getPlayerData(hpScaleOwnerId).scaleHpPerLevelEnabled;
                // Once the island owner has beaten this biome's boss, every level in the
                // biome spawns the biome's peak enemy count instead of the normal ramp.
                boolean ownerBeatBiomeBoss = PlayerProgression.get(world)
                    .getStats(hpScaleOwnerId).getBossKills(biomeId) >= 1;
                // INFINITE MODE: thread the run spec so the next level scales off
                // the cleared-biome count and a boss level rolls the randomized boss.
                com.crackedgames.craftics.level.InfiniteSpec contInfSpec =
                    InfiniteRunManager.specFor(data, dataOwner, biome, globalLevel);
                com.crackedgames.craftics.level.LevelDefinition nextLevelDef =
                    com.crackedgames.craftics.level.LevelRegistry.get(globalLevel, branchChoice,
                        islandHpScale, ownerBeatBiomeBoss, contInfSpec);
                if (nextLevelDef != null) {
                    java.util.Random eventRng = new java.util.Random();
                    float eventRoll = eventRng.nextFloat();

                    // Calculate biome position for difficulty scaling (use active-campaign ordinal, not registry index)
                    int biomeOrdinal = contInfSpec != null
                        ? contInfSpec.virtualOrdinal()
                        : com.crackedgames.craftics.level.campaign.CampaignManager
                            .ordinalOf(biome.biomeId, Math.max(0, branchChoice));
                    if (biomeOrdinal < 0) biomeOrdinal = 0;

                    // No events on the very first continue (level index 1 = just beat level 1)
                    // Never have events before a boss fight
                    // Reduced event chance on early biomes (first 3 biomes)
                    boolean isBossLevel = biome.isBossLevel(globalLevel);
                    boolean skipEvents = levelIndex <= 1 || isBossLevel;
                    if (!skipEvents && biomeOrdinal < 3) {
                        // Early biomes: reduced event chance (configurable)
                        skipEvents = eventRoll > CrafticsMod.CONFIG.earlyBiomeEventChance();
                        if (!skipEvents) eventRoll = eventRng.nextFloat(); // re-roll within event pool
                    }

                    // === PITY TIMER: Increase overall event chance based on levels without event ===
                    // Each event-less level ADDS 5% (cap +50%) to every event window.
                    // This used to multiply the thresholds by (1 - pity), which SHRANK
                    // them - the longer the dry streak, the RARER events got, quietly
                    // starving the low-probability tail (e.g. the Artifacts campsite).
                    float pityBonus = 0f;
                    if (!skipEvents && ld.levelsSinceLastEvent > 0) {
                        pityBonus = Math.min(0.50f, ld.levelsSinceLastEvent * 0.05f);
                        if (ld.levelsSinceLastEvent >= 3) {
                            //sendMessageToAllChat("§7§o[Pity Timer: " + ld.levelsSinceLastEvent + " levels without events - event probability +" + (int)(pityBonus * 100) + "%]");
                        }
                    }

                    // Check for forced event from /craftics force_event
                    String forced = forcedNextEvent;
                    if (forced != null) {
                        forcedNextEvent = null;
                        skipEvents = false; // override skip
                    }

                    // Helper: broadcast event messages to all party members
                    // Use savedMembers (captured before endCombat) since party state is already cleared
                    List<ServerPlayerEntity> partyMsg = savedMembers;

                    // Cap the pity boost so the whole cascade (built-ins + addon
                    // events) still fits under 1.0 - otherwise a long dry streak
                    // would push the trader window past 1.0 and make the addon
                    // events at the tail unreachable again.
                    float addonEventTotal = 0f;
                    for (var addonEntry : com.crackedgames.craftics.api.registry.EventRegistry.getAll()) {
                        if (addonEntry.handler() != null && biomeOrdinal >= addonEntry.minBiomeOrdinal()) {
                            addonEventTotal += addonEntry.probability();
                        }
                    }
                    float baseEventTotal = CrafticsMod.CONFIG.ominousTrialChance()
                        + CrafticsMod.CONFIG.trialChamberChance()
                        + CrafticsMod.CONFIG.ambushChance()
                        + CrafticsMod.CONFIG.shrineChance()
                        + CrafticsMod.CONFIG.travelerChance()
                        + CrafticsMod.CONFIG.vaultChance()
                        + CrafticsMod.CONFIG.digSiteChance()
                        + 0.06f // enchanter (hardcoded below)
                        + CrafticsMod.CONFIG.traderSpawnChance()
                        + addonEventTotal;
                    float pityScale = 1f + pityBonus;
                    if (baseEventTotal * pityScale > 0.98f) {
                        pityScale = Math.max(1f, 0.98f / baseEventTotal);
                    }

                    // Build cumulative thresholds from config (with pity boost applied)
                    float cOminous = CrafticsMod.CONFIG.ominousTrialChance() * pityScale;
                    float cTrial = cOminous + CrafticsMod.CONFIG.trialChamberChance() * pityScale;
                    float cAmbush = cTrial + CrafticsMod.CONFIG.ambushChance() * pityScale;
                    float cShrine = cAmbush + CrafticsMod.CONFIG.shrineChance() * pityScale;
                    float cTraveler = cShrine + CrafticsMod.CONFIG.travelerChance() * pityScale;
                    float cVault = cTraveler + CrafticsMod.CONFIG.vaultChance() * pityScale;
                    float cDigSite = cVault + CrafticsMod.CONFIG.digSiteChance() * pityScale;
                    float cEnchanter = cDigSite + 0.06f * pityScale; // 6% enchanter chance
                    float cTrader = cEnchanter + CrafticsMod.CONFIG.traderSpawnChance() * pityScale;

                    boolean isNetherRegion = "nether".equals(
                        java.util.Optional.ofNullable(
                            com.crackedgames.craftics.level.campaign.CampaignManager.regionOf(biome.biomeId))
                        .map(r -> r.id()).orElse("overworld"));

                    // RAID gets first claim on the event slot. A fresh island (raid never
                    // defeated) is under active pillager threat: 75% of rolls are the raid
                    // until the players win one, then it drops to an ordinary event rate.
                    // Rolled independently of eventRoll so the cumulative windows below are
                    // untouched either way.
                    boolean raidAlreadyDefeated = data.getPlayerData(
                        data.getEffectiveWorldOwner(savedPlayer.getUuid())).raidDefeated;
                    float raidChance = raidAlreadyDefeated ? 0.06f : 0.75f;
                    float raidRoll = (float) Math.random();

                    if (skipEvents) {
                        // No event -go straight to next level. Boss levels get a
                        // narrator intro first; once all members dismiss it the
                        // transition fires (no leader choice -combat starts either way).
                        ld.levelsSinceLastEvent++; // increment pity timer
                        data.markDirty();
                        final com.crackedgames.craftics.level.LevelDefinition nextDef = nextLevelDef;
                        final ServerPlayerEntity ref = savedPlayer;
                        final List<ServerPlayerEntity> members = savedMembers;
                        final ServerWorld w = world;
                        Runnable transition = () -> {
                            ServerPlayerEntity source = (ref != null && !ref.isRemoved() && !ref.isDisconnected())
                                ? ref : firstOnlinePartyMember();
                            if (source == null) return;
                            GridArena nextArena = buildArena(w, nextDef);
                            transitionPartyToArena(source, members, nextArena, nextDef);
                        };
                        if (isBossLevel && contInfSpec == null) {
                            // Infinite runs skip the authored biome-boss intro - the
                            // randomized boss announces itself at spawn instead.
                            offerBossIntro(members, biome, transition);
                        } else {
                            transition.run();
                        }
                    } else if (forced != null ? forced.equals("raid") : (raidRoll < raidChance)) {
                        // Raid - defend the villagers from pillager waves on a plains field.
                        ld.levelsSinceLastEvent = 0;
                        data.markDirty();
                        pendingNextLevelDef = nextLevelDef;
                        pendingBiome = biome;
                        var raidDef = TrialChamberEvent.generateRaid(
                            Math.max(0, biomeOrdinal), ngPlusLevel);
                        pendingEventBiomeOrdinal = Math.max(0, biomeOrdinal);
                        lastFightWasTrial = true;
                        offerRaid(savedPlayer, savedMembers, raidDef);
                    } else if (forced != null ? forced.equals("ominous_trial") : (eventRoll < cOminous && biomeOrdinal >= 10)) {
                        // Ominous Trial Chamber (late game only). Party-vote dialogue -
                        // tie or majority Accept enters the trial; majority Decline skips
                        // straight to the next level.
                        ld.levelsSinceLastEvent = 0;
                        data.markDirty();
                        pendingNextLevelDef = nextLevelDef;
                        pendingBiome = biome;
                        trialChamberLevelDef = RandomEvents.generateOminousTrial(biomeOrdinal, ngPlusLevel);
                        trialChamberPending = true;
                        offerTrialVote(savedPlayer, partyMsg, true);
                    } else if (forced != null ? forced.equals("trial") : (eventRoll < cTrial)) {
                        // Trial Chamber. Party-vote dialogue -tie or majority Enter takes
                        // the trial; majority Pass skips straight to the next level.
                        ld.levelsSinceLastEvent = 0;
                        data.markDirty();
                        pendingNextLevelDef = nextLevelDef;
                        pendingBiome = biome;
                        trialChamberLevelDef = TrialChamberEvent.generate(biomeOrdinal, ngPlusLevel);
                        trialChamberPending = true;
                        offerTrialVote(savedPlayer, partyMsg, false);
                    } else if (forced != null ? forced.equals("ambush") : (eventRoll < cAmbush)) {
                        // Shiny on the ground. The party votes Take vs Leave; majority Yes
                        // resolves 50/50 into a reward for one Yes voter or this ambush
                        // combat. Majority No walks past safely. Ties trigger the ambush.
                        // (Config name kept as "ambush" so the chance / force_event key
                        // does not break.)
                        ld.levelsSinceLastEvent = 0; // reset pity timer on event
                        data.markDirty();
                        pendingNextLevelDef = nextLevelDef;
                        pendingBiome = biome;
                        var ambushDef = RandomEvents.generateAmbush(biome.biomeId, biomeOrdinal,
                            biome.getBiomeLevelIndex(globalLevel), ngPlusLevel);
                        pendingEventBiomeOrdinal = Math.max(0, biomeOrdinal);
                        lastFightWasTrial = true;
                        offerShinyChoice(savedPlayer, savedMembers, ambushDef);
                    } else if (forced != null ? forced.equals("shrine") : (eventRoll < cShrine)) {
                        // Shrine of Fortune -interactive room
                        ld.levelsSinceLastEvent = 0; // reset pity timer on event
                        data.markDirty();
                        pendingNextLevelDef = nextLevelDef;
                        pendingBiome = biome;
                        offerShrine(savedPlayer, biomeOrdinal);
                    } else if (forced != null ? forced.equals("traveler") : (eventRoll < cTraveler)) {
                        // Wounded Traveler -interactive room
                        ld.levelsSinceLastEvent = 0; // reset pity timer on event
                        data.markDirty();
                        pendingNextLevelDef = nextLevelDef;
                        pendingBiome = biome;
                        offerTraveler(savedPlayer, biomeOrdinal);
                    } else if (forced != null ? forced.equals("vault") : (eventRoll < cVault)) {
                        // Treasure Vault -interactive room
                        ld.levelsSinceLastEvent = 0; // reset pity timer on event
                        data.markDirty();
                        pendingNextLevelDef = nextLevelDef;
                        pendingBiome = biome;
                        offerVault(savedPlayer, biomeOrdinal);
                    } else if (forced != null ? forced.equals("dig_site") : (eventRoll < cDigSite)) {
                        // Dig Site
                        ld.levelsSinceLastEvent = 0; // reset pity timer on event
                        data.markDirty();
                        pendingNextLevelDef = nextLevelDef;
                        pendingBiome = biome;
                        offerDigSite(savedPlayer, biome);
                    } else if (forced != null ? forced.equals("enchanter") : (eventRoll < cEnchanter)) {
                        // Enchanter -enhance a weapon or armor piece
                        ld.levelsSinceLastEvent = 0; // reset pity timer on event
                        data.markDirty();
                        pendingNextLevelDef = nextLevelDef;
                        pendingBiome = biome;
                        offerEnchanter(savedPlayer);
                    } else if (forced != null ? (forced.equals("trader") || forced.equals("piglin_barter")) : (eventRoll < cTrader)) {
                        // Configurable chance: Wandering Trader (Overworld/End) or Piglin Barter (Nether)
                        ld.levelsSinceLastEvent = 0; // reset pity timer on event
                        data.markDirty();
                        pendingNextLevelDef = nextLevelDef;
                        pendingBiome = biome;
                        if (isNetherRegion) {
                            offerPiglinBarter(savedPlayer, biome, biomeOrdinal);
                        } else {
                            offerTrader(savedPlayer, biome, biomeOrdinal);
                        }
                    } else {
                        // Check addon-registered events from EventRegistry
                        String addonEventId = null;
                        if (forced != null) {
                            // Forced event that didn't match any built-in -check addon registry
                            addonEventId = forced;
                        } else {
                            // Roll against addon event probabilities. Apply the same
                            // pity-timer boost as built-in events so addons scale
                            // proportionally as pity ramps.
                            float addonRoll = eventRoll - cTrader; // remaining probability space
                            if (addonRoll >= 0) {
                                for (var addonEvent : com.crackedgames.craftics.api.registry.EventRegistry.getAll()) {
                                    // Skip built-in events that are also mirrored into the registry
                                    // with a null handler (VanillaContent registers them for listing
                                    // only). They are driven by the inline cascade above, not here;
                                    // counting them would consume the addon probability space and
                                    // starve real addon events (e.g. the Artifacts campsite), which
                                    // sit later in the iteration order and could never be reached.
                                    if (addonEvent.handler() == null) continue;
                                    if (biomeOrdinal >= addonEvent.minBiomeOrdinal()) {
                                        addonRoll -= addonEvent.probability() * pityScale;
                                        if (addonRoll < 0) {
                                            addonEventId = addonEvent.id();
                                            break;
                                        }
                                    }
                                }
                            }
                        }

                        if (addonEventId != null) {
                            var addonEvent = com.crackedgames.craftics.api.registry.EventRegistry.getById(addonEventId);
                            if (addonEvent != null && addonEvent.handler() != null) {
                                ld.levelsSinceLastEvent = 0;
                                data.markDirty();
                                pendingNextLevelDef = nextLevelDef;
                                pendingBiome = biome;

                                if (addonEvent.isChoiceEvent()) {
                                    // Choice event: show accept/decline prompt, execute handler only on accept
                                    pendingAddonEventId = addonEventId;
                                    pendingAddonEventMembers = savedMembers;
                                    pendingAddonEventManager = savedEventManager;
                                    final ServerPlayerEntity addonLeader = savedPlayer;
                                    final int addonLeaderEmeralds = ld.emeralds;
                                    final String addonLabel = addonEvent.displayName();
                                    Runnable addonPrompt = leaderPromptOrAutoDecline(addonLeader,
                                        new VictoryChoicePayload(0, addonLeaderEmeralds, false,
                                            addonLabel, -1, false, true, new java.util.ArrayList<>()));
                                    if (addonEvent.introLines() != null && !addonEvent.introLines().isEmpty()) {
                                        // Opt-in narrator intro -gate the leader's Accept/Decline
                                        // screen behind an all-dismiss dialogue.
                                        var addonIntro = new com.crackedgames.craftics.combat.dialogue.DialogueDefinition(
                                            "craftics:addon_intro_" + addonEventId.replace(':', '_'),
                                            "", "addon_intro",
                                            addonEvent.introLines(), java.util.List.of());
                                        offerIntroNarrator(savedMembers, addonIntro,
                                            "§e§l✦ " + addonLabel + " ✦", addonPrompt);
                                    } else {
                                        // Legacy: chat preface + immediate leader prompt.
                                        for (ServerPlayerEntity p : partyMsg) {
                                            sendMessageTo(p, "§e§l" + addonLabel + " discovered!");
                                        }
                                        addonPrompt.run();
                                    }
                                } else {
                                    // Non-choice event: execute immediately, then auto-continue
                                    try {
                                        addonEvent.handler().execute(savedMembers, world, savedEventManager);
                                    } catch (Exception addonEx) {
                                        CrafticsMod.LOGGER.error("Addon event '{}' handler threw exception", addonEventId, addonEx);
                                    }
                                    // Auto-continue to next level after simple event
                                    pendingNextLevelDef = null;
                                    pendingBiome = null;
                                    spawnSavedPets();
                                    GridArena nextArena = buildArena(world, nextLevelDef);
                                    transitionPartyToArena(savedPlayer, savedMembers, nextArena, nextLevelDef);
                                }
                            } else {
                                // Unknown addon event ID or no handler -skip to next level
                                ld.levelsSinceLastEvent++;
                                data.markDirty();
                                GridArena nextArena = buildArena(world, nextLevelDef);
                                transitionPartyToArena(savedPlayer, savedMembers, nextArena, nextLevelDef);
                            }
                        } else {
                            // No event -start next level immediately
                            // Increment pity counter since no event occurred
                            ld.levelsSinceLastEvent++;
                            data.markDirty();
                            GridArena nextArena = buildArena(world, nextLevelDef);
                            transitionPartyToArena(savedPlayer, savedMembers, nextArena, nextLevelDef);
                        }
                    }
                }
            }
            } catch (Exception ex) {
                CrafticsMod.LOGGER.error("Failed to start next level, sending player home", ex);
                sendMessageTo(savedPlayer, "§cError loading next level! Returning to hub...");
                ld.endBiomeRun();
                ld.inCombat = false;
                data.markDirty();
                teleportToHub(savedPlayer);
                // Send all party members home on error, not just the leader
                for (ServerPlayerEntity m : savedMembers) {
                    if (!m.getUuid().equals(savedPlayer.getUuid())) {
                        teleportToHub(m);
                    }
                    ServerPlayNetworking.send(m, new ExitCombatPayload(false));
                }
            }
        }
    }

    // ---- Forced event (debug command) ----
    private String forcedNextEvent = null;
    public void setForcedNextEvent(String event) { this.forcedNextEvent = event; }
    public String getForcedNextEvent() { return forcedNextEvent; }

    // ---- Addon event (pending choice) ----
    private String pendingAddonEventId = null;
    private List<ServerPlayerEntity> pendingAddonEventMembers = null;
    private EventManager pendingAddonEventManager = null;

    // ---- Trial Chamber event ----
    private boolean trialChamberPending = false;
    private com.crackedgames.craftics.level.LevelDefinition trialChamberLevelDef;
    private boolean lastFightWasTrial = false;

    // ---- Addon-event public hooks ----
    /**
     * The biome the player is currently progressing through, captured at level
     * transition. Used by addon event handlers (e.g. Artifacts mimic encounter)
     * to read floor blocks, boss stats, etc.
     */
    public com.crackedgames.craftics.level.BiomeTemplate getPendingBiome() { return pendingBiome; }

    /** Position of the current biome in the dimension path (0 = first biome). */
    public int getCurrentBiomeOrdinal() { return currentBiomeOrdinal; }

    /** The level definition that will be loaded next, if any. */
    public com.crackedgames.craftics.level.LevelDefinition getPendingNextLevel() { return pendingNextLevelDef; }
    public void setPendingNextLevel(com.crackedgames.craftics.level.LevelDefinition def) { this.pendingNextLevelDef = def; }
    public void setPendingBiome(com.crackedgames.craftics.level.BiomeTemplate b) { this.pendingBiome = b; }

    /**
     * Build an arena for the given level definition and transition the given leader's
     * party into combat there. Used by addon event handlers that need to launch an
     * encounter outside the normal "next biome level" pipeline.
     * <p>
     * Accepts {@code leader} explicitly because at addon-event-acceptance time
     * {@code this.player} may have been cleared by a prior endCombat call. The
     * leader passed in by the event handler is always the current party leader.
     */
    public void startCustomCombat(ServerPlayerEntity leader, com.crackedgames.craftics.level.LevelDefinition def) {
        if (def == null || leader == null) {
            CrafticsMod.LOGGER.warn("startCustomCombat: ignoring null def or leader (def={}, leader={})",
                def, leader);
            return;
        }
        ServerWorld w = (ServerWorld) leader.getEntityWorld();
        spawnSavedPets();
        GridArena custom = buildArena(w, def);
        if (custom == null) {
            CrafticsMod.LOGGER.error("startCustomCombat: buildArena returned null for level '{}' -aborting",
                def.getName());
            return;
        }
        CrafticsMod.LOGGER.info("startCustomCombat: transitioning party into '{}' at {} ({}x{})",
            def.getName(), custom.getOrigin(), custom.getWidth(), custom.getHeight());
        transitionPartyToArena(leader, custom, def);
        // Clear the pending-next-level so the post-choice auto-continue doesn't also
        // try to load the normal next biome level on top of this custom combat.
        this.pendingNextLevelDef = null;
        this.pendingBiome = null;
    }

    /** @deprecated use {@link #startCustomCombat(ServerPlayerEntity, com.crackedgames.craftics.level.LevelDefinition)} */
    @Deprecated
    public void startCustomCombat(com.crackedgames.craftics.level.LevelDefinition def) {
        startCustomCombat(this.player, def);
    }

