        int ox = origin.getX(), oy = origin.getY(), oz = origin.getZ();
        net.minecraft.block.BlockState air = Blocks.AIR.getDefaultState();
        int sf = net.minecraft.block.Block.NOTIFY_LISTENERS | net.minecraft.block.Block.FORCE_STATE;

